/* AUTO-GENERATED — Massachusetts Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["MA"] = {"code":"MA","name":"Massachusetts","agency":"Massachusetts RMV","agencyShort":"RMV","handbook":"https://www.mass.gov/commercial-drivers-licenses-cdl","links":{},"en":[{"q":"On Massachusetts ways, what is the maximum legal width of a commercial motor vehicle, exclusive of mirrors, turn signals, and certain safety devices?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"answer":1,"explanation":"Massachusetts limits vehicle width to 102 inches (8 feet 6 inches), not counting mirrors, turn signals, and certain safety devices. Source: MGL Chapter 90, Section 19; Massachusetts RMV CDL Manual.","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle and its load on Massachusetts highways without a permit?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"answer":1,"explanation":"Massachusetts sets the maximum vehicle-and-load height at 13 feet 6 inches. Vehicles over 10 feet tall must display their height. Source: MGL Chapter 90, Section 19; MassDOT commercial truck height limits.","handbook":"","hbref":""},{"q":"Without a special permit, what is the maximum length of a semitrailer in a tractor-semitrailer combination in Massachusetts?","options":["48 feet","53 feet","57 feet","60 feet"],"answer":1,"explanation":"A semitrailer in a tractor-semitrailer unit may be up to 53 feet long in Massachusetts. Source: MGL Chapter 90, Section 19; Massachusetts RMV CDL Manual.","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle weight allowed on Massachusetts ways, without a permit, for a vehicle with three or more axles?","options":["73,280 pounds","80,000 pounds","88,000 pounds","99,000 pounds"],"answer":1,"explanation":"Massachusetts caps gross vehicle weight at 80,000 pounds for vehicles with three or more axles, matching the federal interstate maximum. Source: MGL Chapter 90, Section 19A.","handbook":"","hbref":""},{"q":"What is the maximum weight Massachusetts allows on a single axle without an overweight permit?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"answer":2,"explanation":"Massachusetts permits up to 22,400 pounds on a single axle, which is higher than the 20,000-pound federal interstate limit. Source: MGL Chapter 90, Section 19A.","handbook":"","hbref":""},{"q":"What is the maximum weight Massachusetts allows on a tandem axle (two axles) without an overweight permit?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"Massachusetts sets the tandem-axle limit at 34,000 pounds, consistent with the federal standard. Source: MGL Chapter 90, Section 19A.","handbook":"","hbref":""},{"q":"In Massachusetts, what is the maximum height of a straight (single) truck before height markings are required to be displayed on the vehicle?","options":["8 feet","10 feet","12 feet","13 feet 6 inches"],"answer":1,"explanation":"Massachusetts requires vehicles taller than 10 feet to display their height in markings, even though the legal maximum height is 13 feet 6 inches. Source: MGL Chapter 90, Section 19.","handbook":"","hbref":""},{"q":"Which Massachusetts agency issues oversize and overweight permits for travel on state highways?","options":["The Registry of Motor Vehicles (RMV)","The MassDOT Highway Division","The Massachusetts State Police","The Federal Motor Carrier Safety Administration"],"answer":1,"explanation":"Oversize/overweight permits for state highways are issued by the MassDOT Highway Division through its Truck Permit Office. Source: Mass.gov Commercial Truck Permits; MassDOT.","handbook":"","hbref":""},{"q":"What is the name of the MassDOT online system used to request commercial oversize/overweight truck permits and routing?","options":["ATLAS","OASIS","PRISM","UCR"],"answer":1,"explanation":"MassDOT's web-based Oversize/Overweight Permitting and Routing Application is called OASIS, used to apply for commercial truck permits. Source: MassDOT Highway Division; Mass.gov.","handbook":"","hbref":""},{"q":"When is a vehicle required to obtain a MassDOT oversize/overweight permit?","options":["Only when crossing a state line","Whenever it exceeds the legal limits for width, height, length, or weight","Only when carrying hazardous materials","Only when traveling at night"],"answer":1,"explanation":"A permit is required any time a vehicle or load exceeds the legal limits for width (102 in), height (13'6\"), length, or weight (80,000 lb). Source: MGL Chapter 90, Section 19/19A; MassDOT.","handbook":"","hbref":""},{"q":"Massachusetts applies the federal Bridge Formula to weight on a group of two or more consecutive axles. What is the constant multiplier used in that formula, W = 500[LN/(N-1) + 12N + 36]?","options":["100","250","500","1,000"],"answer":2,"explanation":"The federal Bridge Formula adopted in Massachusetts uses the constant 500: W = 500[LN/(N-1) + 12N + 36], where L is the axle spread and N is the number of axles. Source: MGL Chapter 90, Section 19A; FHWA Bridge Formula.","handbook":"","hbref":""},{"q":"In the federal Bridge Formula used in Massachusetts, what does the variable 'L' represent?","options":["The legal load weight in pounds","The distance in feet between the extreme (outer) axles of the group","The lane width of the highway","The length of the trailer in feet"],"answer":1,"explanation":"In W = 500[LN/(N-1) + 12N + 36], 'L' is the distance in feet between the extreme axles of any group of two or more consecutive axles. Source: MGL Chapter 90, Section 19A; FHWA Bridge Formula.","handbook":"","hbref":""},{"q":"What is the maximum gross weight Massachusetts allows on a vehicle with only two axles, without a permit?","options":["34,000 pounds","40,000 pounds","46,000 pounds","54,000 pounds"],"answer":2,"explanation":"A two-axle vehicle is limited to 46,000 pounds gross in Massachusetts, while three-or-more-axle vehicles may reach 80,000 pounds. Source: MGL Chapter 90, Section 19A.","handbook":"","hbref":""},{"q":"In Massachusetts, if two single axles are spaced less than 6 feet apart, what is the maximum weight allowed on each such axle?","options":["16,000 pounds","18,000 pounds","20,000 pounds","22,400 pounds"],"answer":1,"explanation":"When axles are spaced less than 6 feet apart, the single-axle allowance drops from 22,400 pounds to 18,000 pounds each. Source: MGL Chapter 90, Section 19A.","handbook":"","hbref":""},{"q":"How do Massachusetts maximum width and height limits on Interstate highways compare to those on other state highways?","options":["Width and height limits are the same (102 in wide, 13'6\" high) on both","Interstates allow a wider 8'6\" but other roads only 8'","Interstates allow 14 feet of height but other roads only 13'6\"","Other state roads allow wider vehicles than Interstates"],"answer":0,"explanation":"The 102-inch width and 13-foot-6-inch height limits apply uniformly on both the Interstate/National Network and other state highways in Massachusetts. Source: MGL Chapter 90, Section 19; J.J. Keller MA size/weight summary.","handbook":"","hbref":""},{"q":"Compared with the federal interstate single-axle limit, Massachusetts' single-axle allowance is:","options":["Lower (Massachusetts allows 18,000 lb vs. federal 20,000 lb)","The same (both 20,000 lb)","Higher (Massachusetts allows 22,400 lb vs. federal 20,000 lb)","Unlimited on state roads"],"answer":2,"explanation":"Massachusetts permits 22,400 pounds on a single axle, which is higher than the 20,000-pound federal interstate standard. Source: MGL Chapter 90, Section 19A.","handbook":"","hbref":""},{"q":"Without a permit, what is the maximum length of a straight (single-unit) truck in Massachusetts?","options":["33 feet","40 feet","45 feet","53 feet"],"answer":1,"explanation":"A straight truck (single unit) may be up to 40 feet long in Massachusetts; a semitrailer in a combination may be up to 53 feet. Source: MGL Chapter 90, Section 19.","handbook":"","hbref":""},{"q":"A carrier needs to move a load that is 14 feet wide on a Massachusetts state highway. What must the carrier do?","options":["Nothing, because 14 feet is within the legal width limit","Obtain an oversize permit from the MassDOT Highway Division before traveling","Notify only the local police department","Apply for a CDL endorsement"],"answer":1,"explanation":"At 14 feet wide the load exceeds the 102-inch (8'6\") legal width, so an oversize permit must be obtained from the MassDOT Highway Division (via OASIS) before travel. Source: MGL Chapter 90, Section 19; MassDOT.","handbook":"","hbref":""},{"q":"Under Massachusetts law, what is the maximum legal overall length for a tractor with twin/tandem trailers (each trailer at its legal length)?","options":["Each trailer up to 28 feet, with no overall combination length limit when trailers are legal","A fixed 65-foot overall limit regardless of trailer length","A fixed 53-foot overall limit","Twin trailers are prohibited in Massachusetts"],"answer":0,"explanation":"In a tractor twin-trailer combination, each trailer (tandem unit) may be up to 28 feet, and there is no overall combination length limit when the trailers are legal. Source: MGL Chapter 90, Section 19; J.J. Keller MA size/weight summary.","handbook":"","hbref":""},{"q":"In Massachusetts, which CDL class is required to operate a single vehicle with a gross vehicle weight rating (GVWR) of 26,001 lbs. or more that is NOT towing a trailer over 10,000 lbs.?","options":["Class A","Class B","Class C","Class D"],"answer":1,"explanation":"Massachusetts requires a Class B CDL to operate any single vehicle with a GVWR of 26,001 lbs. or more, or such a vehicle towing a trailer not over 10,000 lbs. (e.g., box trucks, dump trucks, straight trucks). Source: Mass.gov 'CDL classes and endorsements' and the Massachusetts CDL Manual (RMV).","handbook":"","hbref":""},{"q":"A Massachusetts driver wants to pull a tractor-trailer combination with a gross combination weight rating of 80,000 lbs. where the towed trailer is rated over 10,000 lbs. Which CDL class is required?","options":["Class B","Class C","Class A","Class D"],"answer":2,"explanation":"A Class A CDL is required in Massachusetts for any combination of vehicles with a GCWR of 26,001 lbs. or more where the towed unit(s) exceed 10,000 lbs. GVWR. Source: Mass.gov 'CDL classes and endorsements' and the Massachusetts CDL Manual (RMV).","handbook":"","hbref":""},{"q":"Under Massachusetts rules, a vehicle that does not meet Class A or B weight thresholds but is designed to carry 16 or more passengers (including the driver) or to transport placarded hazardous materials requires which CDL class?","options":["Class C","Class A","Class B","Class M"],"answer":0,"explanation":"Massachusetts requires a Class C CDL for a vehicle that does not qualify as Class A or B but is designed to transport 16 or more people (including the driver) or is used to carry hazardous materials requiring placards. Source: Mass.gov 'CDL classes and endorsements' and the Massachusetts CDL Manual (RMV).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Massachusetts CDL or Commercial Learner's Permit restricted to INTRASTATE (Massachusetts-only) commerce?","options":["16 years old","17 years old","18 years old","21 years old"],"answer":2,"explanation":"Massachusetts requires applicants to be at least 18 years old for an intrastate (Massachusetts-only) CDL/CLP. Driving in interstate commerce requires age 21. Source: Mass.gov 'Apply for a Commercial Learner's Permit (CLP)' (RMV).","handbook":"","hbref":""},{"q":"What is the minimum age required to drive a commercial motor vehicle in INTERSTATE commerce under a Massachusetts CDL?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"A driver must be at least 21 years old to operate a CMV across state lines (interstate commerce). Drivers aged 18-20 are limited to intrastate (Massachusetts-only) operation. Source: Mass.gov RMV CLP/CDL pages, consistent with 49 CFR 391.11.","handbook":"","hbref":""},{"q":"Which endorsement code is required on a Massachusetts CDL to drive a vehicle designed to carry passengers, such as a large bus?","options":["Code N","Code P","Code T","Code H"],"answer":1,"explanation":"The Passenger (P) endorsement is required in Massachusetts to operate a vehicle designed to transport passengers (e.g., buses). It requires passing a knowledge test and a skills test in a representative vehicle. Source: Mass.gov 'CDL classes and endorsements' and the Massachusetts CDL Manual (RMV).","handbook":"","hbref":""},{"q":"Which CDL endorsement is required to transport hazardous materials in quantities requiring placards in Massachusetts?","options":["N (Tanker)","T (Doubles/Triples)","H (Hazardous Materials)","S (School Bus)"],"answer":2,"explanation":"The H (Hazardous Materials) endorsement is required to haul placardable quantities of hazardous materials. It requires a knowledge test, a TSA security threat assessment, and ELDT theory training for first-time applicants. Source: Mass.gov 'CDL classes and endorsements' and TSA HazMat endorsement program.","handbook":"","hbref":""},{"q":"In Massachusetts, which endorsement is required to pull double or triple trailers?","options":["T endorsement","N endorsement","X endorsement","P endorsement"],"answer":0,"explanation":"The T (Doubles/Triples) endorsement is required to tow more than one trailer. It is obtained by passing a knowledge test only (no separate skills test). Source: Mass.gov 'CDL classes and endorsements' and the Massachusetts CDL Manual (RMV).","handbook":"","hbref":""},{"q":"Which endorsement does a Massachusetts CDL holder need to drive a tank vehicle hauling a liquid or gaseous load?","options":["H endorsement","T endorsement","N endorsement","S endorsement"],"answer":2,"explanation":"The N (Tank Vehicle) endorsement is required to operate a tank vehicle designed to haul liquids or gases in bulk. It is obtained by passing the tank vehicle knowledge test. Source: Mass.gov 'CDL classes and endorsements' and the Massachusetts CDL Manual (RMV).","handbook":"","hbref":""},{"q":"In Massachusetts, which endorsement must a driver already hold (as a prerequisite) before obtaining the School Bus (S) endorsement?","options":["H (Hazardous Materials)","P (Passenger)","N (Tank Vehicle)","T (Doubles/Triples)"],"answer":1,"explanation":"Massachusetts requires the Passenger (P) endorsement as a prerequisite to earning the School Bus (S) endorsement. A driver must pass the P and S knowledge tests and the school bus skills test. Source: Mass.gov 'CDL classes and endorsements' and 'Apply for a school bus learner's permit' (RMV).","handbook":"","hbref":""},{"q":"Under federal rules applied by the Massachusetts RMV, how long must an applicant hold a Commercial Learner's Permit before being eligible to take the CDL skills (road) test?","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"answer":1,"explanation":"Federal regulation (49 CFR 383.25), applied by the Massachusetts RMV, requires the CLP to be held for at least 14 days before the applicant may take the skills test. The clock starts the day the permit is issued. Source: Mass.gov RMV CLP page and FMCSA 49 CFR 383.25.","handbook":"","hbref":""},{"q":"How long is a Massachusetts Commercial Learner's Permit (CLP) valid before it must be renewed or the skills test completed?","options":["90 days","180 days","1 year","2 years"],"answer":1,"explanation":"A Massachusetts CLP is valid for 180 days. It may be renewed once for an additional 180 days without retaking the general knowledge test, consistent with federal limits. Source: Mass.gov 'Apply for a Commercial Learner's Permit (CLP)' (RMV).","handbook":"","hbref":""},{"q":"While driving on a Massachusetts Commercial Learner's Permit, the CLP holder must be accompanied by a person who:","options":["Is at least 25 years old with any driver's license","Holds a valid CDL of the proper class and endorsements, seated next to the driver","Is a certified driving instructor only","Has at least 5 years of commercial driving experience"],"answer":1,"explanation":"A CLP holder may only operate a CMV when accompanied by a person who holds a valid CDL with the appropriate class and endorsements, seated in the front seat beside the driver. Source: Mass.gov RMV CLP page and 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Which document combination must an applicant present to the Massachusetts RMV to establish eligibility for a CDL or CLP?","options":["Proof of identity/lawful presence, Social Security number, and Massachusetts residency","Only a Social Security card","Only a current passport","A high school diploma and proof of residency"],"answer":0,"explanation":"The Massachusetts RMV requires proof of identity and lawful presence in the U.S., a Social Security number, and proof of Massachusetts residency to issue a CLP/CDL. Source: Mass.gov RMV CDL/CLP application requirements and 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) required before a first-time Massachusetts Class A CDL skills test must be completed by a provider that is:","options":["Approved by the Massachusetts RMV only","Listed on the FMCSA Training Provider Registry (TPR)","Certified by the U.S. Department of Education","Any licensed Massachusetts driving school"],"answer":1,"explanation":"ELDT must be completed with a provider listed on the FMCSA Training Provider Registry (TPR). Only TPR-registered providers may deliver the required theory and behind-the-wheel training. Source: Mass.gov 'Entry-Level Driver Training (ELDT)' guide and FMCSA TPR (49 CFR Part 380).","handbook":"","hbref":""},{"q":"For a first-time Hazardous Materials (H) endorsement in Massachusetts, what type of ELDT must be completed and when?","options":["Theory training only, before taking the knowledge test","Behind-the-wheel training only, before the skills test","Both theory and behind-the-wheel, before the road test","No ELDT is required for the H endorsement"],"answer":0,"explanation":"For the H endorsement, ELDT consists of theory instruction only and must be completed before taking the State HazMat knowledge test. There is no separate skills test for the H endorsement. Source: Mass.gov ELDT guide and FMCSA TPR (49 CFR Part 380).","handbook":"","hbref":""},{"q":"A Massachusetts driver who operates only within Massachusetts and must meet state medical qualification requirements should self-certify under which category?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"answer":2,"explanation":"Non-Excepted Intrastate (NA) applies to drivers operating only in intrastate commerce who must meet Massachusetts medical/driver-qualification standards and hold a medical examiner's certificate. Source: Mass.gov 'CDL Self-Certification' (RMV) and 49 CFR 383.71.","handbook":"","hbref":""},{"q":"A driver who self-certifies as Non-Excepted Interstate (NI) in Massachusetts must keep on file with the RMV a valid medical certificate from an examiner who is:","options":["Any licensed physician in Massachusetts","Listed on the FMCSA National Registry of Certified Medical Examiners","Approved by the driver's employer","A Massachusetts RMV staff examiner"],"answer":1,"explanation":"Non-Excepted Interstate drivers must pass a DOT physical performed by a medical examiner listed on the FMCSA National Registry of Certified Medical Examiners and keep the medical certificate current with the RMV. Source: Mass.gov 'Medical standards for CDL' and 49 CFR 391.41-391.43.","handbook":"","hbref":""},{"q":"Beyond completing ELDT theory and passing the knowledge test, the Hazardous Materials (H) endorsement in Massachusetts also requires the applicant to:","options":["Complete a behind-the-wheel road test for hazardous loads","Pass a TSA security threat assessment including fingerprinting","Hold a Tank (N) endorsement first","Be at least 25 years of age"],"answer":1,"explanation":"The H endorsement requires a TSA security threat assessment, which includes submitting fingerprints and biographical data and undergoing a criminal/immigration/terrorist-watchlist check, in addition to the knowledge test and ELDT theory. Source: Mass.gov 'CDL classes and endorsements' and TSA HazMat endorsement program (49 CFR 1572).","handbook":"","hbref":""},{"q":"Which group of drivers is subject to the Entry-Level Driver Training (ELDT) requirements in Massachusetts?","options":["Only drivers renewing an existing CDL","Drivers obtaining a Class A or B CDL for the first time, upgrading Class B to Class A, or getting a first-time S, P, or H endorsement","Only out-of-state drivers transferring a CDL","Only drivers over the age of 21"],"answer":1,"explanation":"ELDT applies to applicants obtaining a Class A or B CDL for the first time, upgrading a Class B to Class A, or obtaining a school bus (S), passenger (P), or hazardous materials (H) endorsement for the first time. Source: Mass.gov 'Entry-Level Driver Training (ELDT)' guide and FMCSA TPR (49 CFR Part 380).","handbook":"","hbref":""},{"q":"In Massachusetts, what is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV)?","options":["0.08","0.04","0.02","0.00"],"answer":1,"explanation":"Massachusetts follows the federal standard: operating a CMV with a BAC of 0.04 or higher is a major offense and a disqualifying violation. The 0.08 limit applies to non-commercial drivers. Source: MA RMV CDL Manual, Section 1 (Disqualifications); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Massachusetts CDL rules, a driver who operates a CMV with a BAC of 0.04 or more for a FIRST major offense (and is not carrying placarded hazardous materials) is disqualified for how long?","options":["60 days","90 days","1 year","3 years"],"answer":2,"explanation":"A first major offense, such as driving a CMV with a BAC of 0.04 or more, results in a minimum 1-year disqualification (3 years if transporting placarded hazardous materials). Source: MA RMV CDL Manual; M.G.L. c. 90F; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Massachusetts, if a CDL driver commits a first major offense while operating a CMV that is transporting placarded hazardous materials, the disqualification period is increased to:","options":["1 year","2 years","3 years","5 years"],"answer":2,"explanation":"When a first major offense occurs while the CMV is placarded for hazardous materials, the disqualification is increased from 1 year to 3 years. Source: MA RMV CDL Manual (Disqualifications); 49 CFR 383.51(b).","handbook":"","hbref":""},{"q":"What is the Massachusetts CDL disqualification period for a SECOND major offense (such as a second OUI or second refusal), arising from separate incidents?","options":["3 years","10 years","Lifetime","5 years"],"answer":2,"explanation":"A second major offense, in any combination and arising from separate incidents, results in a lifetime CDL disqualification. Source: MA RMV CDL Manual; M.G.L. c. 90F; 49 CFR 383.51(b).","handbook":"","hbref":""},{"q":"In Massachusetts, under the implied-consent rule, a CDL driver who REFUSES to submit to a required alcohol (chemical) test while operating a CMV is treated as having committed:","options":["A serious traffic violation (60-day disqualification)","A minor violation with only a fine","A major offense (1-year disqualification, 3 years if hazmat)","A railroad-crossing violation"],"answer":2,"explanation":"By operating a CMV, a driver gives implied consent to alcohol testing. Refusing the test is a major offense carrying the same penalty as driving under the influence: 1-year disqualification (3 years if placarded for hazmat), and lifetime for a second occurrence. Source: MA RMV CDL Manual; 49 CFR 383.51(b); M.G.L. c. 90F.","handbook":"","hbref":""},{"q":"How many SERIOUS traffic violations within a 3-year period (in separate incidents) trigger a 60-day CDL disqualification in Massachusetts?","options":["1","2","3","4"],"answer":1,"explanation":"A second serious traffic violation within a 3-year period results in a 60-day disqualification; a third within 3 years results in 120 days. A single serious violation alone does not disqualify. Source: MA RMV CDL Manual; 49 CFR 383.51(c).","handbook":"","hbref":""},{"q":"In Massachusetts, THREE serious traffic violations committed within a 3-year period result in a CDL disqualification of:","options":["60 days","90 days","120 days","180 days"],"answer":2,"explanation":"A third serious traffic violation within a 3-year period results in a 120-day disqualification (a second within 3 years is 60 days). Source: MA RMV CDL Manual; 49 CFR 383.51(c).","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation for a Massachusetts CDL driver?","options":["Driving a CMV with a BAC of 0.04 or more","Refusing an alcohol test","Driving 15 mph or more above the posted speed limit","Driving a CMV while your CDL is suspended"],"answer":2,"explanation":"Speeding 15 mph or more over the limit is a serious traffic violation. Driving with a BAC of 0.04+, refusing a test, and driving on a suspended CDL are all MAJOR offenses, not serious violations. Source: MA RMV CDL Manual; 49 CFR 383.51(c).","handbook":"","hbref":""},{"q":"Under Massachusetts CDL rules, violating a law that prohibits TEXTING while driving a CMV is categorized as:","options":["A major offense","A serious traffic violation","An out-of-service order violation","A railroad-crossing violation"],"answer":1,"explanation":"Texting while driving a CMV is a serious traffic violation; accumulating two within 3 years causes a 60-day disqualification, three within 3 years causes 120 days. Source: MA RMV CDL Manual; 49 CFR 383.51(c); M.G.L. c. 90 sec. 13B.","handbook":"","hbref":""},{"q":"Using a HAND-HELD mobile telephone while driving a CMV is, for Massachusetts CDL disqualification purposes, treated as:","options":["A serious traffic violation","A major offense","An out-of-service violation","Not a disqualifying violation"],"answer":0,"explanation":"Using a hand-held phone while driving a CMV is a serious traffic violation that counts toward the 2-in-3-years (60 day) and 3-in-3-years (120 day) disqualification thresholds. Source: MA RMV CDL Manual; 49 CFR 383.51(c); M.G.L. c. 90 sec. 13B.","handbook":"","hbref":""},{"q":"Under Massachusetts' Hands-Free Law (M.G.L. c. 90 sec. 13B), the fine for a FIRST handheld-device offense is:","options":["$35","$100","$250","$500"],"answer":1,"explanation":"The Massachusetts Hands-Free Law sets fines of $100 for a first offense, $250 for a second, and $500 for a third or subsequent offense, with a required distracted-driving program for repeat offenders. Source: M.G.L. c. 90 sec. 13B.","handbook":"","hbref":""},{"q":"Under the Massachusetts Hands-Free Law, the fine for a THIRD or subsequent handheld-device offense is:","options":["$100","$250","$500","$1,000"],"answer":2,"explanation":"Fines escalate to $500 for a third or subsequent offense ($100 first, $250 second). A second or later offense also requires completion of a distracted-driving program. Source: M.G.L. c. 90 sec. 13B.","handbook":"","hbref":""},{"q":"What is the disqualification period for a FIRST railroad-highway grade crossing violation by a Massachusetts CDL driver?","options":["No less than 30 days","No less than 60 days","No less than 120 days","No less than 1 year"],"answer":1,"explanation":"A first railroad-highway grade crossing violation results in a disqualification of no less than 60 days. Source: MA RMV CDL Manual; 49 CFR 383.51(d).","handbook":"","hbref":""},{"q":"For a Massachusetts CDL driver, a SECOND railroad-highway grade crossing violation within a 3-year period results in a disqualification of:","options":["No less than 60 days","No less than 120 days","No less than 1 year","No less than 3 years"],"answer":1,"explanation":"A second railroad-crossing violation within 3 years results in a disqualification of no less than 120 days (first is 60 days, third within 3 years is no less than 1 year). Source: MA RMV CDL Manual; 49 CFR 383.51(d).","handbook":"","hbref":""},{"q":"A THIRD railroad-highway grade crossing violation within a 3-year period disqualifies a Massachusetts CDL driver for:","options":["No less than 120 days","No less than 180 days","No less than 1 year","Lifetime"],"answer":2,"explanation":"Three railroad-crossing violations within a 3-year period result in a disqualification of no less than 1 year. Source: MA RMV CDL Manual; 49 CFR 383.51(d).","handbook":"","hbref":""},{"q":"In Massachusetts, a FIRST conviction for violating a driver out-of-service (OOS) order (non-hazmat, non-passenger) results in a disqualification of:","options":["No less than 60 days","No less than 90 days","No less than 180 days nor more than 1 year","No less than 1 year nor more than 5 years"],"answer":2,"explanation":"A first out-of-service order violation results in a disqualification of no less than 180 days and no more than 1 year. Source: MA RMV CDL Manual; 49 CFR 383.51(e).","handbook":"","hbref":""},{"q":"A SECOND out-of-service order violation within a 10-year period disqualifies a Massachusetts CDL driver for:","options":["No less than 180 days nor more than 1 year","No less than 2 years nor more than 5 years","No less than 1 year nor more than 3 years","Lifetime"],"answer":1,"explanation":"A second out-of-service order violation within 10 years results in a disqualification of no less than 2 years and no more than 5 years. Source: MA RMV CDL Manual; 49 CFR 383.51(e).","handbook":"","hbref":""},{"q":"A FIRST out-of-service order violation while transporting placarded hazardous materials or operating a vehicle designed for 16+ passengers results in a Massachusetts CDL disqualification of:","options":["No less than 180 days nor more than 1 year","No less than 180 days nor more than 2 years","No less than 1 year nor more than 3 years","No less than 3 years nor more than 5 years"],"answer":1,"explanation":"A first out-of-service violation involving placarded hazmat or a 16+ passenger vehicle carries a heightened penalty: no less than 180 days and no more than 2 years. Source: MA RMV CDL Manual; 49 CFR 383.51(e).","handbook":"","hbref":""},{"q":"Which of the following is considered a MAJOR offense that disqualifies a Massachusetts CDL driver, even when committed in the driver's personal (non-commercial) vehicle?","options":["Following too closely","Improper lane change","Leaving the scene of an accident","Using a hand-held phone"],"answer":2,"explanation":"Leaving the scene of an accident is a major offense disqualifying the CDL whether committed in a CMV or a personal vehicle. The others are serious traffic violations only when committed while driving a CMV. Source: MA RMV CDL Manual; 49 CFR 383.51(b).","handbook":"","hbref":""},{"q":"A Massachusetts CDL driver who uses any motor vehicle to commit a felony involving the manufacturing, distributing, or dispensing of a controlled substance is disqualified for:","options":["1 year","3 years","10 years","Lifetime with no reinstatement"],"answer":3,"explanation":"Using a motor vehicle to commit a felony involving controlled substances (manufacture, distribution, or dispensing) results in a lifetime disqualification that is NOT subject to reinstatement. Source: MA RMV CDL Manual; M.G.L. c. 90F; 49 CFR 383.51(b).","handbook":"","hbref":""},{"q":"Under the Massachusetts railroad-crossing law, a school bus or a vehicle carrying explosives or flammable liquids as cargo must come to a full stop within what zone from the nearest rail?","options":["Not less than 15 feet and not more than 50 feet","Not less than 10 feet and not more than 40 feet","Not less than 5 feet and not more than 25 feet","Not less than 20 feet and not more than 75 feet"],"answer":0,"explanation":"Massachusetts General Laws c. 90, s. 15 requires a school bus or a vehicle carrying explosives or flammable liquids as cargo to stop not less than 15 feet and not more than 50 feet from the nearest track before crossing. Source: MGL c. 90, s. 15.","handbook":"","hbref":""},{"q":"On which Massachusetts statute is the state's 'Move Over' law based, and what is the basic requirement when approaching a stationary emergency, maintenance, or recovery vehicle displaying flashing lights?","options":["MGL c. 89, s. 7C; move over to a non-adjacent lane if possible, or slow to a safe and reasonable speed if you cannot","MGL c. 90, s. 14; come to a complete stop until the lights are turned off","MGL c. 85, s. 2; sound your horn and continue at posted speed","MGL c. 90, s. 17; reduce speed to no more than 20 mph and keep your lane"],"answer":0,"explanation":"Massachusetts' Move Over law, MGL c. 89, s. 7C (effective March 2009), requires drivers approaching a stationary emergency, maintenance, or recovery vehicle with flashing lights to move over to a non-adjacent lane when safe, and if unable, to reduce to a safe and reasonable speed. Source: MGL c. 89, s. 7C; Mass.gov Move Over Law.","handbook":"","hbref":""},{"q":"What is the penalty (fine) in Massachusetts for a violation of the Move Over law under MGL c. 89, s. 7C?","options":["$100","$35","$250","$500"],"answer":0,"explanation":"A violation of the Massachusetts Move Over law (MGL c. 89, s. 7C) carries a fine of $100. Source: MGL c. 89, s. 7C; Massachusetts State Police Move Over Law page.","handbook":"","hbref":""},{"q":"In Massachusetts, when must a driver approaching a stopped school bus with red lights flashing NOT be required to stop?","options":["When approaching from the opposite direction on a divided highway","When the driver is traveling at less than 20 mph","When the driver is more than two car lengths behind the bus","When the bus is stopped within a business district"],"answer":0,"explanation":"Under MGL c. 90, s. 14, every driver must stop before reaching a school bus displaying flashing red lights, except when approaching from the opposite direction on a divided highway. Source: MGL c. 90, s. 14.","handbook":"","hbref":""},{"q":"What is the minimum fine in Massachusetts for a first offense of failing to stop for, or illegally passing, a stopped school bus with red lights flashing?","options":["$250","$100","$50","$500"],"answer":0,"explanation":"Under MGL c. 90, s. 14, a first violation of the school bus stopping law carries a fine of at least $250; a second offense is $500-$1,000 with a 6-month license suspension. Source: MGL c. 90, s. 14.","handbook":"","hbref":""},{"q":"On a level, straight, divided highway, where should a CDL driver place the three emergency reflective triangles after stopping on the shoulder?","options":["Within 10 feet of the rear, about 100 feet to the rear, and about 200 feet to the rear","Within 25 feet, about 75 feet, and about 150 feet to the rear","Within 5 feet, about 50 feet, and about 100 feet to the rear","Within 15 feet, about 150 feet, and about 300 feet to the rear"],"answer":0,"explanation":"The Massachusetts CDL Manual (adopting 49 CFR 392.22) directs placing one triangle within 10 feet of the rear of the vehicle, one about 100 feet to the rear, and one about 200 feet to the rear on a divided or one-way road. Source: Massachusetts CDL Manual, Driving Safely (49 CFR 392.22).","handbook":"","hbref":""},{"q":"If a commercial vehicle is stopped within 500 feet of a hill, curve, or other obstruction that limits visibility, how should a CDL driver adjust the emergency-triangle placement?","options":["Move the rear-most triangle back so it is 100 to 500 feet from the vehicle, toward the obstruction, to give approaching drivers more warning","Remove all triangles and rely on the four-way flashers only","Place all three triangles within 50 feet of the vehicle so they stay together","Place only one triangle, directly behind the vehicle, no more than 10 feet away"],"answer":0,"explanation":"Per the Massachusetts CDL Manual (49 CFR 392.22), if a vehicle is stopped within 500 feet of a curve, crest of a hill, or other obstruction, the warning device toward the obstruction should be placed 100 to 500 feet from the vehicle to give approaching traffic adequate warning. Source: Massachusetts CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"On the Massachusetts Turnpike (I-90) between Interchange 14 in Weston and Interchange 9 in Sturbridge, which travel lanes may a heavy commercial vehicle (other than a bus) use?","options":["Only the extreme right-hand lane, or the next adjacent lane when overtaking and passing","Any lane, with no lane restriction for trucks on the Turnpike","Only the extreme left-hand lane to keep slower traffic clear","Only the two left-most lanes during daylight hours"],"answer":0,"explanation":"700 CMR 7.09 restricts a heavy commercial vehicle (other than a bus) between Interchange 14 (Weston) and Interchange 9 (Sturbridge) to the extreme right-hand travel lane, or the next adjacent lane only when overtaking and passing, except in an emergency. Source: 700 CMR 7.09.","handbook":"","hbref":""},{"q":"Why are box trucks, moving trucks, and other commercial vehicles prohibited from Storrow Drive and Soldiers Field Road in Boston (the cause of so-called 'Storrowing')?","options":["They are DCR 'cars only' parkways with low overpass clearances (roughly 10 feet or less), and trucks/buses are banned","They have a toll that only accepts commercial transponders","They are reserved for high-occupancy vehicles during rush hour","They have a posted truck speed limit too low for interstate freight"],"answer":0,"explanation":"Storrow Drive and Soldiers Field Road are Department of Conservation and Recreation (DCR) parkways restricted to passenger vehicles ('cars only'), with low bridge clearances around 10 feet or less; trucks, buses, and similar vehicles are banned, and over-height trucks routinely strike the overpasses. Source: 302 CMR 11.00; Mass.gov / DCR Storrowing campaign.","handbook":"","hbref":""},{"q":"Outside a thickly settled or business district on an undivided Massachusetts highway with no posted speed limit, what is the statutory speed above which you are presumed to be speeding?","options":["40 mph","30 mph","50 mph","55 mph"],"answer":0,"explanation":"Under MGL c. 90, s. 17, on an undivided way outside a thickly settled or business district with no posted limit, exceeding 40 mph for at least a quarter mile is prima facie evidence of speeding (the divided-highway figure is 50 mph). Source: MGL c. 90, s. 17.","handbook":"","hbref":""},{"q":"Inside a thickly settled or business district in Massachusetts, what is the statutory speed limit where none is posted?","options":["30 mph","25 mph","20 mph","35 mph"],"answer":0,"explanation":"Under MGL c. 90, s. 17, the statutory speed in a thickly settled or business district where no special limit is posted is 30 mph (a thickly settled district is defined as territory where dwelling houses average less than 200 feet apart). Source: MGL c. 90, s. 17.","handbook":"","hbref":""},{"q":"In Massachusetts, a school bus driver stopping at a railroad crossing must do which of the following in addition to stopping in the 15-to-50-foot zone?","options":["Open the service door, make sure it is safe to cross, then close the door before proceeding","Sound the horn three times before crossing","Set out reflective triangles on each side of the tracks","Shift into the highest available gear before crossing"],"answer":0,"explanation":"Under MGL c. 90, s. 15, a school bus operator must stop within 15-50 feet of the nearest rail, open the service door, ascertain it is safe to cross, and then close the door before proceeding. Source: MGL c. 90, s. 15.","handbook":"","hbref":""},{"q":"According to the Massachusetts CDL Manual, what should a driver do with the gears when driving a commercial vehicle across railroad tracks?","options":["Cross in a low enough gear that the tracks can be cleared without shifting","Shift up through the gears while on the tracks to clear them faster","Shift to neutral and coast across the tracks","Downshift in the middle of the crossing to reduce speed"],"answer":0,"explanation":"The Massachusetts CDL Manual instructs drivers to pick a gear that will let the vehicle cross the tracks completely without shifting, and not to change gears while on the tracks. Source: Massachusetts CDL Manual, Railroad Crossings (49 CFR 392.10).","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle weight a truck may operate at in Massachusetts on the federal highway system without an overweight permit?","options":["80,000 pounds","73,280 pounds","99,000 pounds","100,000 pounds"],"answer":0,"explanation":"Massachusetts follows the federal limit of 80,000 pounds gross vehicle weight without a special permit; loads above that require a MassDOT overweight permit. Source: MassDOT Commercial Truck Permits; federal weight limits applied in Massachusetts.","handbook":"","hbref":""},{"q":"Without an oversize permit, what is the maximum legal vehicle/load width allowed on Massachusetts highways?","options":["8 feet 6 inches (102 inches)","8 feet 0 inches (96 inches)","10 feet 0 inches (120 inches)","9 feet 0 inches (108 inches)"],"answer":0,"explanation":"The legal maximum width in Massachusetts without an oversize permit is 8 feet 6 inches (102 inches); wider loads require a MassDOT oversize permit. Source: MassDOT oversize/overweight regulations; Mass.gov Commercial Truck Permits.","handbook":"","hbref":""},{"q":"Without an oversize permit, what is the maximum legal height for a vehicle and load on Massachusetts highways?","options":["13 feet 6 inches","13 feet 0 inches","14 feet 0 inches","12 feet 6 inches"],"answer":0,"explanation":"Massachusetts sets the legal maximum height at 13 feet 6 inches; taller loads require a MassDOT oversize permit and may need a route survey. Source: MassDOT oversize/overweight regulations; Mass.gov Commercial Truck Permits.","handbook":"","hbref":""},{"q":"On the Massachusetts Turnpike, how does the heavy-commercial-vehicle lane restriction between Weston and Sturbridge treat buses?","options":["Buses are exempt from that right-lane-only restriction","Buses must stay in the left lane at all times","Buses are banned entirely from that segment","Buses must travel only at night"],"answer":0,"explanation":"Under 700 CMR 7.09, the right-lane-only restriction between Interchange 14 (Weston) and Interchange 9 (Sturbridge) applies to heavy commercial vehicles 'other than a bus,' so buses are exempt from that particular restriction. Source: 700 CMR 7.09.","handbook":"","hbref":""},{"q":"Under Massachusetts law, after a driver who is required to stop for a school bus has stopped, when may that driver proceed?","options":["When the bus's flashing red warning signals are deactivated, unless directed otherwise by a police officer","After waiting a fixed 10 seconds regardless of the lights","As soon as the bus's amber (yellow) lights begin flashing","Immediately, as long as no children are visible"],"answer":0,"explanation":"MGL c. 90, s. 14 requires the stopped driver to remain stopped until the school bus's flashing red signals are deactivated, unless directed to proceed by a police officer. Source: MGL c. 90, s. 14.","handbook":"","hbref":""},{"q":"Under MGL c. 90, s. 14, how closely may a vehicle follow behind a school bus on a Massachusetts public way?","options":["No closer than 100 feet","No closer than 50 feet","No closer than 200 feet","No closer than 25 feet"],"answer":0,"explanation":"MGL c. 90, s. 14 prohibits operating a vehicle within 100 feet behind a school bus (except when overtaking and passing it where permitted). Source: MGL c. 90, s. 14.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver's Licenses (CDLs) in Massachusetts?","options":["The Registry of Motor Vehicles (RMV), part of MassDOT","The Federal Motor Carrier Safety Administration (FMCSA)","The Massachusetts Department of Public Safety","The Massachusetts State Police Commercial Vehicle Section"],"answer":0,"explanation":"In Massachusetts, CDLs are issued by the Registry of Motor Vehicles (RMV), a division of the Massachusetts Department of Transportation (MassDOT). The FMCSA sets federal standards but does not issue the license. Source: Mass.gov RMV Commercial Driver's Licenses (CDL) pages.","handbook":"","hbref":""},{"q":"Before you can take any CDL skills (road) test in Massachusetts, you must first obtain which document?","options":["A Commercial Learner's Permit (CLP)","A full Class A CDL","A federal interstate operating authority (MC number)","A hazardous materials endorsement"],"answer":0,"explanation":"To operate a commercial motor vehicle for practice and to qualify for the skills test, a Massachusetts applicant must first pass the knowledge test(s) and obtain a Commercial Learner's Permit (CLP). Source: Mass.gov RMV CDL pages; 49 CFR 383.","handbook":"","hbref":""},{"q":"How long must a Massachusetts CLP holder wait after the CLP is issued before they are eligible to take the CDL skills test?","options":["At least 14 days","At least 24 hours","At least 30 days","At least 60 days"],"answer":0,"explanation":"A CLP must be held for a minimum of 14 days before the applicant can take the CDL skills test. This is a federal requirement (49 CFR 383.37) that Massachusetts applies. Source: Mass.gov RMV CDL pages; 49 CFR 383.37.","handbook":"","hbref":""},{"q":"How long is a Massachusetts Commercial Learner's Permit (CLP) valid?","options":["180 days, renewable once for an additional 180 days","30 days, with no renewal allowed","1 year, renewable twice","90 days, renewable once for an additional 90 days"],"answer":0,"explanation":"A Massachusetts CLP is valid for 180 days and may be renewed once for an additional 180 days without retaking the knowledge tests; after that the applicant must reapply. Source: Mass.gov RMV CDL pages; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"The Massachusetts CDL skills test is made up of which three parts?","options":["Pre-trip inspection, basic vehicle control, and on-road driving","Written exam, vision screening, and road driving","Air brakes check, hazmat handling, and on-road driving","Coupling/uncoupling, logbook review, and on-road driving"],"answer":0,"explanation":"The Massachusetts CDL skills test has three segments: the pre-trip (vehicle) inspection, basic vehicle control (control skills such as backing), and the on-road driving test. Source: Mass.gov RMV CDL Skills Test Information Sheet / Modernized CDL Skills Exam Standard.","handbook":"","hbref":""},{"q":"How many self-certification categories must a Massachusetts CDL/CLP applicant choose from when certifying the type of driving they perform?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"Federal and Massachusetts rules require the driver to self-certify into one of four categories of commerce. Source: Mass.gov 'Commercial Driver's License (CDL) Self-Certification'; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which of the following is one of the four CDL self-certification categories used in Massachusetts?","options":["Non-Excepted Interstate (NI)","Restricted Commercial (RC)","Federal Excepted Operator (FEO)","Limited Intrastate Hauler (LIH)"],"answer":0,"explanation":"The four categories are Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), and Excepted Intrastate (EA). The other options are not real categories. Source: Mass.gov CDL Self-Certification; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Under Massachusetts/FMCSA rules, a driver who self-certifies as 'Non-Excepted Interstate (NI)' is making what statement about their operation?","options":["They operate across state lines and must meet federal DOT medical card requirements","They operate only within Massachusetts and need no medical certificate","They operate across state lines but are exempt from medical requirements","They operate only within Massachusetts and meet only state medical rules"],"answer":0,"explanation":"Non-Excepted Interstate (NI) means the driver operates (or expects to operate) in interstate commerce and is required to meet the federal DOT medical examiner's certificate requirements. Source: Mass.gov CDL Self-Certification; 49 CFR 383.71/391.","handbook":"","hbref":""},{"q":"A driver who self-certifies as 'Excepted Intrastate (EA)' in Massachusetts is indicating which of the following?","options":["They operate only within Massachusetts and are not required to meet the federal DOT medical card requirements","They operate across state lines and must carry a federal medical card","They operate only within Massachusetts and must hold a federal DOT medical card","They are restricted to hazardous materials transport only"],"answer":0,"explanation":"Excepted Intrastate (EA) means the driver operates only in intrastate (within-state) commerce and is excepted from the federal DOT medical card requirements. Source: Mass.gov CDL Self-Certification; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"When a non-excepted interstate Massachusetts CDL driver passes a DOT physical, what document does the certified medical examiner issue?","options":["A Medical Examiner's Certificate (Form MCSA-5876)","A Massachusetts RMV Class D vision waiver","A federal Hours-of-Service exemption letter","An FMCSA operating authority certificate"],"answer":0,"explanation":"An examiner from the FMCSA National Registry who finds the driver qualified issues a Medical Examiner's Certificate (Form MCSA-5876). Source: Mass.gov CDL Self-Certification / Medical Certification; FMCSA National Registry.","handbook":"","hbref":""},{"q":"A Massachusetts CDL medical examiner who performs DOT physicals must be listed where?","options":["On the FMCSA National Registry of Certified Medical Examiners","On the Massachusetts RMV approved physician roster","On the Massachusetts Board of Registration in Medicine CDL list","On the MassDOT Highway Division provider list"],"answer":0,"explanation":"DOT physicals for CDL purposes must be performed by a medical examiner listed on the FMCSA National Registry of Certified Medical Examiners. Source: Mass.gov CDL Self-Certification; FMCSA National Registry.","handbook":"","hbref":""},{"q":"As of mid-2025, how does medical certification information for most Massachusetts CDL drivers reach the RMV?","options":["Electronically from the FMCSA National Registry, so a paper card usually need not be submitted","Only by the driver mailing a paper card to the RMV within 5 days","Only by the employer faxing the card to MassDOT","Automatically from the driver's insurance carrier"],"answer":0,"explanation":"Beginning June 23, 2025, the RMV receives medical certification information electronically from the FMCSA National Registry, so most drivers do not need to submit a physical copy (intrastate-only drivers may still submit one if not uploaded). Source: Mass.gov CDL Self-Certification.","handbook":"","hbref":""},{"q":"Which training must a first-time Class A or Class B Massachusetts applicant complete before the RMV will schedule the CDL skills test?","options":["Entry-Level Driver Training (ELDT) from an FMCSA-registered provider","A 40-hour MassDOT defensive-driving course","A state-run apprenticeship at an RMV service center","An employer-issued road safety orientation only"],"answer":0,"explanation":"Since February 7, 2022, first-time Class A/B applicants (and first-time S, P, or H endorsements) must complete Entry-Level Driver Training (ELDT) from a provider listed on the FMCSA Training Provider Registry before the RMV schedules the skills test. Source: Mass.gov ELDT guide; 49 CFR Part 380 Subpart F.","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) required before the Massachusetts CDL skills test consists of which two components?","options":["Theory instruction and behind-the-wheel instruction","A written exam and a vision screening","Classroom-only instruction and a federal background check","A medical exam and a drug screening"],"answer":0,"explanation":"ELDT requires successful completion of a prescribed program of theory and behind-the-wheel instruction before taking the CDL skills test. Source: Mass.gov ELDT guide; FMCSA 49 CFR Part 380 Subpart F.","handbook":"","hbref":""},{"q":"Besides first-time Class A/B applicants, ELDT must also be completed before applying for which endorsement for the first time?","options":["Hazardous materials (H), passenger (P), or school bus (S)","Tank vehicle (N) only","Double/triple trailers (T) only","Air brakes (no restriction)"],"answer":0,"explanation":"ELDT applies to first-time Class A/B CDLs, Class B-to-A upgrades, and the first-time hazardous materials (H), passenger (P), and school bus (S) endorsements. Source: Mass.gov ELDT guide; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"How long is a Massachusetts CDL valid before it must be renewed?","options":["5 years","2 years","8 years","10 years"],"answer":0,"explanation":"A Massachusetts CDL is valid for 5 years and generally expires on the holder's birthday. Source: Mass.gov RMV license renewal pages.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an intrastate-only (Massachusetts-only) CDL, and the minimum age for interstate operation?","options":["18 for intrastate and 21 for interstate","16 for intrastate and 18 for interstate","18 for both intrastate and interstate","21 for both intrastate and interstate"],"answer":0,"explanation":"An applicant must be at least 18 to obtain an intrastate (within Massachusetts) CDL/CLP and at least 21 to operate in interstate commerce. Source: Mass.gov RMV CDL pages; 49 CFR 383.3/391.11.","handbook":"","hbref":""},{"q":"When applying for a Massachusetts CLP/CDL, which set of documents must the applicant generally provide?","options":["Proof of identity/lawful presence, a Social Security number, and Massachusetts residency","Only a valid passport and a vehicle registration","Only an employer letter and a vehicle title","A birth certificate and a credit report"],"answer":0,"explanation":"Massachusetts CDL applicants must prove identity/lawful presence, provide a Social Security number, and prove Massachusetts residency, the same identity standards used for other RMV credentials. Source: Mass.gov RMV CDL and identification requirements.","handbook":"","hbref":""},{"q":"On the Massachusetts CDL general knowledge written test, what passing score is required?","options":["At least 80% correct","At least 60% correct","At least 70% correct","A perfect 100% correct"],"answer":0,"explanation":"Massachusetts CDL knowledge tests, including the general knowledge test, require a passing score of at least 80% correct. Source: Massachusetts CDL Manual; Mass.gov RMV CDL testing pages.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная разрешённая ширина коммерческого автомобиля на дорогах Массачусетса, не считая зеркал, указателей поворота и некоторых устройств безопасности?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"Массачусетс ограничивает ширину автомобиля до 102 inches (8 feet 6 inches), не считая зеркал, указателей поворота и некоторых устройств безопасности. Источник: MGL Chapter 90, Section 19; Massachusetts RMV CDL Manual."},"1":{"q":"Какова максимальная разрешённая высота автомобиля вместе с грузом на автомагистралях Массачусетса без специального разрешения?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"Массачусетс устанавливает максимальную высоту автомобиля с грузом в 13 feet 6 inches. Автомобили выше 10 feet должны иметь обозначение своей высоты. Источник: MGL Chapter 90, Section 19; MassDOT commercial truck height limits."},"2":{"q":"Без специального разрешения, какова максимальная длина полуприцепа в составе автопоезда «тягач — полуприцеп» в Массачусетсе?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"Полуприцеп в составе автопоезда «тягач — полуприцеп» в Массачусетсе может иметь длину до 53 feet. Источник: MGL Chapter 90, Section 19; Massachusetts RMV CDL Manual."},"3":{"q":"Какова максимальная полная масса автомобиля, разрешённая на дорогах Массачусетса без разрешения, для автомобиля с тремя или более осями?","options":["73,280 pounds","80,000 pounds","88,000 pounds","99,000 pounds"],"explanation":"Массачусетс ограничивает полную массу автомобиля до 80,000 pounds для автомобилей с тремя или более осями, что соответствует федеральному максимуму для межштатных автомагистралей. Источник: MGL Chapter 90, Section 19A."},"4":{"q":"Какую максимальную нагрузку Массачусетс разрешает на одиночную ось без разрешения на перевес?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Массачусетс допускает до 22,400 pounds на одиночную ось, что выше федерального лимита для межштатных автомагистралей в 20,000 pounds. Источник: MGL Chapter 90, Section 19A."},"5":{"q":"Какую максимальную нагрузку Массачусетс разрешает на сдвоенную ось (две оси) без разрешения на перевес?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Массачусетс устанавливает лимит для сдвоенной оси в 34,000 pounds, что соответствует федеральному стандарту. Источник: MGL Chapter 90, Section 19A."},"6":{"q":"В Массачусетсе, какова максимальная высота прямого (одиночного) грузовика, при превышении которой на автомобиле требуется наносить обозначения высоты?","options":["8 feet","10 feet","12 feet","13 feet 6 inches"],"explanation":"Массачусетс требует, чтобы автомобили выше 10 feet имели обозначения своей высоты, хотя законная максимальная высота составляет 13 feet 6 inches. Источник: MGL Chapter 90, Section 19."},"7":{"q":"Какое ведомство Массачусетса выдаёт разрешения на негабаритные и тяжеловесные перевозки по автомагистралям штата?","options":["The Registry of Motor Vehicles (RMV)","The MassDOT Highway Division","The Massachusetts State Police","The Federal Motor Carrier Safety Administration"],"explanation":"Разрешения на негабаритные/тяжеловесные перевозки по автомагистралям штата выдаёт MassDOT Highway Division через своё Truck Permit Office. Источник: Mass.gov Commercial Truck Permits; MassDOT."},"8":{"q":"Как называется онлайн-система MassDOT, используемая для подачи заявок на разрешения для негабаритных/тяжеловесных коммерческих грузовиков и определения маршрута?","options":["ATLAS","OASIS","PRISM","UCR"],"explanation":"Веб-приложение MassDOT для оформления разрешений на негабаритные/тяжеловесные перевозки и определения маршрута называется OASIS, оно используется для подачи заявок на разрешения для коммерческих грузовиков. Источник: MassDOT Highway Division; Mass.gov."},"9":{"q":"В каких случаях для автомобиля требуется получить разрешение MassDOT на негабаритную/тяжеловесную перевозку?","options":["Только при пересечении границы штата","Всякий раз, когда он превышает законные лимиты по ширине, высоте, длине или массе","Только при перевозке опасных грузов","Только при движении в ночное время"],"explanation":"Разрешение требуется всякий раз, когда автомобиль или груз превышает законные лимиты по ширине (102 in), высоте (13'6\"), длине или массе (80,000 lb). Источник: MGL Chapter 90, Section 19/19A; MassDOT."},"10":{"q":"Массачусетс применяет федеральную мостовую формулу (Bridge Formula) к нагрузке на группу из двух или более последовательных осей. Какой постоянный множитель используется в этой формуле, W = 500[LN/(N-1) + 12N + 36]?","options":["100","250","500","1,000"],"explanation":"Федеральная мостовая формула, принятая в Массачусетсе, использует константу 500: W = 500[LN/(N-1) + 12N + 36], где L — расстояние между осями, а N — количество осей. Источник: MGL Chapter 90, Section 19A; FHWA Bridge Formula."},"11":{"q":"В федеральной мостовой формуле (Bridge Formula), используемой в Массачусетсе, что обозначает переменная «L»?","options":["Законную массу груза в фунтах","Расстояние в футах между крайними (внешними) осями группы","Ширину полосы движения автомагистрали","Длину прицепа в футах"],"explanation":"В формуле W = 500[LN/(N-1) + 12N + 36] «L» — это расстояние в футах между крайними осями любой группы из двух или более последовательных осей. Источник: MGL Chapter 90, Section 19A; FHWA Bridge Formula."},"12":{"q":"Какова максимальная полная масса, разрешённая Массачусетсом для автомобиля только с двумя осями, без разрешения?","options":["34,000 pounds","40,000 pounds","46,000 pounds","54,000 pounds"],"explanation":"Двухосный автомобиль в Массачусетсе ограничен полной массой 46,000 pounds, тогда как автомобили с тремя или более осями могут достигать 80,000 pounds. Источник: MGL Chapter 90, Section 19A."},"13":{"q":"В Массачусетсе, если две одиночные оси расположены на расстоянии менее 6 feet друг от друга, какова максимальная нагрузка, разрешённая на каждую такую ось?","options":["16,000 pounds","18,000 pounds","20,000 pounds","22,400 pounds"],"explanation":"Когда оси расположены на расстоянии менее 6 feet друг от друга, допустимая нагрузка на одиночную ось снижается с 22,400 pounds до 18,000 pounds на каждую. Источник: MGL Chapter 90, Section 19A."},"14":{"q":"Как лимиты Массачусетса на максимальную ширину и высоту на межштатных автомагистралях (Interstate) соотносятся с лимитами на других автомагистралях штата?","options":["Лимиты по ширине и высоте одинаковы (102 in в ширину, 13'6\" в высоту) на обоих типах дорог","На межштатных автомагистралях разрешена бóльшая ширина 8'6\", а на других дорогах только 8'","На межштатных автомагистралях разрешена высота 14 feet, а на других дорогах только 13'6\"","На других дорогах штата разрешены более широкие автомобили, чем на межштатных автомагистралях"],"explanation":"Лимиты в 102 inches по ширине и 13 feet 6 inches по высоте применяются единообразно как на межштатных автомагистралях/National Network, так и на других автомагистралях штата в Массачусетсе. Источник: MGL Chapter 90, Section 19; J.J. Keller MA size/weight summary."},"15":{"q":"По сравнению с федеральным лимитом на одиночную ось для межштатных автомагистралей, допустимая нагрузка на одиночную ось в Массачусетсе:","options":["Ниже (Массачусетс разрешает 18,000 lb против федеральных 20,000 lb)","Такая же (оба 20,000 lb)","Выше (Массачусетс разрешает 22,400 lb против федеральных 20,000 lb)","Неограниченна на дорогах штата"],"explanation":"Массачусетс допускает 22,400 pounds на одиночную ось, что выше федерального стандарта для межштатных автомагистралей в 20,000 pounds. Источник: MGL Chapter 90, Section 19A."},"16":{"q":"Без разрешения, какова максимальная длина прямого (одиночного) грузовика в Массачусетсе?","options":["33 feet","40 feet","45 feet","53 feet"],"explanation":"Прямой грузовик (одиночный) в Массачусетсе может иметь длину до 40 feet; полуприцеп в составе автопоезда может иметь длину до 53 feet. Источник: MGL Chapter 90, Section 19."},"17":{"q":"Перевозчику необходимо переместить груз шириной 14 feet по автомагистрали штата Массачусетс. Что должен сделать перевозчик?","options":["Ничего, поскольку 14 feet находится в пределах законного лимита по ширине","Получить разрешение на негабаритную перевозку в MassDOT Highway Division перед поездкой","Уведомить только местное полицейское управление","Подать заявку на специальную отметку (endorsement) к CDL"],"explanation":"При ширине 14 feet груз превышает законную ширину 102 inches (8'6\"), поэтому перед поездкой необходимо получить разрешение на негабаритную перевозку в MassDOT Highway Division (через OASIS). Источник: MGL Chapter 90, Section 19; MassDOT."},"18":{"q":"Согласно закону Массачусетса, какова максимальная законная общая длина для тягача со сдвоенными/тандемными прицепами (при законной длине каждого прицепа)?","options":["Каждый прицеп до 28 feet, без ограничения общей длины автопоезда, когда прицепы соответствуют закону","Фиксированный лимит общей длины 65 feet независимо от длины прицепа","Фиксированный лимит общей длины 53 feet","Сдвоенные прицепы запрещены в Массачусетсе"],"explanation":"В составе тягача со сдвоенными прицепами каждый прицеп (тандемная единица) может иметь длину до 28 feet, и общего ограничения длины автопоезда нет, когда прицепы соответствуют закону. Источник: MGL Chapter 90, Section 19; J.J. Keller MA size/weight summary."},"19":{"q":"В Массачусетсе, какой класс CDL требуется для управления одиночным автомобилем с полной разрешённой массой (GVWR) 26,001 lbs. или более, который НЕ буксирует прицеп массой свыше 10,000 lbs.?","options":["Class A","Class B","Class C","Class D"],"explanation":"Массачусетс требует CDL класса Class B для управления любым одиночным автомобилем с GVWR 26,001 lbs. или более, либо таким автомобилем, буксирующим прицеп массой не более 10,000 lbs. (например, фургоны, самосвалы, прямые грузовики). Источник: Mass.gov «CDL classes and endorsements» и Massachusetts CDL Manual (RMV)."},"20":{"q":"Водитель из Массачусетса хочет управлять автопоездом «тягач — прицеп» с полной разрешённой массой автопоезда (GCWR) 80,000 lbs., где буксируемый прицеп имеет массу свыше 10,000 lbs. Какой класс CDL требуется?","options":["Class B","Class C","Class A","Class D"],"explanation":"В Массачусетсе CDL класса Class A требуется для любого сочетания автомобилей с GCWR 26,001 lbs. или более, где буксируемая(ые) единица(ы) превышает(ют) 10,000 lbs. GVWR. Источник: Mass.gov «CDL classes and endorsements» и Massachusetts CDL Manual (RMV)."},"21":{"q":"Согласно правилам Массачусетса, автомобиль, который не достигает весовых порогов класса Class A или Class B, но рассчитан на перевозку 16 или более пассажиров (включая водителя) либо на перевозку опасных грузов с табличками (placards), требует какого класса CDL?","options":["Class C","Class A","Class B","Class M"],"explanation":"Массачусетс требует CDL класса Class C для автомобиля, который не подпадает под Class A или Class B, но рассчитан на перевозку 16 или более человек (включая водителя) либо используется для перевозки опасных грузов, требующих табличек (placards). Источник: Mass.gov «CDL classes and endorsements» и Massachusetts CDL Manual (RMV)."},"22":{"q":"Каков минимальный возраст для получения CDL Массачусетса или ученического коммерческого разрешения (Commercial Learner's Permit) с ограничением ВНУТРИШТАТНОЙ (только в пределах Массачусетса) коммерческой деятельностью?","options":["16 years old","17 years old","18 years old","21 years old"],"explanation":"Массачусетс требует, чтобы заявители были не моложе 18 лет для внутриштатного (только в пределах Массачусетса) CDL/CLP. Для вождения в межштатной коммерческой деятельности требуется возраст 21 год. Источник: Mass.gov «Apply for a Commercial Learner's Permit (CLP)» (RMV)."},"23":{"q":"Каков минимальный возраст, требуемый для управления коммерческим автомобилем в МЕЖШТАТНОЙ коммерческой деятельности по CDL Массачусетса?","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"Водитель должен быть не моложе 21 года для управления CMV за пределами штата (межштатная коммерческая деятельность). Водители в возрасте 18-20 лет ограничены внутриштатной (только в пределах Массачусетса) деятельностью. Источник: страницы Mass.gov RMV CLP/CDL, в соответствии с 49 CFR 391.11."},"24":{"q":"Какой код отметки (endorsement) требуется на CDL Массачусетса для управления автомобилем, рассчитанным на перевозку пассажиров, таким как большой автобус?","options":["Code N","Code P","Code T","Code H"],"explanation":"Пассажирская отметка (P) требуется в Массачусетсе для управления автомобилем, рассчитанным на перевозку пассажиров (например, автобусами). Для неё необходимо сдать теоретический тест и практический тест на представительном автомобиле. Источник: Mass.gov «CDL classes and endorsements» и Massachusetts CDL Manual (RMV)."},"25":{"q":"Какая отметка (endorsement) к CDL требуется для перевозки опасных грузов в количествах, требующих табличек (placards), в Массачусетсе?","options":["N (Tanker)","T (Doubles/Triples)","H (Hazardous Materials)","S (School Bus)"],"explanation":"Отметка H (Hazardous Materials) требуется для перевозки опасных грузов в количествах, требующих табличек. Для неё необходимы теоретический тест, оценка угрозы безопасности TSA (security threat assessment) и теоретическое обучение ELDT для впервые подающих заявку. Источник: Mass.gov «CDL classes and endorsements» и программа TSA HazMat endorsement."},"26":{"q":"В Массачусетсе, какая отметка (endorsement) требуется для буксировки сдвоенных или строенных прицепов?","options":["T endorsement","N endorsement","X endorsement","P endorsement"],"explanation":"Отметка T (Doubles/Triples) требуется для буксировки более одного прицепа. Она получается только путём сдачи теоретического теста (без отдельного практического теста). Источник: Mass.gov «CDL classes and endorsements» и Massachusetts CDL Manual (RMV)."},"27":{"q":"Какая отметка (endorsement) нужна владельцу CDL Массачусетса для управления автоцистерной, перевозящей жидкий или газообразный груз?","options":["H endorsement","T endorsement","N endorsement","S endorsement"],"explanation":"Отметка N (Tank Vehicle) требуется для управления автоцистерной, предназначенной для перевозки жидкостей или газов наливом/насыпью. Она получается путём сдачи теоретического теста по автоцистернам. Источник: Mass.gov «CDL classes and endorsements» и Massachusetts CDL Manual (RMV)."},"28":{"q":"В Массачусетсе, какую отметку (endorsement) водитель уже должен иметь (как обязательное условие) перед получением отметки School Bus (S)?","options":["H (Hazardous Materials)","P (Passenger)","N (Tank Vehicle)","T (Doubles/Triples)"],"explanation":"Массачусетс требует наличия пассажирской отметки (P) как обязательного условия для получения отметки School Bus (S). Водитель должен сдать теоретические тесты P и S и практический тест на школьном автобусе. Источник: Mass.gov «CDL classes and endorsements» и «Apply for a school bus learner's permit» (RMV)."},"29":{"q":"Согласно федеральным правилам, применяемым Massachusetts RMV, как долго заявитель должен владеть ученическим коммерческим разрешением (Commercial Learner's Permit), прежде чем получить право сдавать практический (дорожный) тест на CDL?","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"explanation":"Федеральное правило (49 CFR 383.25), применяемое Massachusetts RMV, требует владеть CLP не менее 14 days, прежде чем заявитель сможет сдавать практический тест. Отсчёт начинается со дня выдачи разрешения. Источник: страница Mass.gov RMV CLP и FMCSA 49 CFR 383.25."},"30":{"q":"Как долго действительно ученическое коммерческое разрешение (CLP) Массачусетса, прежде чем его нужно продлить или сдать практический тест?","options":["90 days","180 days","1 year","2 years"],"explanation":"CLP Массачусетса действительно в течение 180 days. Оно может быть продлено один раз ещё на 180 days без повторной сдачи общего теоретического теста, в соответствии с федеральными ограничениями. Источник: Mass.gov «Apply for a Commercial Learner's Permit (CLP)» (RMV)."},"31":{"q":"При вождении по ученическому коммерческому разрешению (CLP) Массачусетса владелец CLP должен сопровождаться лицом, которое:","options":["Не моложе 25 лет и имеет любые водительские права","Имеет действительный CDL надлежащего класса и с надлежащими отметками, находясь рядом с водителем","Является только сертифицированным инструктором по вождению","Имеет не менее 5 лет опыта коммерческого вождения"],"explanation":"Владелец CLP может управлять CMV только в сопровождении лица, которое имеет действительный CDL соответствующего класса и с соответствующими отметками, находясь на переднем сиденье рядом с водителем. Источник: страница Mass.gov RMV CLP и 49 CFR 383.25."},"32":{"q":"Какое сочетание документов заявитель должен предъявить в Massachusetts RMV, чтобы подтвердить право на получение CDL или CLP?","options":["Подтверждение личности/законного пребывания, номер Social Security и подтверждение проживания в Массачусетсе","Только карточку Social Security","Только действующий паспорт","Аттестат об окончании средней школы и подтверждение проживания"],"explanation":"Massachusetts RMV требует подтверждения личности и законного пребывания в США, номера Social Security и подтверждения проживания в Массачусетсе для выдачи CLP/CDL. Источник: требования к подаче заявки на CDL/CLP Mass.gov RMV и 49 CFR 383.71."},"33":{"q":"Обучение водителей начального уровня (Entry-Level Driver Training, ELDT), требуемое до первого практического теста на CDL класса Class A в Массачусетсе, должно быть пройдено у провайдера, который:","options":["Одобрен только Massachusetts RMV","Внесён в реестр провайдеров обучения FMCSA (Training Provider Registry, TPR)","Сертифицирован Министерством образования США (U.S. Department of Education)","Любая лицензированная автошкола Массачусетса"],"explanation":"ELDT должно быть пройдено у провайдера, внесённого в реестр провайдеров обучения FMCSA (Training Provider Registry, TPR). Только провайдеры, зарегистрированные в TPR, могут проводить требуемое теоретическое и практическое обучение за рулём. Источник: руководство Mass.gov «Entry-Level Driver Training (ELDT)» и FMCSA TPR (49 CFR Part 380)."},"34":{"q":"Для первичного получения отметки Hazardous Materials (H) в Массачусетсе, какой вид ELDT должен быть пройден и когда?","options":["Только теоретическое обучение, перед сдачей теоретического теста","Только практическое обучение за рулём, перед практическим тестом","И теоретическое, и практическое обучение за рулём, перед дорожным тестом","ELDT не требуется для отметки H"],"explanation":"Для отметки H обучение ELDT состоит только из теоретической части и должно быть пройдено до сдачи государственного теоретического теста по HazMat. Отдельного практического теста для отметки H нет. Источник: руководство Mass.gov ELDT и FMCSA TPR (49 CFR Part 380)."},"35":{"q":"Водитель из Массачусетса, который работает только в пределах Массачусетса и должен соответствовать медицинским квалификационным требованиям штата, должен подать самодекларацию (self-certify) по какой категории?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Категория Non-Excepted Intrastate (NA) применяется к водителям, работающим только во внутриштатной коммерческой деятельности, которые должны соответствовать медицинским/квалификационным стандартам Массачусетса и иметь сертификат медицинского эксперта (medical examiner's certificate). Источник: Mass.gov «CDL Self-Certification» (RMV) и 49 CFR 383.71."},"36":{"q":"Водитель, подавший самодекларацию как Non-Excepted Interstate (NI) в Массачусетсе, должен хранить в RMV действительный медицинский сертификат от эксперта, который:","options":["Любой лицензированный врач в Массачусетсе","Внесён в Национальный реестр сертифицированных медицинских экспертов FMCSA (National Registry of Certified Medical Examiners)","Одобрен работодателем водителя","Штатный эксперт Massachusetts RMV"],"explanation":"Водители категории Non-Excepted Interstate должны пройти медосмотр DOT (DOT physical), проводимый медицинским экспертом, внесённым в Национальный реестр сертифицированных медицинских экспертов FMCSA (National Registry of Certified Medical Examiners), и поддерживать медицинский сертификат действительным в RMV. Источник: Mass.gov «Medical standards for CDL» и 49 CFR 391.41-391.43."},"37":{"q":"Помимо прохождения теоретической части ELDT и сдачи теоретического теста, отметка Hazardous Materials (H) в Массачусетсе также требует от заявителя:","options":["Пройти практический дорожный тест для опасных грузов","Пройти оценку угрозы безопасности TSA (security threat assessment), включая снятие отпечатков пальцев","Сначала иметь отметку Tank (N)","Быть не моложе 25 лет"],"explanation":"Отметка H требует прохождения оценки угрозы безопасности TSA (security threat assessment), которая включает предоставление отпечатков пальцев и биографических данных, а также проверку по уголовным/иммиграционным/террористическим спискам, в дополнение к теоретическому тесту и теоретической части ELDT. Источник: Mass.gov «CDL classes and endorsements» и программа TSA HazMat endorsement (49 CFR 1572)."},"38":{"q":"Какая группа водителей подпадает под требования об обучении водителей начального уровня (ELDT) в Массачусетсе?","options":["Только водители, продлевающие существующий CDL","Водители, впервые получающие CDL класса Class A или Class B, повышающие класс с Class B до Class A или впервые получающие отметку S, P или H","Только водители из других штатов, переоформляющие CDL","Только водители старше 21 года"],"explanation":"ELDT применяется к заявителям, впервые получающим CDL класса Class A или Class B, повышающим класс с Class B до Class A, либо впервые получающим отметку школьного автобуса (S), пассажирскую (P) или опасных грузов (H). Источник: руководство Mass.gov «Entry-Level Driver Training (ELDT)» и FMCSA TPR (49 CFR Part 380)."},"39":{"q":"В Массачусетсе, какова максимальная концентрация алкоголя в крови (BAC), при которой человек может законно управлять коммерческим автомобилем (CMV)?","options":["0.08","0.04","0.02","0.00"],"explanation":"Массачусетс следует федеральному стандарту: управление CMV с BAC 0.04 или выше является серьёзным правонарушением (major offense) и нарушением, влекущим дисквалификацию. Лимит 0.08 применяется к некоммерческим водителям. Источник: MA RMV CDL Manual, Section 1 (Disqualifications); 49 CFR 383.51."},"40":{"q":"Согласно правилам CDL Массачусетса, водитель, управляющий CMV с BAC 0.04 или более при ПЕРВОМ серьёзном правонарушении (и не перевозящий опасные грузы с табличками), дисквалифицируется на какой срок?","options":["60 days","90 days","1 year","3 years"],"explanation":"Первое серьёзное правонарушение (major offense), такое как управление CMV с BAC 0.04 или более, влечёт минимальную дисквалификацию на 1 year (3 years при перевозке опасных грузов с табличками). Источник: MA RMV CDL Manual; M.G.L. c. 90F; 49 CFR 383.51."},"41":{"q":"В Массачусетсе, если водитель CDL совершает первое серьёзное правонарушение (major offense) при управлении CMV, перевозящим опасные грузы с табличками (placards), срок дисквалификации увеличивается до:","options":["1 year","2 years","3 years","5 years"],"explanation":"Когда первое серьёзное правонарушение совершается при наличии на CMV табличек опасных грузов, дисквалификация увеличивается с 1 year до 3 years. Источник: MA RMV CDL Manual (Disqualifications); 49 CFR 383.51(b)."},"42":{"q":"Каков срок дисквалификации CDL в Массачусетсе за ВТОРОЕ серьёзное правонарушение (major offense) (например, второе OUI или второй отказ), возникшее в результате отдельных инцидентов?","options":["3 years","10 years","Пожизненно","5 years"],"explanation":"Второе серьёзное правонарушение (major offense), в любом сочетании и возникшее в результате отдельных инцидентов, влечёт пожизненную дисквалификацию CDL. Источник: MA RMV CDL Manual; M.G.L. c. 90F; 49 CFR 383.51(b)."},"43":{"q":"В Массачусетсе, согласно правилу подразумеваемого согласия (implied consent), водитель CDL, который ОТКАЗЫВАЕТСЯ пройти требуемый тест на алкоголь (химический тест) при управлении CMV, считается совершившим:","options":["Серьёзное нарушение ПДД (serious traffic violation) (дисквалификация на 60 days)","Незначительное нарушение только со штрафом","Серьёзное правонарушение (major offense) (дисквалификация на 1 year, 3 years при hazmat)","Нарушение на железнодорожном переезде"],"explanation":"Управляя CMV, водитель даёт подразумеваемое согласие на тестирование на алкоголь. Отказ от теста является серьёзным правонарушением (major offense), влекущим то же наказание, что и вождение в состоянии опьянения: дисквалификация на 1 year (3 years при наличии табличек hazmat) и пожизненно при повторном случае. Источник: MA RMV CDL Manual; 49 CFR 383.51(b); M.G.L. c. 90F."},"44":{"q":"Сколько СЕРЬЁЗНЫХ нарушений ПДД (serious traffic violations) в течение 3-летнего периода (в отдельных инцидентах) влекут дисквалификацию CDL на 60 days в Массачусетсе?","options":["1","2","3","4"],"explanation":"Второе серьёзное нарушение ПДД в течение 3-летнего периода влечёт дисквалификацию на 60 days; третье в течение 3 лет влечёт 120 days. Одно серьёзное нарушение само по себе не влечёт дисквалификации. Источник: MA RMV CDL Manual; 49 CFR 383.51(c)."},"45":{"q":"В Массачусетсе ТРИ серьёзных нарушения ПДД (serious traffic violations), совершённых в течение 3-летнего периода, влекут дисквалификацию CDL на:","options":["60 days","90 days","120 days","180 days"],"explanation":"Третье серьёзное нарушение ПДД в течение 3-летнего периода влечёт дисквалификацию на 120 days (второе в течение 3 лет — это 60 days). Источник: MA RMV CDL Manual; 49 CFR 383.51(c)."},"46":{"q":"Что из перечисленного классифицируется как СЕРЬЁЗНОЕ нарушение ПДД (serious traffic violation) для водителя CDL в Массачусетсе?","options":["Управление CMV с BAC 0.04 или более","Отказ от теста на алкоголь","Превышение разрешённой скорости на 15 mph или более","Управление CMV при приостановленном CDL"],"explanation":"Превышение скорости на 15 mph или более является серьёзным нарушением ПДД (serious traffic violation). Управление с BAC 0.04+, отказ от теста и управление при приостановленном CDL — это всё серьёзные правонарушения (MAJOR offenses), а не серьёзные нарушения ПДД. Источник: MA RMV CDL Manual; 49 CFR 383.51(c)."},"47":{"q":"Согласно правилам CDL Массачусетса, нарушение закона, запрещающего НАБОР ТЕКСТОВЫХ СООБЩЕНИЙ (texting) при управлении CMV, относится к категории:","options":["Серьёзное правонарушение (major offense)","Серьёзное нарушение ПДД (serious traffic violation)","Нарушение приказа о выводе из эксплуатации (out-of-service order)","Нарушение на железнодорожном переезде"],"explanation":"Набор текстовых сообщений при управлении CMV является серьёзным нарушением ПДД (serious traffic violation); накопление двух в течение 3 лет влечёт дисквалификацию на 60 days, трёх в течение 3 лет — на 120 days. Источник: MA RMV CDL Manual; 49 CFR 383.51(c); M.G.L. c. 90 sec. 13B."},"48":{"q":"Использование РУЧНОГО мобильного телефона при управлении CMV для целей дисквалификации CDL в Массачусетсе рассматривается как:","options":["Серьёзное нарушение ПДД (serious traffic violation)","Серьёзное правонарушение (major offense)","Нарушение вывода из эксплуатации (out-of-service)","Не является нарушением, влекущим дисквалификацию"],"explanation":"Использование ручного телефона при управлении CMV является серьёзным нарушением ПДД (serious traffic violation), которое учитывается при достижении порогов «2 за 3 года» (60 days) и «3 за 3 года» (120 days) для дисквалификации. Источник: MA RMV CDL Manual; 49 CFR 383.51(c); M.G.L. c. 90 sec. 13B."},"49":{"q":"Согласно закону Массачусетса о вождении без рук (Hands-Free Law, M.G.L. c. 90 sec. 13B), штраф за ПЕРВОЕ нарушение с использованием ручного устройства составляет:","options":["$35","$100","$250","$500"],"explanation":"Закон Массачусетса о вождении без рук (Hands-Free Law) устанавливает штрафы в размере $100 за первое нарушение, $250 за второе и $500 за третье или последующее нарушение, с обязательной программой по борьбе с отвлечённым вождением для повторных нарушителей. Источник: M.G.L. c. 90 sec. 13B."},"50":{"q":"Согласно закону Массачусетса о вождении без рук (Hands-Free Law), штраф за ТРЕТЬЕ или последующее нарушение с использованием ручного устройства составляет:","options":["$100","$250","$500","$1,000"],"explanation":"Штрафы возрастают до $500 за третье или последующее нарушение ($100 за первое, $250 за второе). Второе или последующее нарушение также требует прохождения программы по борьбе с отвлечённым вождением. Источник: M.G.L. c. 90 sec. 13B."},"51":{"q":"Каков срок дисквалификации за ПЕРВОЕ нарушение на железнодорожно-автодорожном переезде водителем CDL в Массачусетсе?","options":["Не менее 30 days","Не менее 60 days","Не менее 120 days","Не менее 1 year"],"explanation":"Первое нарушение на железнодорожно-автодорожном переезде влечёт дисквалификацию не менее чем на 60 days. Источник: MA RMV CDL Manual; 49 CFR 383.51(d)."},"52":{"q":"Для водителя CDL в Массачусетсе ВТОРОЕ нарушение на железнодорожно-автодорожном переезде в течение 3-летнего периода влечёт дисквалификацию на:","options":["Не менее 60 days","Не менее 120 days","Не менее 1 year","Не менее 3 years"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 лет влечёт дисквалификацию не менее чем на 120 days (первое — 60 days, третье в течение 3 лет — не менее 1 year). Источник: MA RMV CDL Manual; 49 CFR 383.51(d)."},"53":{"q":"ТРЕТЬЕ нарушение на железнодорожно-автодорожном переезде в течение 3-летнего периода дисквалифицирует водителя CDL в Массачусетсе на:","options":["Не менее 120 days","Не менее 180 days","Не менее 1 year","Пожизненно"],"explanation":"Три нарушения на железнодорожном переезде в течение 3-летнего периода влекут дисквалификацию не менее чем на 1 year. Источник: MA RMV CDL Manual; 49 CFR 383.51(d)."},"54":{"q":"В Массачусетсе ПЕРВОЕ осуждение за нарушение приказа о выводе водителя из эксплуатации (out-of-service, OOS) (без hazmat, без пассажиров) влечёт дисквалификацию на:","options":["Не менее 60 days","Не менее 90 days","Не менее 180 days, но не более 1 year","Не менее 1 year, но не более 5 years"],"explanation":"Первое нарушение приказа о выводе из эксплуатации влечёт дисквалификацию не менее чем на 180 days и не более чем на 1 year. Источник: MA RMV CDL Manual; 49 CFR 383.51(e)."},"55":{"q":"ВТОРОЕ нарушение приказа о выводе из эксплуатации (out-of-service) в течение 10-летнего периода дисквалифицирует водителя CDL в Массачусетсе на:","options":["Не менее 180 days, но не более 1 year","Не менее 2 years, но не более 5 years","Не менее 1 year, но не более 3 years","Пожизненно"],"explanation":"Второе нарушение приказа о выводе из эксплуатации в течение 10 лет влечёт дисквалификацию не менее чем на 2 years и не более чем на 5 years. Источник: MA RMV CDL Manual; 49 CFR 383.51(e)."},"56":{"q":"ПЕРВОЕ нарушение приказа о выводе из эксплуатации (out-of-service) при перевозке опасных грузов с табличками (placards) или управлении автомобилем, рассчитанным на 16+ пассажиров, влечёт дисквалификацию CDL в Массачусетсе на:","options":["Не менее 180 days, но не более 1 year","Не менее 180 days, но не более 2 years","Не менее 1 year, но не более 3 years","Не менее 3 years, но не более 5 years"],"explanation":"Первое нарушение о выводе из эксплуатации с участием опасных грузов с табличками или автомобиля на 16+ пассажиров влечёт усиленное наказание: не менее 180 days и не более 2 years. Источник: MA RMV CDL Manual; 49 CFR 383.51(e)."},"57":{"q":"Что из перечисленного считается СЕРЬЁЗНЫМ правонарушением (major offense), которое дисквалифицирует водителя CDL в Массачусетсе, даже если оно совершено в личном (некоммерческом) автомобиле водителя?","options":["Слишком близкое следование за впереди идущим транспортом","Неправильная смена полосы движения","Оставление места происшествия (ДТП)","Использование ручного телефона"],"explanation":"Оставление места происшествия (ДТП) является серьёзным правонарушением (major offense), дисквалифицирующим CDL, независимо от того, совершено ли оно в CMV или в личном автомобиле. Остальные являются серьёзными нарушениями ПДД (serious traffic violations) только при совершении за рулём CMV. Источник: MA RMV CDL Manual; 49 CFR 383.51(b)."},"58":{"q":"Водитель CDL в Массачусетсе, который использует любой автомобиль для совершения тяжкого преступления (felony), связанного с производством, распространением или сбытом контролируемого вещества, дисквалифицируется на:","options":["1 year","3 years","10 years","Пожизненно без права восстановления"],"explanation":"Использование автомобиля для совершения тяжкого преступления (felony), связанного с контролируемыми веществами (производство, распространение или сбыт), влечёт пожизненную дисквалификацию, которая НЕ подлежит восстановлению. Источник: MA RMV CDL Manual; M.G.L. c. 90F; 49 CFR 383.51(b)."},"59":{"q":"Согласно закону Массачусетса о железнодорожных переездах, школьный автобус или транспортное средство, перевозящее в качестве груза взрывчатые вещества или легковоспламеняющиеся жидкости, должно полностью остановиться в пределах какой зоны от ближайшего рельса?","options":["Не ближе 15 футов и не дальше 50 футов","Не ближе 10 футов и не дальше 40 футов","Не ближе 5 футов и не дальше 25 футов","Не ближе 20 футов и не дальше 75 футов"],"explanation":"Общие законы Массачусетса, гл. 90, ст. 15 требуют, чтобы школьный автобус или транспортное средство, перевозящее в качестве груза взрывчатые вещества или легковоспламеняющиеся жидкости, останавливалось не ближе 15 футов и не дальше 50 футов от ближайшего пути перед его пересечением. Источник: MGL c. 90, s. 15."},"60":{"q":"На каком статуте Массачусетса основан закон штата «Move Over» («Уступи дорогу»), и каково основное требование при приближении к стоящему аварийному, ремонтному или эвакуационному транспортному средству с включёнными проблесковыми маячками?","options":["MGL c. 89, s. 7C; перестроиться в несмежную полосу, если это возможно, или снизить скорость до безопасной и разумной, если перестроиться нельзя","MGL c. 90, s. 14; полностью остановиться, пока маячки не будут выключены","MGL c. 85, s. 2; подать звуковой сигнал и продолжать движение с установленной скоростью","MGL c. 90, s. 17; снизить скорость не более чем до 20 mph и не покидать свою полосу"],"explanation":"Закон Массачусетса «Move Over», MGL c. 89, s. 7C (вступил в силу в марте 2009 года), требует, чтобы водители, приближающиеся к стоящему аварийному, ремонтному или эвакуационному транспортному средству с включёнными проблесковыми маячками, перестраивались в несмежную полосу, когда это безопасно, а при невозможности — снижали скорость до безопасной и разумной. Источник: MGL c. 89, s. 7C; Mass.gov Move Over Law."},"61":{"q":"Каков размер штрафа в Массачусетсе за нарушение закона «Move Over» согласно MGL c. 89, s. 7C?","options":["$100","$35","$250","$500"],"explanation":"Нарушение закона Массачусетса «Move Over» (MGL c. 89, s. 7C) влечёт штраф в размере $100. Источник: MGL c. 89, s. 7C; страница закона «Move Over» полиции штата Массачусетс."},"62":{"q":"В каком случае в Массачусетсе водитель, приближающийся к остановившемуся школьному автобусу с мигающими красными огнями, НЕ обязан останавливаться?","options":["При приближении со встречного направления по разделённой автомагистрали","Когда водитель движется со скоростью менее 20 mph","Когда водитель находится более чем в двух длинах автомобиля позади автобуса","Когда автобус остановился в пределах делового района"],"explanation":"Согласно MGL c. 90, s. 14, каждый водитель должен остановиться, не доезжая до школьного автобуса с мигающими красными огнями, за исключением случаев приближения со встречного направления по разделённой автомагистрали. Источник: MGL c. 90, s. 14."},"63":{"q":"Каков минимальный штраф в Массачусетсе за первое нарушение в виде непредоставления остановки или незаконного объезда остановившегося школьного автобуса с мигающими красными огнями?","options":["$250","$100","$50","$500"],"explanation":"Согласно MGL c. 90, s. 14, первое нарушение закона об остановке у школьного автобуса влечёт штраф не менее $250; второе нарушение — от $500 до $1,000 с приостановлением действия прав на 6 месяцев. Источник: MGL c. 90, s. 14."},"64":{"q":"На ровной, прямой, разделённой автомагистрали, где водитель с CDL должен разместить три аварийных световозвращающих треугольника после остановки на обочине?","options":["В пределах 10 футов от задней части, примерно в 100 футах позади и примерно в 200 футах позади","В пределах 25 футов, примерно в 75 футах и примерно в 150 футах позади","В пределах 5 футов, примерно в 50 футах и примерно в 100 футах позади","В пределах 15 футов, примерно в 150 футах и примерно в 300 футах позади"],"explanation":"Руководство по CDL Массачусетса (принимающее 49 CFR 392.22) предписывает размещать один треугольник в пределах 10 футов от задней части транспортного средства, один примерно в 100 футах позади и один примерно в 200 футах позади на разделённой дороге или дороге с односторонним движением. Источник: Massachusetts CDL Manual, Driving Safely (49 CFR 392.22)."},"65":{"q":"Если коммерческое транспортное средство остановилось в пределах 500 футов от холма, поворота или иного препятствия, ограничивающего видимость, как водитель с CDL должен скорректировать расстановку аварийных треугольников?","options":["Отодвинуть самый дальний треугольник назад так, чтобы он находился в 100–500 футах от транспортного средства, в сторону препятствия, чтобы дать приближающимся водителям больше предупреждения","Убрать все треугольники и полагаться только на аварийную сигнализацию","Разместить все три треугольника в пределах 50 футов от транспортного средства, чтобы они оставались вместе","Разместить только один треугольник прямо позади транспортного средства, не дальше 10 футов"],"explanation":"Согласно Руководству по CDL Массачусетса (49 CFR 392.22), если транспортное средство остановилось в пределах 500 футов от поворота, вершины холма или иного препятствия, предупреждающее устройство в сторону препятствия следует размещать в 100–500 футах от транспортного средства, чтобы дать приближающемуся транспорту достаточное предупреждение. Источник: Massachusetts CDL Manual; 49 CFR 392.22."},"66":{"q":"На платной автомагистрали Massachusetts Turnpike (I-90) между развязкой 14 в Уэстоне и развязкой 9 в Стербридже какие полосы движения может использовать тяжёлое коммерческое транспортное средство (кроме автобуса)?","options":["Только крайнюю правую полосу или следующую смежную полосу при обгоне и опережении","Любую полосу, без ограничений по полосам для грузовиков на этой платной автомагистрали","Только крайнюю левую полосу, чтобы не мешать более медленному транспорту","Только две крайние левые полосы в светлое время суток"],"explanation":"700 CMR 7.09 ограничивает тяжёлое коммерческое транспортное средство (кроме автобуса) между развязкой 14 (Уэстон) и развязкой 9 (Стербридж) крайней правой полосой движения или следующей смежной полосой только при обгоне и опережении, за исключением аварийных ситуаций. Источник: 700 CMR 7.09."},"67":{"q":"Почему фургонам, грузовикам для переездов и другим коммерческим транспортным средствам запрещён проезд по Storrow Drive и Soldiers Field Road в Бостоне (причина так называемого «Storrowing»)?","options":["Это парковые дороги DCR «только для легковых автомобилей» с низкими путепроводами (около 10 футов или меньше), и грузовики/автобусы там запрещены","На них взимается плата, которая принимается только коммерческими транспондерами","Они зарезервированы для транспортных средств с высокой заполняемостью в часы пик","На них установлено ограничение скорости для грузовиков, слишком низкое для междугородних грузоперевозок"],"explanation":"Storrow Drive и Soldiers Field Road — это парковые дороги Департамента охраны природы и отдыха (DCR), предназначенные только для легковых автомобилей («только для легковых»), с низкими габаритами мостов около 10 футов или меньше; грузовики, автобусы и подобные транспортные средства там запрещены, и негабаритные по высоте грузовики регулярно врезаются в путепроводы. Источник: 302 CMR 11.00; кампания Mass.gov / DCR Storrowing."},"68":{"q":"За пределами густонаселённого или делового района на неразделённой автомагистрали Массачусетса без установленного ограничения скорости какова законодательно установленная скорость, выше которой вы считаетесь превышающим скорость?","options":["40 mph","30 mph","50 mph","55 mph"],"explanation":"Согласно MGL c. 90, s. 17, на неразделённой дороге за пределами густонаселённого или делового района без установленного ограничения превышение 40 mph на протяжении не менее четверти мили является prima facie доказательством превышения скорости (для разделённой автомагистрали этот показатель составляет 50 mph). Источник: MGL c. 90, s. 17."},"69":{"q":"В пределах густонаселённого или делового района Массачусетса каково законодательно установленное ограничение скорости там, где оно не указано знаками?","options":["30 mph","25 mph","20 mph","35 mph"],"explanation":"Согласно MGL c. 90, s. 17, законодательно установленная скорость в густонаселённом или деловом районе, где не указано специальное ограничение, составляет 30 mph (густонаселённым районом считается территория, где жилые дома расположены в среднем менее чем в 200 футах друг от друга). Источник: MGL c. 90, s. 17."},"70":{"q":"В Массачусетсе водитель школьного автобуса, останавливающийся на железнодорожном переезде, должен сделать что из перечисленного в дополнение к остановке в зоне 15–50 футов?","options":["Открыть рабочую дверь, убедиться, что пересечение безопасно, затем закрыть дверь перед продолжением движения","Подать звуковой сигнал три раза перед пересечением","Выставить световозвращающие треугольники с каждой стороны путей","Включить максимально доступную передачу перед пересечением"],"explanation":"Согласно MGL c. 90, s. 15, водитель школьного автобуса должен остановиться в пределах 15–50 футов от ближайшего рельса, открыть рабочую дверь, убедиться, что пересечение безопасно, и затем закрыть дверь перед продолжением движения. Источник: MGL c. 90, s. 15."},"71":{"q":"Согласно Руководству по CDL Массачусетса, как водитель должен поступать с передачами при движении коммерческого транспортного средства через железнодорожные пути?","options":["Пересекать на достаточно низкой передаче, чтобы можно было полностью преодолеть пути без переключения","Переключаться на повышенные передачи, находясь на путях, чтобы быстрее их преодолеть","Перейти на нейтраль и преодолеть пути накатом","Понизить передачу в середине переезда, чтобы снизить скорость"],"explanation":"Руководство по CDL Массачусетса предписывает водителям выбирать передачу, которая позволит транспортному средству полностью преодолеть пути без переключения, и не менять передачи, находясь на путях. Источник: Massachusetts CDL Manual, Railroad Crossings (49 CFR 392.10)."},"72":{"q":"Какова максимальная полная масса транспортного средства, с которой грузовик может эксплуатироваться в Массачусетсе на федеральной системе автомагистралей без разрешения на превышение массы?","options":["80,000 фунтов","73,280 фунтов","99,000 фунтов","100,000 фунтов"],"explanation":"Массачусетс следует федеральному ограничению в 80,000 фунтов полной массы транспортного средства без специального разрешения; грузы сверх этого требуют разрешения MassDOT на превышение массы. Источник: MassDOT Commercial Truck Permits; федеральные ограничения массы, применяемые в Массачусетсе."},"73":{"q":"Без разрешения на негабарит какова максимальная допустимая ширина транспортного средства/груза на автомагистралях Массачусетса?","options":["8 футов 6 дюймов (102 inches)","8 футов 0 дюймов (96 inches)","10 футов 0 дюймов (120 inches)","9 футов 0 дюймов (108 inches)"],"explanation":"Законная максимальная ширина в Массачусетсе без разрешения на негабарит составляет 8 футов 6 дюймов (102 inches); более широкие грузы требуют разрешения MassDOT на негабарит. Источник: правила MassDOT по негабариту/превышению массы; Mass.gov Commercial Truck Permits."},"74":{"q":"Без разрешения на негабарит какова максимальная допустимая высота транспортного средства с грузом на автомагистралях Массачусетса?","options":["13 футов 6 дюймов","13 футов 0 дюймов","14 футов 0 дюймов","12 футов 6 дюймов"],"explanation":"Массачусетс устанавливает законную максимальную высоту в 13 футов 6 дюймов; более высокие грузы требуют разрешения MassDOT на негабарит и могут потребовать обследования маршрута. Источник: правила MassDOT по негабариту/превышению массы; Mass.gov Commercial Truck Permits."},"75":{"q":"На платной автомагистрали Massachusetts Turnpike как ограничение по полосам для тяжёлых коммерческих транспортных средств между Уэстоном и Стербриджем относится к автобусам?","options":["Автобусы освобождены от этого ограничения «только правая полоса»","Автобусы всегда должны держаться левой полосы","Автобусам полностью запрещён проезд по этому участку","Автобусы должны двигаться только в ночное время"],"explanation":"Согласно 700 CMR 7.09, ограничение «только правая полоса» между развязкой 14 (Уэстон) и развязкой 9 (Стербридж) применяется к тяжёлым коммерческим транспортным средствам «кроме автобуса», поэтому автобусы освобождены от этого конкретного ограничения. Источник: 700 CMR 7.09."},"76":{"q":"Согласно законодательству Массачусетса, после того как водитель, обязанный остановиться у школьного автобуса, остановился, когда этот водитель может продолжить движение?","options":["Когда мигающие красные предупреждающие сигналы автобуса будут выключены, если иное не предписано сотрудником полиции","После ожидания фиксированных 10 секунд независимо от сигналов","Как только начнут мигать жёлтые (янтарные) огни автобуса","Немедленно, при условии, что не видно детей"],"explanation":"MGL c. 90, s. 14 требует, чтобы остановившийся водитель оставался на месте, пока мигающие красные сигналы школьного автобуса не будут выключены, если только сотрудник полиции не даст указание продолжить движение. Источник: MGL c. 90, s. 14."},"77":{"q":"Согласно MGL c. 90, s. 14, на каком минимальном расстоянии транспортное средство может следовать за школьным автобусом на дороге общего пользования в Массачусетсе?","options":["Не ближе 100 футов","Не ближе 50 футов","Не ближе 200 футов","Не ближе 25 футов"],"explanation":"MGL c. 90, s. 14 запрещает управление транспортным средством на расстоянии менее 100 футов позади школьного автобуса (за исключением случаев обгона и опережения там, где это разрешено). Источник: MGL c. 90, s. 14."},"78":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) в Массачусетсе?","options":["Управление регистрации транспортных средств (RMV), входящее в состав MassDOT","Федеральное управление безопасности автоперевозчиков (FMCSA)","Департамент общественной безопасности Массачусетса","Отдел коммерческого транспорта полиции штата Массачусетс"],"explanation":"В Массачусетсе CDL выдаются Управлением регистрации транспортных средств (RMV), подразделением Департамента транспорта Массачусетса (MassDOT). FMCSA устанавливает федеральные стандарты, но не выдаёт удостоверение. Источник: страницы Mass.gov RMV о коммерческих водительских удостоверениях (CDL)."},"79":{"q":"Прежде чем вы сможете сдать любой экзамен по практическим навыкам (вождению) для CDL в Массачусетсе, вы должны сначала получить какой документ?","options":["Коммерческое ученическое разрешение (CLP)","Полноценное CDL класса A","Федеральное разрешение на междуштатные перевозки (номер MC)","Сертификат на перевозку опасных материалов"],"explanation":"Чтобы управлять коммерческим транспортным средством для практики и претендовать на сдачу экзамена по навыкам, заявитель в Массачусетсе должен сначала сдать теоретический экзамен(ы) и получить коммерческое ученическое разрешение (CLP). Источник: страницы Mass.gov RMV о CDL; 49 CFR 383."},"80":{"q":"Сколько времени держатель CLP в Массачусетсе должен ждать после выдачи CLP, прежде чем он сможет сдавать экзамен по навыкам для CDL?","options":["Не менее 14 days","Не менее 24 hours","Не менее 30 days","Не менее 60 days"],"explanation":"CLP должно быть на руках не менее 14 days, прежде чем заявитель сможет сдать экзамен по навыкам для CDL. Это федеральное требование (49 CFR 383.37), которое применяет Массачусетс. Источник: страницы Mass.gov RMV о CDL; 49 CFR 383.37."},"81":{"q":"Сколько времени действует коммерческое ученическое разрешение (CLP) в Массачусетсе?","options":["180 days, с возможностью однократного продления ещё на 180 days","30 days, без возможности продления","1 год, с возможностью двукратного продления","90 days, с возможностью однократного продления ещё на 90 days"],"explanation":"CLP в Массачусетсе действует 180 days и может быть однократно продлено ещё на 180 days без повторной сдачи теоретических экзаменов; после этого заявитель должен подать заявление заново. Источник: страницы Mass.gov RMV о CDL; 49 CFR 383.25."},"82":{"q":"Из каких трёх частей состоит экзамен по навыкам для CDL в Массачусетсе?","options":["Предрейсовый осмотр, базовое управление транспортным средством и вождение на дороге","Письменный экзамен, проверка зрения и вождение на дороге","Проверка пневматических тормозов, обращение с опасными грузами и вождение на дороге","Сцепка/расцепка, проверка бортового журнала и вождение на дороге"],"explanation":"Экзамен по навыкам для CDL в Массачусетсе состоит из трёх частей: предрейсовый осмотр (транспортного средства), базовое управление транспортным средством (навыки управления, такие как движение задним ходом) и экзамен по вождению на дороге. Источник: Mass.gov RMV CDL Skills Test Information Sheet / Modernized CDL Skills Exam Standard."},"83":{"q":"Из скольких категорий самосертификации должен выбрать заявитель на CDL/CLP в Массачусетсе при удостоверении типа вождения, которое он осуществляет?","options":["Четырёх","Двух","Трёх","Пяти"],"explanation":"Федеральные правила и правила Массачусетса требуют, чтобы водитель прошёл самосертификацию в одну из четырёх категорий коммерческой деятельности. Источник: Mass.gov «Commercial Driver's License (CDL) Self-Certification»; 49 CFR 383.71."},"84":{"q":"Какое из перечисленного является одной из четырёх категорий самосертификации CDL, используемых в Массачусетсе?","options":["Non-Excepted Interstate (NI)","Restricted Commercial (RC)","Federal Excepted Operator (FEO)","Limited Intrastate Hauler (LIH)"],"explanation":"Четыре категории — это Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) и Excepted Intrastate (EA). Остальные варианты не являются реальными категориями. Источник: Mass.gov CDL Self-Certification; 49 CFR 383.71."},"85":{"q":"Согласно правилам Массачусетса/FMCSA, водитель, который проходит самосертификацию как «Non-Excepted Interstate (NI)», делает какое заявление о своей деятельности?","options":["Он осуществляет перевозки через границы штатов и должен соответствовать требованиям к федеральной медицинской справке DOT","Он осуществляет перевозки только в пределах Массачусетса и не нуждается в медицинской справке","Он осуществляет перевозки через границы штатов, но освобождён от медицинских требований","Он осуществляет перевозки только в пределах Массачусетса и соответствует только медицинским правилам штата"],"explanation":"Non-Excepted Interstate (NI) означает, что водитель осуществляет (или предполагает осуществлять) межштатные перевозки и обязан соответствовать требованиям к справке федерального медицинского эксперта DOT. Источник: Mass.gov CDL Self-Certification; 49 CFR 383.71/391."},"86":{"q":"Водитель, который проходит самосертификацию как «Excepted Intrastate (EA)» в Массачусетсе, указывает на что из перечисленного?","options":["Он осуществляет перевозки только в пределах Массачусетса и не обязан соответствовать требованиям к федеральной медицинской справке DOT","Он осуществляет перевозки через границы штатов и должен иметь федеральную медицинскую справку","Он осуществляет перевозки только в пределах Массачусетса и должен иметь федеральную медицинскую справку DOT","Он ограничен только перевозкой опасных материалов"],"explanation":"Excepted Intrastate (EA) означает, что водитель осуществляет перевозки только во внутриштатной (в пределах штата) коммерческой деятельности и освобождён от требований к федеральной медицинской справке DOT. Источник: Mass.gov CDL Self-Certification; 49 CFR 383.71."},"87":{"q":"Когда водитель CDL в Массачусетсе, осуществляющий межштатные перевозки без исключений, проходит медосмотр DOT, какой документ выдаёт сертифицированный медицинский эксперт?","options":["Справку медицинского эксперта (Form MCSA-5876)","Освобождение по зрению для класса D от RMV Массачусетса","Письмо о федеральном освобождении от требований по часам работы (Hours-of-Service)","Сертификат операционного разрешения FMCSA"],"explanation":"Эксперт из Национального реестра FMCSA, признавший водителя годным, выдаёт справку медицинского эксперта (Form MCSA-5876). Источник: Mass.gov CDL Self-Certification / Medical Certification; FMCSA National Registry."},"88":{"q":"Медицинский эксперт в Массачусетсе, проводящий медосмотры DOT для целей CDL, должен быть внесён в какой список?","options":["В Национальный реестр сертифицированных медицинских экспертов FMCSA (FMCSA National Registry of Certified Medical Examiners)","В реестр одобренных врачей RMV Массачусетса","В список CDL Совета по регистрации в медицине Массачусетса","В список поставщиков услуг отдела автомагистралей MassDOT"],"explanation":"Медосмотры DOT для целей CDL должны проводиться медицинским экспертом, внесённым в Национальный реестр сертифицированных медицинских экспертов FMCSA. Источник: Mass.gov CDL Self-Certification; FMCSA National Registry."},"89":{"q":"По состоянию на середину 2025 года, как информация о медицинской сертификации для большинства водителей CDL в Массачусетсе поступает в RMV?","options":["Электронно из Национального реестра FMCSA, поэтому бумажную справку обычно подавать не требуется","Только путём отправки водителем бумажной справки в RMV по почте в течение 5 дней","Только путём отправки работодателем справки в MassDOT по факсу","Автоматически от страховой компании водителя"],"explanation":"Начиная с 23 июня 2025 года RMV получает информацию о медицинской сертификации электронно из Национального реестра FMCSA, поэтому большинству водителей не нужно подавать бумажную копию (водители, осуществляющие только внутриштатные перевозки, могут всё же подать её, если она не была загружена). Источник: Mass.gov CDL Self-Certification."},"90":{"q":"Какое обучение должен пройти впервые подающий заявление на класс A или класс B заявитель в Массачусетсе, прежде чем RMV назначит экзамен по навыкам для CDL?","options":["Обучение водителей начального уровня (ELDT) у поставщика, зарегистрированного в FMCSA","40-часовой курс защитного вождения MassDOT","Государственную стажировку в сервисном центре RMV","Только инструктаж по безопасности на дороге, проводимый работодателем"],"explanation":"С 7 февраля 2022 года впервые подающие заявление на класс A/B (и впервые на эндорсменты S, P или H) должны пройти обучение водителей начального уровня (ELDT) у поставщика, внесённого в Реестр поставщиков обучения FMCSA, прежде чем RMV назначит экзамен по навыкам. Источник: руководство Mass.gov ELDT; 49 CFR Part 380 Subpart F."},"91":{"q":"Обучение водителей начального уровня (ELDT), требуемое перед экзаменом по навыкам для CDL в Массачусетсе, состоит из каких двух компонентов?","options":["Теоретического обучения и практического обучения за рулём","Письменного экзамена и проверки зрения","Только аудиторного обучения и федеральной проверки благонадёжности","Медицинского осмотра и проверки на наркотики"],"explanation":"ELDT требует успешного завершения предписанной программы теоретического и практического обучения за рулём перед сдачей экзамена по навыкам для CDL. Источник: руководство Mass.gov ELDT; FMCSA 49 CFR Part 380 Subpart F."},"92":{"q":"Помимо впервые подающих заявление на класс A/B, ELDT также должно быть пройдено перед подачей заявления на какой эндорсмент впервые?","options":["Опасные материалы (H), пассажирский (P) или школьный автобус (S)","Только цистерна (N)","Только сдвоенные/строенные прицепы (T)","Пневматические тормоза (без ограничения)"],"explanation":"ELDT применяется к впервые получаемым CDL класса A/B, повышению с класса B до A и впервые получаемым эндорсментам на опасные материалы (H), пассажирский (P) и школьный автобус (S). Источник: руководство Mass.gov ELDT; 49 CFR Part 380."},"93":{"q":"Сколько времени действует CDL в Массачусетсе, прежде чем его необходимо продлить?","options":["5 лет","2 года","8 лет","10 лет"],"explanation":"CDL в Массачусетсе действует 5 лет и обычно истекает в день рождения держателя. Источник: страницы Mass.gov RMV о продлении удостоверения."},"94":{"q":"Каков минимальный возраст для получения CDL только для внутриштатных перевозок (только в пределах Массачусетса) и минимальный возраст для межштатных перевозок?","options":["18 для внутриштатных и 21 для межштатных","16 для внутриштатных и 18 для межштатных","18 как для внутриштатных, так и для межштатных","21 как для внутриштатных, так и для межштатных"],"explanation":"Заявитель должен быть не моложе 18 лет для получения CDL/CLP для внутриштатных перевозок (в пределах Массачусетса) и не моложе 21 года для осуществления межштатных перевозок. Источник: страницы Mass.gov RMV о CDL; 49 CFR 383.3/391.11."},"95":{"q":"При подаче заявления на CLP/CDL в Массачусетсе какой набор документов заявитель обычно должен предоставить?","options":["Подтверждение личности/законного пребывания, номер социального страхования (Social Security number) и подтверждение проживания в Массачусетсе","Только действующий паспорт и регистрацию транспортного средства","Только письмо от работодателя и право собственности на транспортное средство","Свидетельство о рождении и кредитный отчёт"],"explanation":"Заявители на CDL в Массачусетсе должны подтвердить личность/законное пребывание, предоставить номер социального страхования (Social Security number) и подтвердить проживание в Массачусетсе — те же стандарты удостоверения личности, что используются для других документов RMV. Источник: требования Mass.gov RMV к CDL и удостоверению личности."},"96":{"q":"Какой проходной балл требуется на письменном тесте на общие знания для CDL в Массачусетсе?","options":["Не менее 80% правильных ответов","Не менее 60% правильных ответов","Не менее 70% правильных ответов","Идеальные 100% правильных ответов"],"explanation":"Тесты на знания для CDL в Массачусетсе, включая тест на общие знания, требуют проходного балла не менее 80% правильных ответов. Источник: Massachusetts CDL Manual; страницы Mass.gov RMV о тестировании для CDL."}},"tr":{"0":{"q":"Massachusetts yollarinda, aynalar, sinyaller ve belirli guvenlik cihazlari haric, bir ticari motorlu tasitin izin verilen azami genisligi nedir?","options":["96 inc (8 fit)","102 inc (8 fit 6 inc)","108 inc (9 fit)","120 inc (10 fit)"],"explanation":"Massachusetts, aynalar, sinyaller ve belirli guvenlik cihazlari haric, tasit genisligini 102 inc (8 fit 6 inc) ile sinirlandirir. Kaynak: MGL Chapter 90, Section 19; Massachusetts RMV CDL Manual."},"1":{"q":"Massachusetts otoyollarinda, izin belgesi olmadan bir tasitin ve yukunun izin verilen azami yuksekligi nedir?","options":["13 fit","13 fit 6 inc","14 fit","14 fit 6 inc"],"explanation":"Massachusetts, tasit ve yuk icin azami yuksekligi 13 fit 6 inc olarak belirler. 10 fitten daha yuksek tasitlar yuksekliklerini gostermek zorundadir. Kaynak: MGL Chapter 90, Section 19; MassDOT ticari kamyon yukseklik sinirlari."},"2":{"q":"Ozel bir izin belgesi olmadan, Massachusetts'te bir cekici-yari romork kombinasyonundaki yari romorkun azami uzunlugu nedir?","options":["48 fit","53 fit","57 fit","60 fit"],"explanation":"Massachusetts'te bir cekici-yari romork biriminde yari romork 53 fit uzunluga kadar olabilir. Kaynak: MGL Chapter 90, Section 19; Massachusetts RMV CDL Manual."},"3":{"q":"Massachusetts yollarinda, izin belgesi olmadan, uc veya daha fazla akslı bir tasit icin izin verilen azami brut tasit agirligi nedir?","options":["73,280 pound","80,000 pound","88,000 pound","99,000 pound"],"explanation":"Massachusetts, uc veya daha fazla akslı tasitlar icin brut tasit agirligini, federal eyaletler arasi azami sinira uygun olarak 80,000 pound ile sinirlandirir. Kaynak: MGL Chapter 90, Section 19A."},"4":{"q":"Massachusetts'in, asiri agirlik izni olmadan tek bir aks uzerinde izin verdigi azami agirlik nedir?","options":["18,000 pound","20,000 pound","22,400 pound","24,000 pound"],"explanation":"Massachusetts, tek bir aks uzerinde 22,400 pound'a kadar izin verir; bu, 20,000 pound'luk federal eyaletler arasi sinirdan daha yuksektir. Kaynak: MGL Chapter 90, Section 19A."},"5":{"q":"Massachusetts'in, asiri agirlik izni olmadan bir tandem aks (iki aks) uzerinde izin verdigi azami agirlik nedir?","options":["32,000 pound","34,000 pound","36,000 pound","40,000 pound"],"explanation":"Massachusetts, federal standartla uyumlu olarak tandem aks sinirini 34,000 pound olarak belirler. Kaynak: MGL Chapter 90, Section 19A."},"6":{"q":"Massachusetts'te, bir duz (tek birim) kamyonda yukseklik isaretlerinin tasit uzerinde gosterilmesi gerekmeden once izin verilen azami yukseklik nedir?","options":["8 fit","10 fit","12 fit","13 fit 6 inc"],"explanation":"Massachusetts, yasal azami yukseklik 13 fit 6 inc olmasina ragmen, 10 fitten daha yuksek tasitlarin yuksekliklerini isaretlerle gostermesini gerektirir. Kaynak: MGL Chapter 90, Section 19."},"7":{"q":"Eyalet otoyollarinda seyahat icin asiri boyut ve asiri agirlik izinlerini hangi Massachusetts kurumu duzenler?","options":["Motorlu Tasitlar Sicil Dairesi (RMV)","MassDOT Highway Division (Karayollari Bolumu)","Massachusetts Eyalet Polisi","Federal Motorlu Tasiyici Guvenlik Idaresi"],"explanation":"Eyalet otoyollari icin asiri boyut/asiri agirlik izinleri, MassDOT Highway Division tarafindan Truck Permit Office (Kamyon Izin Ofisi) araciligiyla duzenlenir. Kaynak: Mass.gov Ticari Kamyon Izinleri; MassDOT."},"8":{"q":"Ticari asiri boyut/asiri agirlik kamyon izinleri ve rota talep etmek icin kullanilan MassDOT cevrimici sisteminin adi nedir?","options":["ATLAS","OASIS","PRISM","UCR"],"explanation":"MassDOT'un web tabanli Asiri Boyut/Asiri Agirlik Izin ve Rota Uygulamasinin adi OASIS'tir ve ticari kamyon izinlerine basvurmak icin kullanilir. Kaynak: MassDOT Highway Division; Mass.gov."},"9":{"q":"Bir tasitin MassDOT asiri boyut/asiri agirlik izni almasi ne zaman gereklidir?","options":["Yalnizca bir eyalet sinirini gectiginde","Genislik, yukseklik, uzunluk veya agirlik icin yasal sinirlari astigi her durumda","Yalnizca tehlikeli madde tasidiginda","Yalnizca gece seyahat ettiginde"],"explanation":"Bir tasit veya yuk, genislik (102 inc), yukseklik (13'6\"), uzunluk veya agirlik (80,000 lb) icin yasal sinirlari her astiginda izin gereklidir. Kaynak: MGL Chapter 90, Section 19/19A; MassDOT."},"10":{"q":"Massachusetts, iki veya daha fazla ardisik aks grubu uzerindeki agirliga federal Kopru Formulunu uygular. W = 500[LN/(N-1) + 12N + 36] formulunde kullanilan sabit carpan nedir?","options":["100","250","500","1,000"],"explanation":"Massachusetts'te benimsenen federal Kopru Formulu 500 sabitini kullanir: W = 500[LN/(N-1) + 12N + 36]; burada L aks acikligi ve N aks sayisidir. Kaynak: MGL Chapter 90, Section 19A; FHWA Bridge Formula."},"11":{"q":"Massachusetts'te kullanilan federal Kopru Formulunde 'L' degiskeni neyi temsil eder?","options":["Yasal yuk agirligini pound cinsinden","Grubun en uctaki (dis) akslari arasindaki mesafeyi fit cinsinden","Otoyolun serit genisligini","Romorkun uzunlugunu fit cinsinden"],"explanation":"W = 500[LN/(N-1) + 12N + 36] formulunde 'L', iki veya daha fazla ardisik aks grubunun en uctaki akslari arasindaki fit cinsinden mesafedir. Kaynak: MGL Chapter 90, Section 19A; FHWA Bridge Formula."},"12":{"q":"Massachusetts'in, izin belgesi olmadan yalnizca iki akslı bir tasitta izin verdigi azami brut agirlik nedir?","options":["34,000 pound","40,000 pound","46,000 pound","54,000 pound"],"explanation":"Massachusetts'te iki akslı bir tasit 46,000 pound brut ile sinirlidir; uc veya daha fazla akslı tasitlar ise 80,000 pound'a ulasabilir. Kaynak: MGL Chapter 90, Section 19A."},"13":{"q":"Massachusetts'te, iki tekli aks birbirinden 6 fitten daha az aralikla yerlestirilmisse, bu tur her aks uzerinde izin verilen azami agirlik nedir?","options":["16,000 pound","18,000 pound","20,000 pound","22,400 pound"],"explanation":"Aksler birbirinden 6 fitten daha az aralikla yerlestirildiginde, tekli aks tahsisi her aks icin 22,400 pound'dan 18,000 pound'a duser. Kaynak: MGL Chapter 90, Section 19A."},"14":{"q":"Massachusetts'in Eyaletler Arasi (Interstate) otoyollardaki azami genislik ve yukseklik sinirlari, diger eyalet otoyollarindakilerle nasil kiyaslanir?","options":["Genislik ve yukseklik sinirlari her ikisinde de aynidir (102 inc genislik, 13'6\" yukseklik)","Eyaletler arasi yollar daha genis olan 8'6\"'ya izin verir ama diger yollar yalnizca 8'","Eyaletler arasi yollar 14 fit yukseklige izin verir ama diger yollar yalnizca 13'6\"","Diger eyalet yollari, Eyaletler arasi yollardan daha genis tasitlara izin verir"],"explanation":"102 inc genislik ve 13 fit 6 inc yukseklik sinirlari, Massachusetts'te hem Eyaletler Arasi/Ulusal Ag hem de diger eyalet otoyollarinda ayni sekilde uygulanir. Kaynak: MGL Chapter 90, Section 19; J.J. Keller MA boyut/agirlik ozeti."},"15":{"q":"Federal eyaletler arasi tekli aks siniriyla kiyaslandiginda, Massachusetts'in tekli aks tahsisi:","options":["Daha dusuktur (Massachusetts 18,000 lb'ye izin verir, federal 20,000 lb)","Aynidir (her ikisi de 20,000 lb)","Daha yuksektir (Massachusetts 22,400 lb'ye izin verir, federal 20,000 lb)","Eyalet yollarinda sinirsizdir"],"explanation":"Massachusetts, tek bir aks uzerinde 22,400 pound'a izin verir; bu, 20,000 pound'luk federal eyaletler arasi standarttan daha yuksektir. Kaynak: MGL Chapter 90, Section 19A."},"16":{"q":"Izin belgesi olmadan, Massachusetts'te bir duz (tek birim) kamyonun azami uzunlugu nedir?","options":["33 fit","40 fit","45 fit","53 fit"],"explanation":"Massachusetts'te bir duz kamyon (tek birim) 40 fit uzunluga kadar olabilir; bir kombinasyondaki yari romork ise 53 fite kadar olabilir. Kaynak: MGL Chapter 90, Section 19."},"17":{"q":"Bir tasiyici, bir Massachusetts eyalet otoyolunda 14 fit genisliginde bir yuk tasimasi gerekiyor. Tasiyici ne yapmalidir?","options":["Hicbir sey, cunku 14 fit yasal genislik siniri icindedir","Seyahatten once MassDOT Highway Division'dan asiri boyut izni almali","Yalnizca yerel polis departmanini bilgilendirmeli","Bir CDL onayi (endorsement) icin basvurmali"],"explanation":"14 fit genislikte yuk, 102 inc (8'6\") yasal genisligi astigi icin, seyahatten once MassDOT Highway Division'dan (OASIS araciligiyla) bir asiri boyut izni alinmalidir. Kaynak: MGL Chapter 90, Section 19; MassDOT."},"18":{"q":"Massachusetts yasasina gore, ikiz/tandem romorklu bir cekici (her romork yasal uzunlugunda iken) icin izin verilen azami toplam uzunluk nedir?","options":["Her romork 28 fite kadar olabilir; romorklar yasal oldugunda toplam kombinasyon uzunluk siniri yoktur","Romork uzunlugundan bagimsiz olarak sabit 65 fitlik toplam sinir","Sabit 53 fitlik toplam sinir","Ikiz romorklar Massachusetts'te yasaktir"],"explanation":"Bir cekici ikiz romork kombinasyonunda, her romork (tandem birim) 28 fite kadar olabilir ve romorklar yasal oldugunda toplam kombinasyon uzunluk siniri yoktur. Kaynak: MGL Chapter 90, Section 19; J.J. Keller MA boyut/agirlik ozeti."},"19":{"q":"Massachusetts'te, 10,000 lbs.'i asan bir romork CEKMEYEN, brut tasit agirlik derecesi (GVWR) 26,001 lbs. veya daha fazla olan tek bir tasiti kullanmak icin hangi CDL sinifi gereklidir?","options":["Sinif A","Sinif B","Sinif C","Sinif D"],"explanation":"Massachusetts, GVWR'si 26,001 lbs. veya daha fazla olan herhangi bir tek tasiti veya 10,000 lbs.'i asmayan bir romork ceken boyle bir tasiti (orn. kapali kasa kamyonlar, damperli kamyonlar, duz kamyonlar) kullanmak icin Sinif B CDL gerektirir. Kaynak: Mass.gov 'CDL classes and endorsements' ve Massachusetts CDL Manual (RMV)."},"20":{"q":"Bir Massachusetts surucusu, cekilen romorkun 10,000 lbs.'i astigi, 80,000 lbs. brut kombinasyon agirlik derecesine sahip bir cekici-romork kombinasyonu cekmek istiyor. Hangi CDL sinifi gereklidir?","options":["Sinif B","Sinif C","Sinif A","Sinif D"],"explanation":"Massachusetts'te, cekilen birim(ler)in 10,000 lbs. GVWR'yi astigi ve GCWR'si 26,001 lbs. veya daha fazla olan herhangi bir tasit kombinasyonu icin Sinif A CDL gereklidir. Kaynak: Mass.gov 'CDL classes and endorsements' ve Massachusetts CDL Manual (RMV)."},"21":{"q":"Massachusetts kurallarina gore, Sinif A veya B agirlik esiklerini karsilamayan ancak 16 veya daha fazla yolcu (surucu dahil) tasimak veya plakartli tehlikeli madde nakletmek icin tasarlanmis bir tasit hangi CDL sinifini gerektirir?","options":["Sinif C","Sinif A","Sinif B","Sinif M"],"explanation":"Massachusetts, Sinif A veya B olarak nitelendirilmeyen ancak 16 veya daha fazla kisi (surucu dahil) tasimak icin tasarlanmis ya da plakart gerektiren tehlikeli madde tasimak icin kullanilan bir tasit icin Sinif C CDL gerektirir. Kaynak: Mass.gov 'CDL classes and endorsements' ve Massachusetts CDL Manual (RMV)."},"22":{"q":"EYALET ICI (yalnizca Massachusetts) ticarete kisitli bir Massachusetts CDL'si veya Ticari Ogrenci Permisi (Commercial Learner's Permit) almak icin asgari yas nedir?","options":["16 yas","17 yas","18 yas","21 yas"],"explanation":"Massachusetts, eyalet ici (yalnizca Massachusetts) CDL/CLP icin basvuru sahiplerinin en az 18 yasinda olmasini gerektirir. Eyaletler arasi ticarette arac kullanmak 21 yasi gerektirir. Kaynak: Mass.gov 'Apply for a Commercial Learner's Permit (CLP)' (RMV)."},"23":{"q":"Bir Massachusetts CDL'si ile EYALETLER ARASI ticarette bir ticari motorlu tasiti kullanmak icin gereken asgari yas nedir?","options":["18 yas","19 yas","20 yas","21 yas"],"explanation":"Bir surucunun eyalet sinirlari otesinde (eyaletler arasi ticarette) bir CMV kullanabilmesi icin en az 21 yasinda olmasi gerekir. 18-20 yas arasi surucüler yalnizca eyalet ici (yalnizca Massachusetts) operasyonla sinirlidir. Kaynak: Mass.gov RMV CLP/CDL sayfalari, 49 CFR 391.11 ile uyumludur."},"24":{"q":"Buyuk bir otobus gibi, yolcu tasimak icin tasarlanmis bir tasiti kullanmak icin bir Massachusetts CDL'sinde hangi onay (endorsement) kodu gereklidir?","options":["Kod N","Kod P","Kod T","Kod H"],"explanation":"Massachusetts'te yolcu tasimak icin tasarlanmis bir tasiti (orn. otobusler) kullanmak icin Yolcu (P) onayi gereklidir. Bir bilgi testini ve temsili bir tasitta beceri testini gecmeyi gerektirir. Kaynak: Mass.gov 'CDL classes and endorsements' ve Massachusetts CDL Manual (RMV)."},"25":{"q":"Massachusetts'te plakart gerektiren miktarlarda tehlikeli madde tasimak icin hangi CDL onayi (endorsement) gereklidir?","options":["N (Tanker)","T (Ikiz/Uclu Romork)","H (Tehlikeli Maddeler)","S (Okul Otobusu)"],"explanation":"Plakart gerektiren miktarlarda tehlikeli madde tasimak icin H (Tehlikeli Maddeler) onayi gereklidir. Ilk kez basvuranlar icin bir bilgi testi, bir TSA guvenlik tehdidi degerlendirmesi ve ELDT teori egitimi gerektirir. Kaynak: Mass.gov 'CDL classes and endorsements' ve TSA HazMat onay programi."},"26":{"q":"Massachusetts'te cift veya uclu romork cekmek icin hangi onay (endorsement) gereklidir?","options":["T onayi","N onayi","X onayi","P onayi"],"explanation":"Birden fazla romork cekmek icin T (Ikiz/Uclu Romork) onayi gereklidir. Yalnizca bir bilgi testini gecerek elde edilir (ayri bir beceri testi yoktur). Kaynak: Mass.gov 'CDL classes and endorsements' ve Massachusetts CDL Manual (RMV)."},"27":{"q":"Bir Massachusetts CDL sahibinin, sivi veya gaz yuk tasiyan bir tank tasitini kullanmak icin hangi onaya (endorsement) ihtiyaci vardir?","options":["H onayi","T onayi","N onayi","S onayi"],"explanation":"Dokme halde sivi veya gaz tasimak icin tasarlanmis bir tank tasitini kullanmak icin N (Tank Tasiti) onayi gereklidir. Tank tasiti bilgi testini gecerek elde edilir. Kaynak: Mass.gov 'CDL classes and endorsements' ve Massachusetts CDL Manual (RMV)."},"28":{"q":"Massachusetts'te bir surucunun Okul Otobusu (S) onayini almadan once (on kosul olarak) zaten hangi onaya (endorsement) sahip olmasi gerekir?","options":["H (Tehlikeli Maddeler)","P (Yolcu)","N (Tank Tasiti)","T (Ikiz/Uclu Romork)"],"explanation":"Massachusetts, Okul Otobusu (S) onayini kazanmak icin on kosul olarak Yolcu (P) onayini gerektirir. Bir surucunun P ve S bilgi testlerini ve okul otobusu beceri testini gecmesi gerekir. Kaynak: Mass.gov 'CDL classes and endorsements' ve 'Apply for a school bus learner's permit' (RMV)."},"29":{"q":"Massachusetts RMV tarafindan uygulanan federal kurallara gore, bir basvuru sahibinin CDL beceri (yol) testine girmeye uygun olmadan once Ticari Ogrenci Permisini (CLP) ne kadar sure elinde tutmasi gerekir?","options":["En az 7 gun","En az 14 gun","En az 30 gun","En az 60 gun"],"explanation":"Massachusetts RMV tarafindan uygulanan federal duzenleme (49 CFR 383.25), basvuru sahibinin beceri testine girebilmesi icin CLP'nin en az 14 gun elde tutulmasini gerektirir. Sayac, permisin verildigi gun baslar. Kaynak: Mass.gov RMV CLP sayfasi ve FMCSA 49 CFR 383.25."},"30":{"q":"Bir Massachusetts Ticari Ogrenci Permisi (CLP), yenilenmesi veya beceri testinin tamamlanmasi gerekmeden once ne kadar sure gecerlidir?","options":["90 gun","180 gun","1 yil","2 yil"],"explanation":"Bir Massachusetts CLP'si 180 gun gecerlidir. Federal sinirlarla uyumlu olarak, genel bilgi testini tekrar yapmadan, ek 180 gun icin bir kez yenilenebilir. Kaynak: Mass.gov 'Apply for a Commercial Learner's Permit (CLP)' (RMV)."},"31":{"q":"Bir Massachusetts Ticari Ogrenci Permisi ile arac kullanirken, CLP sahibine su nitelikte bir kisinin eslik etmesi gerekir:","options":["Herhangi bir surucu belgesine sahip en az 25 yasinda biri","Uygun sinif ve onaylara sahip gecerli bir CDL'ye sahip, surucunun yaninda oturan biri","Yalnizca sertifikali bir surus egitmeni","En az 5 yil ticari surus deneyimine sahip biri"],"explanation":"Bir CLP sahibi, yalnizca uygun sinif ve onaylara sahip gecerli bir CDL'ye sahip, on koltukta surucunun yaninda oturan bir kisi eslik ettiginde bir CMV kullanabilir. Kaynak: Mass.gov RMV CLP sayfasi ve 49 CFR 383.25."},"32":{"q":"Bir basvuru sahibinin, bir CDL veya CLP icin uygunlugunu belgelemek amaciyla Massachusetts RMV'ye hangi belge kombinasyonunu sunmasi gerekir?","options":["Kimlik/yasal mevcudiyet kaniti, Sosyal Guvenlik numarasi ve Massachusetts ikametgah kaniti","Yalnizca bir Sosyal Guvenlik karti","Yalnizca gecerli bir pasaport","Bir lise diplomasi ve ikametgah kaniti"],"explanation":"Massachusetts RMV, bir CLP/CDL duzenlemek icin kimlik ve ABD'de yasal mevcudiyet kaniti, bir Sosyal Guvenlik numarasi ve Massachusetts ikametgah kaniti gerektirir. Kaynak: Mass.gov RMV CDL/CLP basvuru gereksinimleri ve 49 CFR 383.71."},"33":{"q":"Ilk kez alinacak bir Massachusetts Sinif A CDL beceri testinden once tamamlanmasi gereken Giris Seviyesi Surucu Egitimi (ELDT), su nitelikte bir saglayici tarafindan tamamlanmalidir:","options":["Yalnizca Massachusetts RMV tarafindan onaylanmis","FMCSA Egitim Saglayici Sicilinde (TPR) listelenmis","ABD Egitim Bakanligi tarafindan sertifikalandirilmis","Herhangi bir lisansli Massachusetts surus okulu"],"explanation":"ELDT, FMCSA Egitim Saglayici Sicilinde (TPR) listelenmis bir saglayici ile tamamlanmalidir. Yalnizca TPR'ye kayitli saglayicilar gerekli teori ve direksiyon basindaki egitimi verebilir. Kaynak: Mass.gov 'Entry-Level Driver Training (ELDT)' kilavuzu ve FMCSA TPR (49 CFR Part 380)."},"34":{"q":"Massachusetts'te ilk kez alinacak bir Tehlikeli Maddeler (H) onayi icin, ne tur bir ELDT'nin tamamlanmasi gerekir ve ne zaman?","options":["Yalnizca teori egitimi, bilgi testine girmeden once","Yalnizca direksiyon basinda egitim, beceri testinden once","Hem teori hem de direksiyon basinda, yol testinden once","H onayi icin ELDT gerekli degildir"],"explanation":"H onayi icin ELDT yalnizca teori egitiminden olusur ve Eyalet HazMat bilgi testine girmeden once tamamlanmalidir. H onayi icin ayri bir beceri testi yoktur. Kaynak: Mass.gov ELDT kilavuzu ve FMCSA TPR (49 CFR Part 380)."},"35":{"q":"Yalnizca Massachusetts icinde calisan ve eyalet tibbi yeterlilik gereksinimlerini karsilamasi gereken bir Massachusetts surucusu hangi kategori altinda kendini beyan etmelidir (self-certify)?","options":["Istisna Disi Eyaletler Arasi (NI)","Istisnali Eyaletler Arasi (EI)","Istisna Disi Eyalet Ici (NA)","Istisnali Eyalet Ici (EA)"],"explanation":"Istisna Disi Eyalet Ici (NA), yalnizca eyalet ici ticarette calisan, Massachusetts tibbi/surucu yeterlilik standartlarini karsilamasi ve bir tibbi muayene sertifikasi bulundurmasi gereken surucüler icin gecerlidir. Kaynak: Mass.gov 'CDL Self-Certification' (RMV) ve 49 CFR 383.71."},"36":{"q":"Massachusetts'te Istisna Disi Eyaletler Arasi (NI) olarak kendini beyan eden bir surucu, RMV'de su nitelikte bir muayene gorevlisinden gecerli bir tibbi sertifika bulundurmalidir:","options":["Massachusetts'te herhangi bir lisansli hekim","FMCSA Sertifikali Tibbi Muayene Gorevlileri Ulusal Sicilinde listelenmis","Surucunun isvereni tarafindan onaylanmis","Bir Massachusetts RMV personel muayene gorevlisi"],"explanation":"Istisna Disi Eyaletler Arasi surucüler, FMCSA Sertifikali Tibbi Muayene Gorevlileri Ulusal Sicilinde listelenmis bir tibbi muayene gorevlisi tarafindan yapilan bir DOT fizik muayenesini gecmeli ve tibbi sertifikayi RMV'de guncel tutmalidir. Kaynak: Mass.gov 'Medical standards for CDL' ve 49 CFR 391.41-391.43."},"37":{"q":"ELDT teorisini tamamlamanin ve bilgi testini gecmenin otesinde, Massachusetts'teki Tehlikeli Maddeler (H) onayi ayrica basvuru sahibinden sunu da gerektirir:","options":["Tehlikeli yukler icin direksiyon basinda bir yol testi tamamlamasini","Parmak izi alimi dahil bir TSA guvenlik tehdidi degerlendirmesini gecmesini","Once bir Tank (N) onayina sahip olmasini","En az 25 yasinda olmasini"],"explanation":"H onayi, bilgi testi ve ELDT teorisine ek olarak, parmak izi ve biyografik veri sunmayi ve bir adli/goc/teror izleme listesi kontrolunden gecmeyi iceren bir TSA guvenlik tehdidi degerlendirmesi gerektirir. Kaynak: Mass.gov 'CDL classes and endorsements' ve TSA HazMat onay programi (49 CFR 1572)."},"38":{"q":"Massachusetts'te hangi surucu grubu Giris Seviyesi Surucu Egitimi (ELDT) gereksinimlerine tabidir?","options":["Yalnizca mevcut bir CDL'yi yenileyen surucüler","Ilk kez Sinif A veya B CDL alan, Sinif B'yi Sinif A'ya yukselten ya da ilk kez S, P veya H onayi alan surucüler","Yalnizca bir CDL'yi transfer eden eyalet disi surucüler","Yalnizca 21 yas ustu surucüler"],"explanation":"ELDT, ilk kez Sinif A veya B CDL alan, Sinif B'yi Sinif A'ya yukselten ya da ilk kez okul otobusu (S), yolcu (P) veya tehlikeli maddeler (H) onayi alan basvuru sahipleri icin gecerlidir. Kaynak: Mass.gov 'Entry-Level Driver Training (ELDT)' kilavuzu ve FMCSA TPR (49 CFR Part 380)."},"39":{"q":"Massachusetts'te, bir kisinin bir ticari motorlu tasiti (CMV) yasal olarak kullanabilecegi azami kan alkol konsantrasyonu (BAC) nedir?","options":["0.08","0.04","0.02","0.00"],"explanation":"Massachusetts federal standardi takip eder: 0.04 veya daha yuksek bir BAC ile bir CMV kullanmak buyuk bir suctur ve diskalifiye edici bir ihlaldir. 0.08 siniri ticari olmayan surucüler icin gecerlidir. Kaynak: MA RMV CDL Manual, Section 1 (Disqualifications); 49 CFR 383.51."},"40":{"q":"Massachusetts CDL kurallarina gore, ILK buyuk suc olarak (ve plakartli tehlikeli madde tasimadan) 0.04 veya daha yuksek bir BAC ile bir CMV kullanan bir surucu ne kadar sureyle diskalifiye edilir?","options":["60 gun","90 gun","1 yil","3 yil"],"explanation":"0.04 veya daha yuksek bir BAC ile bir CMV kullanmak gibi ilk buyuk bir suc, en az 1 yillik bir diskalifiye ile sonuclanir (plakartli tehlikeli madde tasiniyorsa 3 yil). Kaynak: MA RMV CDL Manual; M.G.L. c. 90F; 49 CFR 383.51."},"41":{"q":"Massachusetts'te, bir CDL surucusu plakartli tehlikeli madde tasiyan bir CMV'yi kullanirken ilk buyuk bir suc islerse, diskalifiye suresi suna yukseltilir:","options":["1 yil","2 yil","3 yil","5 yil"],"explanation":"Ilk buyuk bir suc, CMV tehlikeli maddeler icin plakartli iken meydana geldiginde, diskalifiye 1 yildan 3 yila yukseltilir. Kaynak: MA RMV CDL Manual (Disqualifications); 49 CFR 383.51(b)."},"42":{"q":"Ayri olaylardan kaynaklanan IKINCI bir buyuk suc (ikinci bir OUI veya ikinci bir test reddi gibi) icin Massachusetts CDL diskalifiye suresi nedir?","options":["3 yil","10 yil","Omur boyu","5 yil"],"explanation":"Herhangi bir kombinasyonda ve ayri olaylardan kaynaklanan ikinci bir buyuk suc, omur boyu CDL diskalifiyesi ile sonuclanir. Kaynak: MA RMV CDL Manual; M.G.L. c. 90F; 49 CFR 383.51(b)."},"43":{"q":"Massachusetts'te, zimni riza (implied-consent) kurali geregince, bir CMV kullanirken gerekli bir alkol (kimyasal) testine girmeyi REDDEDEN bir CDL surucusu su sucu islemis kabul edilir:","options":["Ciddi bir trafik ihlali (60 gunluk diskalifiye)","Yalnizca para cezasi olan kucuk bir ihlal","Buyuk bir suc (1 yillik diskalifiye, tehlikeli madde varsa 3 yil)","Bir demiryolu geciti ihlali"],"explanation":"Bir CMV kullanarak, bir surucu alkol testine zimni riza vermis olur. Testi reddetmek, alkollu arac kullanmayla ayni cezayi tasiyan buyuk bir suctur: 1 yillik diskalifiye (tehlikeli madde icin plakartli ise 3 yil) ve ikinci olayda omur boyu. Kaynak: MA RMV CDL Manual; 49 CFR 383.51(b); M.G.L. c. 90F."},"44":{"q":"Massachusetts'te 3 yillik bir donemde (ayri olaylarda) kac CIDDI trafik ihlali, 60 gunluk bir CDL diskalifiyesini tetikler?","options":["1","2","3","4"],"explanation":"3 yillik bir donemde ikinci bir ciddi trafik ihlali 60 gunluk bir diskalifiye ile sonuclanir; 3 yil icinde ucuncu bir ihlal ise 120 gun ile sonuclanir. Tek basina tek bir ciddi ihlal diskalifiyeye yol acmaz. Kaynak: MA RMV CDL Manual; 49 CFR 383.51(c)."},"45":{"q":"Massachusetts'te, 3 yillik bir donemde islenen UC ciddi trafik ihlali su sureyle bir CDL diskalifiyesi ile sonuclanir:","options":["60 gun","90 gun","120 gun","180 gun"],"explanation":"3 yillik bir donemde ucuncu bir ciddi trafik ihlali 120 gunluk bir diskalifiye ile sonuclanir (3 yil icinde ikinci ihlal 60 gundur). Kaynak: MA RMV CDL Manual; 49 CFR 383.51(c)."},"46":{"q":"Asagidakilerden hangisi bir Massachusetts CDL surucusu icin CIDDI bir trafik ihlali olarak siniflandirilir?","options":["0.04 veya daha yuksek bir BAC ile bir CMV kullanmak","Bir alkol testini reddetmek","Belirtilen hiz sinirinin 15 mph veya daha fazla uzerinde arac kullanmak","CDL'niz askiya alinmisken bir CMV kullanmak"],"explanation":"Sinirin 15 mph veya daha fazla uzerinde hiz yapmak ciddi bir trafik ihlalidir. 0.04+ BAC ile arac kullanmak, bir testi reddetmek ve askiya alinmis bir CDL ile arac kullanmak BUYUK suclardir, ciddi ihlaller degil. Kaynak: MA RMV CDL Manual; 49 CFR 383.51(c)."},"47":{"q":"Massachusetts CDL kurallarina gore, bir CMV kullanirken MESAJLASMAYI (texting) yasaklayan bir yasayi ihlal etmek su sekilde kategorize edilir:","options":["Buyuk bir suc","Ciddi bir trafik ihlali","Bir servis disi (out-of-service) emri ihlali","Bir demiryolu geciti ihlali"],"explanation":"Bir CMV kullanirken mesajlasmak ciddi bir trafik ihlalidir; 3 yil icinde iki tane biriktirmek 60 gunluk bir diskalifiyeye, 3 yil icinde uc tane ise 120 gune yol acar. Kaynak: MA RMV CDL Manual; 49 CFR 383.51(c); M.G.L. c. 90 sec. 13B."},"48":{"q":"Bir CMV kullanirken ELDE TUTULAN bir cep telefonu kullanmak, Massachusetts CDL diskalifiye amaclari acisindan su sekilde ele alinir:","options":["Ciddi bir trafik ihlali","Buyuk bir suc","Bir servis disi ihlali","Diskalifiye edici olmayan bir ihlal"],"explanation":"Bir CMV kullanirken elde tutulan bir telefon kullanmak, 3 yilda 2 (60 gun) ve 3 yilda 3 (120 gun) diskalifiye esiklerine sayilan ciddi bir trafik ihlalidir. Kaynak: MA RMV CDL Manual; 49 CFR 383.51(c); M.G.L. c. 90 sec. 13B."},"49":{"q":"Massachusetts Eller Serbest Yasasi (M.G.L. c. 90 sec. 13B) geregince, ILK elde tutulan cihaz sucu icin para cezasi sudur:","options":["$35","$100","$250","$500"],"explanation":"Massachusetts Eller Serbest Yasasi, ilk suc icin $100, ikinci icin $250 ve ucuncu veya sonraki suc icin $500 para cezasi belirler; tekrar suc isleyenler icin zorunlu bir dikkat dagitan surus programi ile birlikte. Kaynak: M.G.L. c. 90 sec. 13B."},"50":{"q":"Massachusetts Eller Serbest Yasasi geregince, UCUNCU veya sonraki elde tutulan cihaz sucu icin para cezasi sudur:","options":["$100","$250","$500","$1,000"],"explanation":"Para cezalari ucuncu veya sonraki suc icin $500'a yukselir ($100 ilk, $250 ikinci). Ikinci veya sonraki bir suc ayrica bir dikkat dagitan surus programinin tamamlanmasini gerektirir. Kaynak: M.G.L. c. 90 sec. 13B."},"51":{"q":"Bir Massachusetts CDL surucusu tarafindan islenen ILK demiryolu-karayolu hemzemin geciti ihlali icin diskalifiye suresi nedir?","options":["30 gunden az olmamak","60 gunden az olmamak","120 gunden az olmamak","1 yildan az olmamak"],"explanation":"Ilk demiryolu-karayolu hemzemin geciti ihlali, 60 gunden az olmayan bir diskalifiye ile sonuclanir. Kaynak: MA RMV CDL Manual; 49 CFR 383.51(d)."},"52":{"q":"Bir Massachusetts CDL surucusu icin, 3 yillik bir donemde IKINCI bir demiryolu-karayolu hemzemin geciti ihlali su diskalifiye ile sonuclanir:","options":["60 gunden az olmamak","120 gunden az olmamak","1 yildan az olmamak","3 yildan az olmamak"],"explanation":"3 yil icinde ikinci bir demiryolu geciti ihlali, 120 gunden az olmayan bir diskalifiye ile sonuclanir (ilki 60 gun, 3 yil icinde ucuncusu 1 yildan az olmaz). Kaynak: MA RMV CDL Manual; 49 CFR 383.51(d)."},"53":{"q":"3 yillik bir donemde UCUNCU bir demiryolu-karayolu hemzemin geciti ihlali, bir Massachusetts CDL surucusunu su sureyle diskalifiye eder:","options":["120 gunden az olmamak","180 gunden az olmamak","1 yildan az olmamak","Omur boyu"],"explanation":"3 yillik bir donemde uc demiryolu geciti ihlali, 1 yildan az olmayan bir diskalifiye ile sonuclanir. Kaynak: MA RMV CDL Manual; 49 CFR 383.51(d)."},"54":{"q":"Massachusetts'te, bir servis disi (OOS) emrini ihlal etmekten ILK mahkumiyet (tehlikeli madde disi, yolcu disi) su diskalifiye ile sonuclanir:","options":["60 gunden az olmamak","90 gunden az olmamak","180 gunden az ve 1 yildan fazla olmamak","1 yildan az ve 5 yildan fazla olmamak"],"explanation":"Ilk servis disi emri ihlali, 180 gunden az ve 1 yildan fazla olmayan bir diskalifiye ile sonuclanir. Kaynak: MA RMV CDL Manual; 49 CFR 383.51(e)."},"55":{"q":"10 yillik bir donemde IKINCI bir servis disi emri ihlali, bir Massachusetts CDL surucusunu su sureyle diskalifiye eder:","options":["180 gunden az ve 1 yildan fazla olmamak","2 yildan az ve 5 yildan fazla olmamak","1 yildan az ve 3 yildan fazla olmamak","Omur boyu"],"explanation":"10 yil icinde ikinci bir servis disi emri ihlali, 2 yildan az ve 5 yildan fazla olmayan bir diskalifiye ile sonuclanir. Kaynak: MA RMV CDL Manual; 49 CFR 383.51(e)."},"56":{"q":"Plakartli tehlikeli madde tasirken veya 16+ yolcu icin tasarlanmis bir tasiti kullanirken yapilan ILK servis disi emri ihlali, su Massachusetts CDL diskalifiyesi ile sonuclanir:","options":["180 gunden az ve 1 yildan fazla olmamak","180 gunden az ve 2 yildan fazla olmamak","1 yildan az ve 3 yildan fazla olmamak","3 yildan az ve 5 yildan fazla olmamak"],"explanation":"Plakartli tehlikeli madde veya 16+ yolcu tasitini iceren ilk servis disi ihlali, daha agir bir ceza tasir: 180 gunden az ve 2 yildan fazla olmamak. Kaynak: MA RMV CDL Manual; 49 CFR 383.51(e)."},"57":{"q":"Asagidakilerden hangisi, surucunun kisisel (ticari olmayan) aracinda islense bile bir Massachusetts CDL surucusunu diskalifiye eden BUYUK bir suc olarak kabul edilir?","options":["Cok yakindan takip etmek","Uygunsuz serit degistirme","Kaza yerinden ayrilmak","Elde tutulan bir telefon kullanmak"],"explanation":"Kaza yerinden ayrilmak, ister bir CMV'de ister kisisel bir aracta islensin CDL'yi diskalifiye eden buyuk bir suctur. Digerleri yalnizca bir CMV kullanirken islendiklerinde ciddi trafik ihlalleridir. Kaynak: MA RMV CDL Manual; 49 CFR 383.51(b)."},"58":{"q":"Bir kontrollu maddenin uretilmesi, dagitilmasi veya teminini iceren bir agir suc (felony) islemek icin herhangi bir motorlu tasiti kullanan bir Massachusetts CDL surucusu su sureyle diskalifiye edilir:","options":["1 yil","3 yil","10 yil","Iadesi mumkun olmayan omur boyu"],"explanation":"Kontrollu maddeleri (uretim, dagitim veya temin) iceren bir agir suc islemek icin bir motorlu tasiti kullanmak, iadeye TABI OLMAYAN omur boyu bir diskalifiye ile sonuclanir. Kaynak: MA RMV CDL Manual; M.G.L. c. 90F; 49 CFR 383.51(b)."},"59":{"q":"Massachusetts demiryolu geçidi yasasına göre, bir okul otobüsü ya da yük olarak patlayıcı veya yanıcı sıvı taşıyan bir araç, en yakın raydan hangi mesafe aralığında tam olarak durmalıdır?","options":["15 fitten az ve 50 fitten fazla olmamak üzere","10 fitten az ve 40 fitten fazla olmamak üzere","5 fitten az ve 25 fitten fazla olmamak üzere","20 fitten az ve 75 fitten fazla olmamak üzere"],"explanation":"Massachusetts General Laws c. 90, s. 15, bir okul otobüsünün veya yük olarak patlayıcı ya da yanıcı sıvı taşıyan bir aracın, geçmeden önce en yakın raydan 15 fitten az ve 50 fitten fazla olmamak üzere durmasını gerektirir. Kaynak: MGL c. 90, s. 15."},"60":{"q":"Eyaletin 'Move Over' (Şerit Değiştir) yasası hangi Massachusetts kanununa dayanır ve yanıp sönen ışıklar gösteren duran bir acil durum, bakım ya da kurtarma aracına yaklaşırken temel gereklilik nedir?","options":["MGL c. 89, s. 7C; mümkünse bitişik olmayan bir şeride geçin, geçemiyorsanız güvenli ve makul bir hıza yavaşlayın","MGL c. 90, s. 14; ışıklar kapanana kadar tamamen durun","MGL c. 85, s. 2; kornanıza basın ve belirtilen hızda devam edin","MGL c. 90, s. 17; hızı en fazla 20 mph'ye düşürün ve şeridinizi koruyun"],"explanation":"Massachusetts'in Move Over yasası olan MGL c. 89, s. 7C (Mart 2009'da yürürlüğe girmiştir), yanıp sönen ışıkları olan duran bir acil durum, bakım veya kurtarma aracına yaklaşan sürücülerin güvenli olduğunda bitişik olmayan bir şeride geçmesini, geçemiyorlarsa güvenli ve makul bir hıza yavaşlamalarını gerektirir. Kaynak: MGL c. 89, s. 7C; Mass.gov Move Over Law."},"61":{"q":"Massachusetts'te MGL c. 89, s. 7C uyarınca Move Over yasasının ihlali için ceza (para cezası) nedir?","options":["$100","$35","$250","$500"],"explanation":"Massachusetts Move Over yasasının (MGL c. 89, s. 7C) ihlali $100 para cezası taşır. Kaynak: MGL c. 89, s. 7C; Massachusetts State Police Move Over Law sayfası."},"62":{"q":"Massachusetts'te, kırmızı ışıkları yanıp sönen duran bir okul otobüsüne yaklaşan bir sürücünün durmasının gerekli OLMADIĞI durum ne zamandır?","options":["Bölünmüş bir karayolunda ters yönden yaklaşırken","Sürücü 20 mph'den daha yavaş giderken","Sürücü otobüsün iki araç boyundan daha geride olduğunda","Otobüs bir iş bölgesi içinde durduğunda"],"explanation":"MGL c. 90, s. 14 uyarınca, bölünmüş bir karayolunda ters yönden yaklaşma durumu hariç, her sürücü yanıp sönen kırmızı ışıklar gösteren bir okul otobüsüne ulaşmadan önce durmalıdır. Kaynak: MGL c. 90, s. 14."},"63":{"q":"Massachusetts'te, kırmızı ışıkları yanıp sönen duran bir okul otobüsü için durmama ya da onu yasadışı şekilde geçme suçunun ilk işlenişi için asgari para cezası nedir?","options":["$250","$100","$50","$500"],"explanation":"MGL c. 90, s. 14 uyarınca, okul otobüsü durma yasasının ilk ihlali en az $250 para cezası taşır; ikinci suç ise 6 aylık ehliyet askıya alma ile birlikte $500-$1,000'dır. Kaynak: MGL c. 90, s. 14."},"64":{"q":"Düz, dümdüz, bölünmüş bir karayolunda, bir CDL sürücüsü banketta durduktan sonra üç adet acil durum yansıtıcı üçgenini nereye yerleştirmelidir?","options":["Arkadan 10 fit içinde, arkaya doğru yaklaşık 100 fit ve arkaya doğru yaklaşık 200 fit","Arkaya doğru 25 fit içinde, yaklaşık 75 fit ve yaklaşık 150 fit","Arkaya doğru 5 fit içinde, yaklaşık 50 fit ve yaklaşık 100 fit","Arkaya doğru 15 fit içinde, yaklaşık 150 fit ve yaklaşık 300 fit"],"explanation":"Massachusetts CDL Kılavuzu (49 CFR 392.22'yi benimseyerek), bölünmüş ya da tek yönlü bir yolda bir üçgenin aracın arkasından 10 fit içinde, birinin arkaya doğru yaklaşık 100 fit, birinin de arkaya doğru yaklaşık 200 fit yerleştirilmesini öngörür. Kaynak: Massachusetts CDL Manual, Driving Safely (49 CFR 392.22)."},"65":{"q":"Bir ticari araç görüşü kısıtlayan bir tepe, viraj ya da başka bir engelin 500 fit içinde durmuşsa, bir CDL sürücüsü acil durum üçgeni yerleşimini nasıl ayarlamalıdır?","options":["Yaklaşan sürücülere daha fazla uyarı vermek için en arkadaki üçgeni, engele doğru, araçtan 100 ila 500 fit uzakta olacak şekilde geriye taşıyın","Tüm üçgenleri kaldırın ve yalnızca dörtlü flaşörlere güvenin","Üç üçgenin de bir arada kalması için hepsini aracın 50 fit içine yerleştirin","Yalnızca bir üçgeni, doğrudan aracın arkasına, en fazla 10 fit uzağa yerleştirin"],"explanation":"Massachusetts CDL Kılavuzuna (49 CFR 392.22) göre, bir araç bir virajın, tepe doruğunun ya da başka bir engelin 500 fit içinde durmuşsa, engele doğru yer alan uyarı cihazı, yaklaşan trafiğe yeterli uyarı vermek için araçtan 100 ila 500 fit uzağa yerleştirilmelidir. Kaynak: Massachusetts CDL Manual; 49 CFR 392.22."},"66":{"q":"Massachusetts Turnpike'ta (I-90), Weston'daki Interchange 14 ile Sturbridge'deki Interchange 9 arasında, ağır bir ticari araç (otobüs dışında) hangi seyir şeritlerini kullanabilir?","options":["Yalnızca en sağdaki şeridi ya da sollayıp geçerken hemen bitişiğindeki şeridi","Turnpike'ta kamyonlar için şerit kısıtlaması olmaksızın herhangi bir şeridi","Yavaş trafiği açık tutmak için yalnızca en soldaki şeridi","Yalnızca gündüz saatlerinde en soldaki iki şeridi"],"explanation":"700 CMR 7.09, Interchange 14 (Weston) ile Interchange 9 (Sturbridge) arasında ağır bir ticari aracı (otobüs dışında), acil durum hariç, en sağdaki seyir şeridine ya da yalnızca sollayıp geçerken hemen bitişiğindeki şeride kısıtlar. Kaynak: 700 CMR 7.09."},"67":{"q":"Boston'da kasalı kamyonlar, taşımacılık kamyonları ve diğer ticari araçlar neden Storrow Drive ve Soldiers Field Road'dan men edilmiştir (sözde 'Storrowing'in nedeni)?","options":["Bunlar düşük üst geçit gabarisine (kabaca 10 fit veya daha az) sahip DCR 'yalnızca otomobil' parkyollarıdır ve kamyonlar/otobüsler yasaktır","Yalnızca ticari transponderları kabul eden bir geçiş ücretleri vardır","Yoğun saatlerde yüksek doluluklu araçlara ayrılmışlardır","Eyaletlerarası yük taşımacılığı için fazla düşük belirtilmiş bir kamyon hız sınırları vardır"],"explanation":"Storrow Drive ve Soldiers Field Road, yolcu araçlarına ('yalnızca otomobil') kısıtlanmış, yaklaşık 10 fit veya daha az düşük köprü gabarilerine sahip Department of Conservation and Recreation (DCR) parkyollarıdır; kamyonlar, otobüsler ve benzeri araçlar yasaktır ve yükseklik aşımı yapan kamyonlar üst geçitlere düzenli olarak çarpar. Kaynak: 302 CMR 11.00; Mass.gov / DCR Storrowing kampanyası."},"68":{"q":"Yoğun yerleşim ya da iş bölgesinin dışında, belirtilmiş bir hız sınırı bulunmayan bölünmemiş bir Massachusetts karayolunda, üzerinde hız yaptığınızın varsayıldığı kanuni hız nedir?","options":["40 mph","30 mph","50 mph","55 mph"],"explanation":"MGL c. 90, s. 17 uyarınca, belirtilmiş bir sınırın olmadığı, yoğun yerleşim ya da iş bölgesinin dışındaki bölünmemiş bir yolda, en az çeyrek mil boyunca 40 mph'yi aşmak, hız yapmanın ilk bakışta (prima facie) kanıtıdır (bölünmüş karayolu için rakam 50 mph'dir). Kaynak: MGL c. 90, s. 17."},"69":{"q":"Massachusetts'te yoğun yerleşim ya da iş bölgesi içinde, hiçbiri belirtilmediğinde kanuni hız sınırı nedir?","options":["30 mph","25 mph","20 mph","35 mph"],"explanation":"MGL c. 90, s. 17 uyarınca, özel bir sınırın belirtilmediği yoğun yerleşim ya da iş bölgesindeki kanuni hız 30 mph'dir (yoğun yerleşim bölgesi, konut binalarının ortalama 200 fitten daha az aralıklarla bulunduğu bölge olarak tanımlanır). Kaynak: MGL c. 90, s. 17."},"70":{"q":"Massachusetts'te, demiryolu geçidinde duran bir okul otobüsü sürücüsü, 15 ila 50 fitlik bölgede durmanın yanı sıra aşağıdakilerden hangisini yapmalıdır?","options":["Servis kapısını açın, geçmenin güvenli olduğundan emin olun, sonra devam etmeden önce kapıyı kapatın","Geçmeden önce kornaya üç kez basın","Rayların her iki yanına yansıtıcı üçgenler yerleştirin","Geçmeden önce mevcut en yüksek vitese geçin"],"explanation":"MGL c. 90, s. 15 uyarınca, bir okul otobüsü sürücüsü en yakın raydan 15-50 fit içinde durmalı, servis kapısını açmalı, geçmenin güvenli olduğunu tespit etmeli ve sonra devam etmeden önce kapıyı kapatmalıdır. Kaynak: MGL c. 90, s. 15."},"71":{"q":"Massachusetts CDL Kılavuzuna göre, bir sürücü ticari bir araçla demiryolu raylarının üzerinden geçerken vitesleri nasıl kullanmalıdır?","options":["Rayların vites değiştirmeden geçilebileceği kadar düşük bir vitesle geçin","Rayları daha hızlı geçmek için raylar üzerindeyken vitesleri yukarı çıkarın","Boşa alın ve rayların üzerinden kayarak geçin","Hızı düşürmek için geçişin ortasında vites küçültün"],"explanation":"Massachusetts CDL Kılavuzu, sürücülere aracın rayları vites değiştirmeden tamamen geçmesini sağlayacak bir vites seçmelerini ve raylar üzerindeyken vites değiştirmemelerini öğütler. Kaynak: Massachusetts CDL Manual, Railroad Crossings (49 CFR 392.10)."},"72":{"q":"Massachusetts'te bir kamyonun, ağırlık aşımı izni olmaksızın federal karayolu sisteminde işletebileceği azami brüt araç ağırlığı nedir?","options":["80,000 pound","73,280 pound","99,000 pound","100,000 pound"],"explanation":"Massachusetts, özel izin olmaksızın 80,000 pound brüt araç ağırlığı federal sınırını uygular; bunun üzerindeki yükler bir MassDOT ağırlık aşımı izni gerektirir. Kaynak: MassDOT Commercial Truck Permits; Massachusetts'te uygulanan federal ağırlık sınırları."},"73":{"q":"Boyut aşımı izni olmaksızın, Massachusetts karayollarında izin verilen azami yasal araç/yük genişliği nedir?","options":["8 fit 6 inç (102 inç)","8 fit 0 inç (96 inç)","10 fit 0 inç (120 inç)","9 fit 0 inç (108 inç)"],"explanation":"Massachusetts'te boyut aşımı izni olmaksızın yasal azami genişlik 8 fit 6 inçtir (102 inç); daha geniş yükler bir MassDOT boyut aşımı izni gerektirir. Kaynak: MassDOT oversize/overweight yönetmelikleri; Mass.gov Commercial Truck Permits."},"74":{"q":"Boyut aşımı izni olmaksızın, Massachusetts karayollarında bir araç ve yük için azami yasal yükseklik nedir?","options":["13 fit 6 inç","13 fit 0 inç","14 fit 0 inç","12 fit 6 inç"],"explanation":"Massachusetts yasal azami yüksekliği 13 fit 6 inç olarak belirler; daha uzun yükler bir MassDOT boyut aşımı izni gerektirir ve bir güzergah etüdüne ihtiyaç duyabilir. Kaynak: MassDOT oversize/overweight yönetmelikleri; Mass.gov Commercial Truck Permits."},"75":{"q":"Massachusetts Turnpike'ta, Weston ile Sturbridge arasındaki ağır ticari araç şerit kısıtlaması otobüslere nasıl davranır?","options":["Otobüsler bu yalnızca sağ şerit kısıtlamasından muaftır","Otobüsler her zaman sol şeritte kalmalıdır","Otobüsler bu kesimden tamamen yasaklanmıştır","Otobüsler yalnızca geceleri seyahat etmelidir"],"explanation":"700 CMR 7.09 uyarınca, Interchange 14 (Weston) ile Interchange 9 (Sturbridge) arasındaki yalnızca sağ şerit kısıtlaması 'otobüs dışındaki' ağır ticari araçlara uygulanır, dolayısıyla otobüsler bu belirli kısıtlamadan muaftır. Kaynak: 700 CMR 7.09."},"76":{"q":"Massachusetts yasalarına göre, bir okul otobüsü için durması gereken bir sürücü durduktan sonra ne zaman devam edebilir?","options":["Bir polis memuru aksini belirtmedikçe, otobüsün yanıp sönen kırmızı uyarı sinyalleri devre dışı bırakıldığında","Işıklara bakılmaksızın sabit 10 saniye bekledikten sonra","Otobüsün amber (sarı) ışıkları yanıp sönmeye başlar başlamaz","Hiçbir çocuk görünmüyorsa hemen"],"explanation":"MGL c. 90, s. 14, duran sürücünün, bir polis memuru tarafından devam etmesi söylenmedikçe, okul otobüsünün yanıp sönen kırmızı sinyalleri devre dışı bırakılana kadar durmuş halde kalmasını gerektirir. Kaynak: MGL c. 90, s. 14."},"77":{"q":"MGL c. 90, s. 14 uyarınca, bir araç bir Massachusetts kamu yolunda bir okul otobüsünün arkasından ne kadar yakın takip edebilir?","options":["100 fitten daha yakın değil","50 fitten daha yakın değil","200 fitten daha yakın değil","25 fitten daha yakın değil"],"explanation":"MGL c. 90, s. 14, bir aracın bir okul otobüsünün 100 fit arkasında işletilmesini yasaklar (izin verilen yerlerde sollayıp geçme durumu hariç). Kaynak: MGL c. 90, s. 14."},"78":{"q":"Massachusetts'te Ticari Sürücü Belgelerini (CDL'ler) hangi kurum verir?","options":["MassDOT'un bir parçası olan Registry of Motor Vehicles (RMV)","Federal Motor Carrier Safety Administration (FMCSA)","Massachusetts Department of Public Safety","Massachusetts State Police Commercial Vehicle Section"],"explanation":"Massachusetts'te CDL'ler, Massachusetts Department of Transportation'ın (MassDOT) bir bölümü olan Registry of Motor Vehicles (RMV) tarafından verilir. FMCSA federal standartları belirler ancak belgeyi vermez. Kaynak: Mass.gov RMV Commercial Driver's Licenses (CDL) sayfaları."},"79":{"q":"Massachusetts'te herhangi bir CDL beceri (yol) sınavına girebilmeden önce, ilk olarak hangi belgeyi almalısınız?","options":["Bir Commercial Learner's Permit (CLP)","Tam bir Class A CDL","Bir federal eyaletlerarası işletme yetkisi (MC numarası)","Bir tehlikeli madde ek belgesi"],"explanation":"Pratik amacıyla ticari bir motorlu aracı işletmek ve beceri sınavına hak kazanmak için, bir Massachusetts başvuru sahibi önce bilgi sınav(lar)ını geçmeli ve bir Commercial Learner's Permit (CLP) almalıdır. Kaynak: Mass.gov RMV CDL sayfaları; 49 CFR 383."},"80":{"q":"Bir Massachusetts CLP sahibi, CDL beceri sınavına girmeye hak kazanmadan önce CLP verildikten sonra ne kadar beklemelidir?","options":["En az 14 gün","En az 24 saat","En az 30 gün","En az 60 gün"],"explanation":"Başvuru sahibi CDL beceri sınavına girebilmeden önce bir CLP en az 14 gün boyunca tutulmalıdır. Bu, Massachusetts'in uyguladığı bir federal gerekliliktir (49 CFR 383.37). Kaynak: Mass.gov RMV CDL sayfaları; 49 CFR 383.37."},"81":{"q":"Bir Massachusetts Commercial Learner's Permit (CLP) ne kadar süre geçerlidir?","options":["180 gün, ek 180 gün için bir kez yenilenebilir","30 gün, yenileme izni yok","1 yıl, iki kez yenilenebilir","90 gün, ek 90 gün için bir kez yenilenebilir"],"explanation":"Bir Massachusetts CLP'si 180 gün geçerlidir ve bilgi sınavlarını yeniden vermeden ek 180 gün için bir kez yenilenebilir; bundan sonra başvuru sahibi yeniden başvurmalıdır. Kaynak: Mass.gov RMV CDL sayfaları; 49 CFR 383.25."},"82":{"q":"Massachusetts CDL beceri sınavı hangi üç bölümden oluşur?","options":["Sefer öncesi muayene, temel araç kontrolü ve yol üstü sürüş","Yazılı sınav, görme taraması ve yol sürüşü","Hava freni kontrolü, tehlikeli madde kullanımı ve yol üstü sürüş","Bağlama/ayırma, seyir defteri incelemesi ve yol üstü sürüş"],"explanation":"Massachusetts CDL beceri sınavının üç bölümü vardır: sefer öncesi (araç) muayenesi, temel araç kontrolü (geri gitme gibi kontrol becerileri) ve yol üstü sürüş sınavı. Kaynak: Mass.gov RMV CDL Skills Test Information Sheet / Modernized CDL Skills Exam Standard."},"83":{"q":"Bir Massachusetts CDL/CLP başvuru sahibi, yaptığı sürüş türünü beyan ederken kaç öz-sertifikasyon kategorisi arasından seçim yapmalıdır?","options":["Dört","İki","Üç","Beş"],"explanation":"Federal ve Massachusetts kuralları, sürücünün ticaretin dört kategorisinden birine öz-sertifikasyon yapmasını gerektirir. Kaynak: Mass.gov 'Commercial Driver's License (CDL) Self-Certification'; 49 CFR 383.71."},"84":{"q":"Aşağıdakilerden hangisi Massachusetts'te kullanılan dört CDL öz-sertifikasyon kategorisinden biridir?","options":["Non-Excepted Interstate (NI)","Restricted Commercial (RC)","Federal Excepted Operator (FEO)","Limited Intrastate Hauler (LIH)"],"explanation":"Dört kategori şunlardır: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) ve Excepted Intrastate (EA). Diğer seçenekler gerçek kategoriler değildir. Kaynak: Mass.gov CDL Self-Certification; 49 CFR 383.71."},"85":{"q":"Massachusetts/FMCSA kurallarına göre, kendini 'Non-Excepted Interstate (NI)' olarak beyan eden bir sürücü, işletmesi hakkında hangi beyanı yapmaktadır?","options":["Eyalet sınırlarının ötesinde işletme yaparlar ve federal DOT tıbbi kart gerekliliklerini karşılamalıdırlar","Yalnızca Massachusetts içinde işletme yaparlar ve hiçbir tıbbi sertifikaya ihtiyaçları yoktur","Eyalet sınırlarının ötesinde işletme yaparlar ancak tıbbi gerekliliklerden muaftırlar","Yalnızca Massachusetts içinde işletme yaparlar ve yalnızca eyalet tıbbi kurallarını karşılarlar"],"explanation":"Non-Excepted Interstate (NI), sürücünün eyaletlerarası ticarette işletme yaptığı (ya da yapmayı beklediği) ve federal DOT tıbbi muayene sertifikası gerekliliklerini karşılamasının zorunlu olduğu anlamına gelir. Kaynak: Mass.gov CDL Self-Certification; 49 CFR 383.71/391."},"86":{"q":"Massachusetts'te kendini 'Excepted Intrastate (EA)' olarak beyan eden bir sürücü aşağıdakilerden hangisini belirtmektedir?","options":["Yalnızca Massachusetts içinde işletme yaparlar ve federal DOT tıbbi kart gerekliliklerini karşılamaları gerekmez","Eyalet sınırlarının ötesinde işletme yaparlar ve bir federal tıbbi kart taşımalıdırlar","Yalnızca Massachusetts içinde işletme yaparlar ve bir federal DOT tıbbi kartı bulundurmalıdırlar","Yalnızca tehlikeli madde taşımacılığı ile kısıtlıdırlar"],"explanation":"Excepted Intrastate (EA), sürücünün yalnızca eyalet içi (eyalet sınırları içinde) ticarette işletme yaptığı ve federal DOT tıbbi kart gerekliliklerinden muaf olduğu anlamına gelir. Kaynak: Mass.gov CDL Self-Certification; 49 CFR 383.71."},"87":{"q":"Eyaletlerarası, muaf olmayan bir Massachusetts CDL sürücüsü bir DOT fizik muayenesini geçtiğinde, sertifikalı tıbbi muayene uzmanı hangi belgeyi düzenler?","options":["Bir Medical Examiner's Certificate (Form MCSA-5876)","Bir Massachusetts RMV Class D görme muafiyeti","Bir federal Hours-of-Service muafiyet mektubu","Bir FMCSA işletme yetkisi sertifikası"],"explanation":"FMCSA National Registry'den, sürücüyü uygun bulan bir muayene uzmanı bir Medical Examiner's Certificate (Form MCSA-5876) düzenler. Kaynak: Mass.gov CDL Self-Certification / Medical Certification; FMCSA National Registry."},"88":{"q":"DOT fizik muayenelerini yapan bir Massachusetts CDL tıbbi muayene uzmanı nerede listelenmiş olmalıdır?","options":["FMCSA National Registry of Certified Medical Examiners üzerinde","Massachusetts RMV onaylı hekim listesi üzerinde","Massachusetts Board of Registration in Medicine CDL listesi üzerinde","MassDOT Highway Division sağlayıcı listesi üzerinde"],"explanation":"CDL amaçlı DOT fizik muayeneleri, FMCSA National Registry of Certified Medical Examiners üzerinde listelenmiş bir tıbbi muayene uzmanı tarafından yapılmalıdır. Kaynak: Mass.gov CDL Self-Certification; FMCSA National Registry."},"89":{"q":"2025 ortası itibarıyla, çoğu Massachusetts CDL sürücüsü için tıbbi sertifikasyon bilgisi RMV'ye nasıl ulaşır?","options":["FMCSA National Registry'den elektronik olarak, dolayısıyla genellikle bir kağıt kartın gönderilmesine gerek yoktur","Yalnızca sürücünün 5 gün içinde RMV'ye bir kağıt kart postalamasıyla","Yalnızca işverenin kartı MassDOT'a fakslamasıyla","Otomatik olarak sürücünün sigorta şirketinden"],"explanation":"23 Haziran 2025'ten itibaren, RMV tıbbi sertifikasyon bilgisini FMCSA National Registry'den elektronik olarak alır, dolayısıyla çoğu sürücünün fiziksel bir kopya göndermesi gerekmez (yalnızca eyalet içi çalışan sürücüler, yüklenmemişse yine de bir tane gönderebilir). Kaynak: Mass.gov CDL Self-Certification."},"90":{"q":"RMV CDL beceri sınavını planlamadan önce, ilk kez başvuran bir Class A ya da Class B Massachusetts başvuru sahibi hangi eğitimi tamamlamalıdır?","options":["FMCSA kayıtlı bir sağlayıcıdan Entry-Level Driver Training (ELDT)","40 saatlik bir MassDOT savunmacı sürüş kursu","Bir RMV hizmet merkezinde eyalet işletmeli bir çıraklık","Yalnızca işveren tarafından verilen bir yol güvenliği oryantasyonu"],"explanation":"7 Şubat 2022'den bu yana, ilk kez başvuran Class A/B adaylarının (ve ilk kez S, P ya da H ek belgeleri için) RMV beceri sınavını planlamadan önce, FMCSA Training Provider Registry üzerinde listelenen bir sağlayıcıdan Entry-Level Driver Training (ELDT) tamamlaması gerekir. Kaynak: Mass.gov ELDT rehberi; 49 CFR Part 380 Subpart F."},"91":{"q":"Massachusetts CDL beceri sınavından önce gerekli olan Entry-Level Driver Training (ELDT) hangi iki bileşenden oluşur?","options":["Teori eğitimi ve direksiyon başında eğitim","Bir yazılı sınav ve bir görme taraması","Yalnızca sınıf içi eğitim ve bir federal geçmiş kontrolü","Bir tıbbi muayene ve bir uyuşturucu taraması"],"explanation":"ELDT, CDL beceri sınavına girmeden önce öngörülen bir teori ve direksiyon başında eğitim programının başarıyla tamamlanmasını gerektirir. Kaynak: Mass.gov ELDT rehberi; FMCSA 49 CFR Part 380 Subpart F."},"92":{"q":"İlk kez başvuran Class A/B adaylarına ek olarak, ELDT ilk kez hangi ek belge için başvurmadan önce de tamamlanmalıdır?","options":["Tehlikeli madde (H), yolcu (P) ya da okul otobüsü (S)","Yalnızca tank aracı (N)","Yalnızca ikili/üçlü römork (T)","Hava frenleri (kısıtlama yok)"],"explanation":"ELDT, ilk kez Class A/B CDL'lerine, Class B'den A'ya yükseltmelere ve ilk kez tehlikeli madde (H), yolcu (P) ve okul otobüsü (S) ek belgelerine uygulanır. Kaynak: Mass.gov ELDT rehberi; 49 CFR Part 380."},"93":{"q":"Bir Massachusetts CDL'si yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["5 yıl","2 yıl","8 yıl","10 yıl"],"explanation":"Bir Massachusetts CDL'si 5 yıl geçerlidir ve genellikle sahibinin doğum gününde sona erer. Kaynak: Mass.gov RMV ehliyet yenileme sayfaları."},"94":{"q":"Yalnızca eyalet içi (yalnızca Massachusetts) bir CDL almak için asgari yaş ve eyaletlerarası işletme için asgari yaş nedir?","options":["Eyalet içi için 18 ve eyaletlerarası için 21","Eyalet içi için 16 ve eyaletlerarası için 18","Hem eyalet içi hem de eyaletlerarası için 18","Hem eyalet içi hem de eyaletlerarası için 21"],"explanation":"Bir başvuru sahibi, eyalet içi (Massachusetts içinde) bir CDL/CLP almak için en az 18 yaşında ve eyaletlerarası ticarette işletme yapmak için en az 21 yaşında olmalıdır. Kaynak: Mass.gov RMV CDL sayfaları; 49 CFR 383.3/391.11."},"95":{"q":"Bir Massachusetts CLP/CDL'sine başvururken, başvuru sahibi genel olarak hangi belge setini sağlamalıdır?","options":["Kimlik/yasal mevcudiyet kanıtı, bir Social Security numarası ve Massachusetts ikameti","Yalnızca geçerli bir pasaport ve bir araç tescili","Yalnızca bir işveren mektubu ve bir araç ruhsatı","Bir doğum belgesi ve bir kredi raporu"],"explanation":"Massachusetts CDL başvuru sahipleri, diğer RMV belgeleri için kullanılan aynı kimlik standartları gibi, kimlik/yasal mevcudiyeti kanıtlamalı, bir Social Security numarası sağlamalı ve Massachusetts ikametini kanıtlamalıdır. Kaynak: Mass.gov RMV CDL ve kimlik gereklilikleri."},"96":{"q":"Massachusetts CDL genel bilgi yazılı sınavında, hangi geçer not gereklidir?","options":["En az %80 doğru","En az %60 doğru","En az %70 doğru","Tam %100 doğru"],"explanation":"Genel bilgi sınavı dahil Massachusetts CDL bilgi sınavları, en az %80 doğru geçer not gerektirir. Kaynak: Massachusetts CDL Manual; Mass.gov RMV CDL test sayfaları."}},"es":{"0":{"q":"En las vías de Massachusetts, ¿cuál es el ancho máximo legal de un vehículo comercial de motor, sin incluir los espejos, las luces direccionales y ciertos dispositivos de seguridad?","options":["96 pulgadas (8 pies)","102 pulgadas (8 pies 6 pulgadas)","108 pulgadas (9 pies)","120 pulgadas (10 pies)"],"explanation":"Massachusetts limita el ancho del vehículo a 102 pulgadas (8 pies 6 pulgadas), sin contar los espejos, las luces direccionales ni ciertos dispositivos de seguridad. Fuente: MGL Chapter 90, Section 19; Manual CDL del Massachusetts RMV."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo y su carga en las carreteras de Massachusetts sin un permiso?","options":["13 pies","13 pies 6 pulgadas","14 pies","14 pies 6 pulgadas"],"explanation":"Massachusetts establece la altura máxima del vehículo y la carga en 13 pies 6 pulgadas. Los vehículos de más de 10 pies de alto deben mostrar su altura. Fuente: MGL Chapter 90, Section 19; límites de altura de camiones comerciales de MassDOT."},"2":{"q":"Sin un permiso especial, ¿cuál es la longitud máxima de un semirremolque en una combinación de tractocamión con semirremolque en Massachusetts?","options":["48 pies","53 pies","57 pies","60 pies"],"explanation":"Un semirremolque en una unidad de tractocamión con semirremolque puede tener hasta 53 pies de longitud en Massachusetts. Fuente: MGL Chapter 90, Section 19; Manual CDL del Massachusetts RMV."},"3":{"q":"¿Cuál es el peso bruto vehicular máximo permitido en las vías de Massachusetts, sin un permiso, para un vehículo con tres o más ejes?","options":["73,280 libras","80,000 libras","88,000 libras","99,000 libras"],"explanation":"Massachusetts limita el peso bruto vehicular a 80,000 libras para vehículos con tres o más ejes, lo que coincide con el máximo federal interestatal. Fuente: MGL Chapter 90, Section 19A."},"4":{"q":"¿Cuál es el peso máximo que Massachusetts permite en un eje sencillo sin un permiso de sobrepeso?","options":["18,000 libras","20,000 libras","22,400 libras","24,000 libras"],"explanation":"Massachusetts permite hasta 22,400 libras en un eje sencillo, lo cual es más alto que el límite federal interestatal de 20,000 libras. Fuente: MGL Chapter 90, Section 19A."},"5":{"q":"¿Cuál es el peso máximo que Massachusetts permite en un eje tándem (dos ejes) sin un permiso de sobrepeso?","options":["32,000 libras","34,000 libras","36,000 libras","40,000 libras"],"explanation":"Massachusetts establece el límite del eje tándem en 34,000 libras, en consonancia con el estándar federal. Fuente: MGL Chapter 90, Section 19A."},"6":{"q":"En Massachusetts, ¿cuál es la altura máxima de un camión rígido (de una sola unidad) antes de que se requiera que el vehículo muestre marcas de altura?","options":["8 pies","10 pies","12 pies","13 pies 6 pulgadas"],"explanation":"Massachusetts exige que los vehículos de más de 10 pies de alto muestren su altura mediante marcas, aunque la altura máxima legal es de 13 pies 6 pulgadas. Fuente: MGL Chapter 90, Section 19."},"7":{"q":"¿Qué agencia de Massachusetts emite los permisos de dimensiones excesivas y sobrepeso para circular por las carreteras estatales?","options":["El Registry of Motor Vehicles (RMV)","La MassDOT Highway Division","La Massachusetts State Police","La Federal Motor Carrier Safety Administration"],"explanation":"Los permisos de dimensiones excesivas/sobrepeso para las carreteras estatales son emitidos por la MassDOT Highway Division a través de su Truck Permit Office. Fuente: Mass.gov Commercial Truck Permits; MassDOT."},"8":{"q":"¿Cuál es el nombre del sistema en línea de MassDOT que se usa para solicitar permisos de camiones comerciales de dimensiones excesivas/sobrepeso y el enrutamiento?","options":["ATLAS","OASIS","PRISM","UCR"],"explanation":"La aplicación web de MassDOT para permisos y enrutamiento de dimensiones excesivas/sobrepeso (Oversize/Overweight Permitting and Routing Application) se llama OASIS, y se utiliza para solicitar permisos de camiones comerciales. Fuente: MassDOT Highway Division; Mass.gov."},"9":{"q":"¿Cuándo se requiere que un vehículo obtenga un permiso de dimensiones excesivas/sobrepeso de MassDOT?","options":["Solo al cruzar una línea estatal","Cada vez que excede los límites legales de ancho, altura, longitud o peso","Solo cuando transporta materiales peligrosos","Solo cuando viaja de noche"],"explanation":"Se requiere un permiso cada vez que un vehículo o carga excede los límites legales de ancho (102 in), altura (13'6\"), longitud o peso (80,000 lb). Fuente: MGL Chapter 90, Section 19/19A; MassDOT."},"10":{"q":"Massachusetts aplica la Fórmula del Puente (Bridge Formula) federal al peso sobre un grupo de dos o más ejes consecutivos. ¿Cuál es el multiplicador constante que se usa en esa fórmula, W = 500[LN/(N-1) + 12N + 36]?","options":["100","250","500","1,000"],"explanation":"La Bridge Formula federal adoptada en Massachusetts usa la constante 500: W = 500[LN/(N-1) + 12N + 36], donde L es la distancia entre ejes y N es el número de ejes. Fuente: MGL Chapter 90, Section 19A; FHWA Bridge Formula."},"11":{"q":"En la Bridge Formula federal que se usa en Massachusetts, ¿qué representa la variable 'L'?","options":["El peso legal de la carga en libras","La distancia en pies entre los ejes extremos (exteriores) del grupo","El ancho del carril de la carretera","La longitud del remolque en pies"],"explanation":"En W = 500[LN/(N-1) + 12N + 36], 'L' es la distancia en pies entre los ejes extremos de cualquier grupo de dos o más ejes consecutivos. Fuente: MGL Chapter 90, Section 19A; FHWA Bridge Formula."},"12":{"q":"¿Cuál es el peso bruto máximo que Massachusetts permite en un vehículo con solo dos ejes, sin un permiso?","options":["34,000 libras","40,000 libras","46,000 libras","54,000 libras"],"explanation":"Un vehículo de dos ejes está limitado a 46,000 libras de peso bruto en Massachusetts, mientras que los vehículos de tres o más ejes pueden alcanzar las 80,000 libras. Fuente: MGL Chapter 90, Section 19A."},"13":{"q":"En Massachusetts, si dos ejes sencillos están separados por menos de 6 pies, ¿cuál es el peso máximo permitido en cada uno de esos ejes?","options":["16,000 libras","18,000 libras","20,000 libras","22,400 libras"],"explanation":"Cuando los ejes están separados por menos de 6 pies, la tolerancia por eje sencillo baja de 22,400 libras a 18,000 libras cada uno. Fuente: MGL Chapter 90, Section 19A."},"14":{"q":"¿Cómo se comparan los límites máximos de ancho y altura de Massachusetts en las carreteras interestatales (Interstate) con los de otras carreteras estatales?","options":["Los límites de ancho y altura son los mismos (102 in de ancho, 13'6\" de alto) en ambas","Las interestatales permiten un ancho mayor de 8'6\", pero las demás carreteras solo 8'","Las interestatales permiten 14 pies de altura, pero las demás carreteras solo 13'6\"","Las demás carreteras estatales permiten vehículos más anchos que las interestatales"],"explanation":"Los límites de 102 pulgadas de ancho y 13 pies 6 pulgadas de alto se aplican de manera uniforme tanto en la red interestatal/nacional (Interstate/National Network) como en las demás carreteras estatales de Massachusetts. Fuente: MGL Chapter 90, Section 19; resumen de dimensiones/peso de MA de J.J. Keller."},"15":{"q":"En comparación con el límite federal interestatal de eje sencillo, la tolerancia de eje sencillo de Massachusetts es:","options":["Menor (Massachusetts permite 18,000 lb frente a las 20,000 lb federales)","Igual (ambas de 20,000 lb)","Mayor (Massachusetts permite 22,400 lb frente a las 20,000 lb federales)","Ilimitada en las carreteras estatales"],"explanation":"Massachusetts permite 22,400 libras en un eje sencillo, lo cual es más alto que el estándar federal interestatal de 20,000 libras. Fuente: MGL Chapter 90, Section 19A."},"16":{"q":"Sin un permiso, ¿cuál es la longitud máxima de un camión rígido (de una sola unidad) en Massachusetts?","options":["33 pies","40 pies","45 pies","53 pies"],"explanation":"Un camión rígido (de una sola unidad) puede tener hasta 40 pies de longitud en Massachusetts; un semirremolque en una combinación puede tener hasta 53 pies. Fuente: MGL Chapter 90, Section 19."},"17":{"q":"Un transportista necesita mover una carga de 14 pies de ancho por una carretera estatal de Massachusetts. ¿Qué debe hacer el transportista?","options":["Nada, porque 14 pies está dentro del límite legal de ancho","Obtener un permiso de dimensiones excesivas de la MassDOT Highway Division antes de viajar","Notificar únicamente al departamento de policía local","Solicitar un endoso de CDL"],"explanation":"Con 14 pies de ancho, la carga excede el ancho legal de 102 pulgadas (8'6\"), por lo que se debe obtener un permiso de dimensiones excesivas de la MassDOT Highway Division (a través de OASIS) antes de viajar. Fuente: MGL Chapter 90, Section 19; MassDOT."},"18":{"q":"Según la ley de Massachusetts, ¿cuál es la longitud total máxima legal para un tractor con remolques gemelos/tándem (cada remolque en su longitud legal)?","options":["Cada remolque hasta 28 pies, sin límite de longitud total de la combinación cuando los remolques son legales","Un límite total fijo de 65 pies sin importar la longitud del remolque","Un límite total fijo de 53 pies","Los remolques gemelos están prohibidos en Massachusetts"],"explanation":"En una combinación de tractor con remolques gemelos, cada remolque (unidad tándem) puede tener hasta 28 pies, y no hay límite de longitud total de la combinación cuando los remolques son legales. Fuente: MGL Chapter 90, Section 19; resumen de dimensiones/peso de MA de J.J. Keller."},"19":{"q":"En Massachusetts, ¿qué clase de CDL se requiere para operar un solo vehículo con una clasificación de peso bruto vehicular (GVWR) de 26,001 lbs. o más que NO está remolcando un remolque de más de 10,000 lbs.?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Massachusetts requiere una CDL Clase B para operar cualquier vehículo individual con un GVWR de 26,001 lbs. o más, o uno de esos vehículos que remolque un remolque que no supere las 10,000 lbs. (por ejemplo, camiones de caja, camiones volquete, camiones rígidos). Fuente: Mass.gov 'CDL classes and endorsements' y el Manual CDL de Massachusetts (RMV)."},"20":{"q":"Un conductor de Massachusetts quiere conducir una combinación de tractocamión con remolque con una clasificación de peso bruto combinado de 80,000 lbs. donde el remolque remolcado tiene una clasificación de más de 10,000 lbs. ¿Qué clase de CDL se requiere?","options":["Clase B","Clase C","Clase A","Clase D"],"explanation":"Se requiere una CDL Clase A en Massachusetts para cualquier combinación de vehículos con un GCWR de 26,001 lbs. o más donde la(s) unidad(es) remolcada(s) superen las 10,000 lbs. de GVWR. Fuente: Mass.gov 'CDL classes and endorsements' y el Manual CDL de Massachusetts (RMV)."},"21":{"q":"Según las reglas de Massachusetts, un vehículo que no alcanza los umbrales de peso de Clase A o B, pero que está diseñado para transportar 16 o más pasajeros (incluido el conductor) o para transportar materiales peligrosos que requieren placas (placarded), ¿qué clase de CDL requiere?","options":["Clase C","Clase A","Clase B","Clase M"],"explanation":"Massachusetts requiere una CDL Clase C para un vehículo que no califica como Clase A o B, pero que está diseñado para transportar 16 o más personas (incluido el conductor) o que se usa para transportar materiales peligrosos que requieren placas (placards). Fuente: Mass.gov 'CDL classes and endorsements' y el Manual CDL de Massachusetts (RMV)."},"22":{"q":"¿Cuál es la edad mínima para obtener una CDL o un Permiso de Aprendizaje Comercial (Commercial Learner's Permit) de Massachusetts restringido al comercio INTRAESTATAL (solo dentro de Massachusetts)?","options":["16 años","17 años","18 años","21 años"],"explanation":"Massachusetts exige que los solicitantes tengan al menos 18 años para una CDL/CLP intraestatal (solo dentro de Massachusetts). Conducir en comercio interestatal requiere tener 21 años. Fuente: Mass.gov 'Apply for a Commercial Learner's Permit (CLP)' (RMV)."},"23":{"q":"¿Cuál es la edad mínima requerida para conducir un vehículo comercial de motor en comercio INTERESTATAL con una CDL de Massachusetts?","options":["18 años","19 años","20 años","21 años"],"explanation":"Un conductor debe tener al menos 21 años para operar un CMV cruzando líneas estatales (comercio interestatal). Los conductores de 18 a 20 años están limitados a la operación intraestatal (solo dentro de Massachusetts). Fuente: páginas de CLP/CDL del RMV en Mass.gov, en consonancia con 49 CFR 391.11."},"24":{"q":"¿Qué código de endoso se requiere en una CDL de Massachusetts para conducir un vehículo diseñado para transportar pasajeros, como un autobús grande?","options":["Código N","Código P","Código T","Código H"],"explanation":"El endoso de Pasajeros (P) se requiere en Massachusetts para operar un vehículo diseñado para transportar pasajeros (por ejemplo, autobuses). Requiere aprobar un examen de conocimientos y un examen de habilidades en un vehículo representativo. Fuente: Mass.gov 'CDL classes and endorsements' y el Manual CDL de Massachusetts (RMV)."},"25":{"q":"¿Qué endoso de CDL se requiere para transportar materiales peligrosos en cantidades que requieren placas (placards) en Massachusetts?","options":["N (Tanque)","T (Dobles/Triples)","H (Materiales Peligrosos)","S (Autobús Escolar)"],"explanation":"El endoso H (Materiales Peligrosos) se requiere para transportar cantidades de materiales peligrosos que requieren placas. Requiere un examen de conocimientos, una evaluación de amenazas de seguridad de la TSA y la capacitación teórica de ELDT para los solicitantes que lo tramitan por primera vez. Fuente: Mass.gov 'CDL classes and endorsements' y el programa de endoso de HazMat de la TSA."},"26":{"q":"En Massachusetts, ¿qué endoso se requiere para remolcar remolques dobles o triples?","options":["Endoso T","Endoso N","Endoso X","Endoso P"],"explanation":"El endoso T (Dobles/Triples) se requiere para remolcar más de un remolque. Se obtiene aprobando únicamente un examen de conocimientos (sin un examen de habilidades por separado). Fuente: Mass.gov 'CDL classes and endorsements' y el Manual CDL de Massachusetts (RMV)."},"27":{"q":"¿Qué endoso necesita un titular de una CDL de Massachusetts para conducir un vehículo cisterna que transporta una carga líquida o gaseosa?","options":["Endoso H","Endoso T","Endoso N","Endoso S"],"explanation":"El endoso N (Vehículo Cisterna) se requiere para operar un vehículo cisterna diseñado para transportar líquidos o gases a granel. Se obtiene aprobando el examen de conocimientos de vehículo cisterna. Fuente: Mass.gov 'CDL classes and endorsements' y el Manual CDL de Massachusetts (RMV)."},"28":{"q":"En Massachusetts, ¿qué endoso debe tener ya un conductor (como requisito previo) antes de obtener el endoso de Autobús Escolar (S)?","options":["H (Materiales Peligrosos)","P (Pasajeros)","N (Vehículo Cisterna)","T (Dobles/Triples)"],"explanation":"Massachusetts exige el endoso de Pasajeros (P) como requisito previo para obtener el endoso de Autobús Escolar (S). Un conductor debe aprobar los exámenes de conocimientos P y S y el examen de habilidades de autobús escolar. Fuente: Mass.gov 'CDL classes and endorsements' y 'Apply for a school bus learner's permit' (RMV)."},"29":{"q":"Según las reglas federales aplicadas por el Massachusetts RMV, ¿cuánto tiempo debe tener un solicitante un Permiso de Aprendizaje Comercial antes de ser elegible para presentar el examen de habilidades (de manejo) de la CDL?","options":["Al menos 7 días","Al menos 14 días","Al menos 30 días","Al menos 60 días"],"explanation":"La regulación federal (49 CFR 383.25), aplicada por el Massachusetts RMV, exige que la CLP se tenga durante al menos 14 días antes de que el solicitante pueda presentar el examen de habilidades. El conteo comienza el día en que se emite el permiso. Fuente: página de CLP del RMV en Mass.gov y FMCSA 49 CFR 383.25."},"30":{"q":"¿Cuánto tiempo es válido un Permiso de Aprendizaje Comercial (CLP) de Massachusetts antes de que deba renovarse o de que se complete el examen de habilidades?","options":["90 días","180 días","1 año","2 años"],"explanation":"Una CLP de Massachusetts es válida por 180 días. Puede renovarse una vez por 180 días adicionales sin volver a presentar el examen de conocimientos generales, en consonancia con los límites federales. Fuente: Mass.gov 'Apply for a Commercial Learner's Permit (CLP)' (RMV)."},"31":{"q":"Mientras conduce con un Permiso de Aprendizaje Comercial de Massachusetts, el titular de la CLP debe ir acompañado de una persona que:","options":["Tenga al menos 25 años con cualquier licencia de conducir","Tenga una CDL válida de la clase y los endosos apropiados, sentada junto al conductor","Sea únicamente un instructor de manejo certificado","Tenga al menos 5 años de experiencia en conducción comercial"],"explanation":"Un titular de una CLP solo puede operar un CMV cuando va acompañado de una persona que tenga una CDL válida con la clase y los endosos apropiados, sentada en el asiento delantero junto al conductor. Fuente: página de CLP del RMV en Mass.gov y 49 CFR 383.25."},"32":{"q":"¿Qué combinación de documentos debe presentar un solicitante al Massachusetts RMV para establecer la elegibilidad para una CDL o CLP?","options":["Prueba de identidad/presencia legal, número de Seguro Social y residencia en Massachusetts","Solo una tarjeta de Seguro Social","Solo un pasaporte vigente","Un diploma de escuela secundaria y prueba de residencia"],"explanation":"El Massachusetts RMV exige prueba de identidad y presencia legal en los EE. UU., un número de Seguro Social y prueba de residencia en Massachusetts para emitir una CLP/CDL. Fuente: requisitos de solicitud de CDL/CLP del RMV en Mass.gov y 49 CFR 383.71."},"33":{"q":"La Capacitación para Conductores Principiantes (ELDT) requerida antes del examen de habilidades de la CDL Clase A de Massachusetts por primera vez debe completarse con un proveedor que esté:","options":["Aprobado únicamente por el Massachusetts RMV","Incluido en el Registro de Proveedores de Capacitación (TPR) de la FMCSA","Certificado por el U.S. Department of Education","Cualquier escuela de manejo con licencia de Massachusetts"],"explanation":"El ELDT debe completarse con un proveedor incluido en el Registro de Proveedores de Capacitación (TPR) de la FMCSA. Solo los proveedores registrados en el TPR pueden impartir la capacitación teórica y de manejo requerida. Fuente: guía 'Entry-Level Driver Training (ELDT)' de Mass.gov y FMCSA TPR (49 CFR Part 380)."},"34":{"q":"Para un endoso de Materiales Peligrosos (H) por primera vez en Massachusetts, ¿qué tipo de ELDT debe completarse y cuándo?","options":["Solo capacitación teórica, antes de presentar el examen de conocimientos","Solo capacitación de manejo, antes del examen de habilidades","Tanto teórica como de manejo, antes del examen de manejo","No se requiere ELDT para el endoso H"],"explanation":"Para el endoso H, el ELDT consiste únicamente en instrucción teórica y debe completarse antes de presentar el examen estatal de conocimientos de HazMat. No hay un examen de habilidades por separado para el endoso H. Fuente: guía de ELDT de Mass.gov y FMCSA TPR (49 CFR Part 380)."},"35":{"q":"Un conductor de Massachusetts que opera únicamente dentro de Massachusetts y que debe cumplir con los requisitos estatales de calificación médica debe autocertificarse bajo qué categoría?","options":["No Exceptuado Interestatal (NI)","Exceptuado Interestatal (EI)","No Exceptuado Intraestatal (NA)","Exceptuado Intraestatal (EA)"],"explanation":"No Exceptuado Intraestatal (NA) se aplica a los conductores que operan únicamente en comercio intraestatal y que deben cumplir con los estándares médicos/de calificación del conductor de Massachusetts y tener un certificado de examinador médico. Fuente: Mass.gov 'CDL Self-Certification' (RMV) y 49 CFR 383.71."},"36":{"q":"Un conductor que se autocertifica como No Exceptuado Interestatal (NI) en Massachusetts debe mantener archivado con el RMV un certificado médico válido de un examinador que esté:","options":["Cualquier médico con licencia en Massachusetts","Incluido en el National Registry of Certified Medical Examiners de la FMCSA","Aprobado por el empleador del conductor","Un examinador del personal del Massachusetts RMV"],"explanation":"Los conductores No Exceptuados Interestatales deben aprobar un examen físico del DOT realizado por un examinador médico incluido en el National Registry of Certified Medical Examiners de la FMCSA y mantener vigente el certificado médico con el RMV. Fuente: Mass.gov 'Medical standards for CDL' y 49 CFR 391.41-391.43."},"37":{"q":"Además de completar la teoría de ELDT y aprobar el examen de conocimientos, el endoso de Materiales Peligrosos (H) en Massachusetts también requiere que el solicitante:","options":["Complete un examen de manejo para cargas peligrosas","Apruebe una evaluación de amenazas de seguridad de la TSA que incluye la toma de huellas dactilares","Tenga primero un endoso de Tanque (N)","Tenga al menos 25 años de edad"],"explanation":"El endoso H requiere una evaluación de amenazas de seguridad de la TSA, que incluye presentar huellas dactilares y datos biográficos y someterse a una verificación criminal/de inmigración/de lista de vigilancia de terroristas, además del examen de conocimientos y la teoría de ELDT. Fuente: Mass.gov 'CDL classes and endorsements' y el programa de endoso de HazMat de la TSA (49 CFR 1572)."},"38":{"q":"¿Qué grupo de conductores está sujeto a los requisitos de Capacitación para Conductores Principiantes (ELDT) en Massachusetts?","options":["Solo los conductores que renuevan una CDL existente","Los conductores que obtienen una CDL Clase A o B por primera vez, que ascienden de Clase B a Clase A, o que obtienen un endoso S, P o H por primera vez","Solo los conductores de otro estado que transfieren una CDL","Solo los conductores mayores de 21 años"],"explanation":"El ELDT se aplica a los solicitantes que obtienen una CDL Clase A o B por primera vez, que ascienden de Clase B a Clase A, o que obtienen un endoso de autobús escolar (S), de pasajeros (P) o de materiales peligrosos (H) por primera vez. Fuente: guía 'Entry-Level Driver Training (ELDT)' de Mass.gov y FMCSA TPR (49 CFR Part 380)."},"39":{"q":"En Massachusetts, ¿cuál es la concentración máxima de alcohol en sangre (BAC) con la que una persona puede operar legalmente un vehículo comercial de motor (CMV)?","options":["0.08","0.04","0.02","0.00"],"explanation":"Massachusetts sigue el estándar federal: operar un CMV con un BAC de 0.04 o más es una infracción mayor y una violación que conlleva descalificación. El límite de 0.08 se aplica a los conductores no comerciales. Fuente: Manual CDL del MA RMV, Section 1 (Disqualifications); 49 CFR 383.51."},"40":{"q":"Según las reglas de CDL de Massachusetts, ¿por cuánto tiempo se descalifica a un conductor que opera un CMV con un BAC de 0.04 o más por una PRIMERA infracción mayor (y que no transporta materiales peligrosos con placas)?","options":["60 días","90 días","1 año","3 años"],"explanation":"Una primera infracción mayor, como conducir un CMV con un BAC de 0.04 o más, resulta en una descalificación mínima de 1 año (3 años si se transportan materiales peligrosos con placas). Fuente: Manual CDL del MA RMV; M.G.L. c. 90F; 49 CFR 383.51."},"41":{"q":"En Massachusetts, si un conductor de CDL comete una primera infracción mayor mientras opera un CMV que transporta materiales peligrosos con placas, el período de descalificación aumenta a:","options":["1 año","2 años","3 años","5 años"],"explanation":"Cuando una primera infracción mayor ocurre mientras el CMV lleva placas de materiales peligrosos, la descalificación aumenta de 1 año a 3 años. Fuente: Manual CDL del MA RMV (Disqualifications); 49 CFR 383.51(b)."},"42":{"q":"¿Cuál es el período de descalificación de la CDL de Massachusetts por una SEGUNDA infracción mayor (como un segundo OUI o una segunda negativa), derivada de incidentes separados?","options":["3 años","10 años","De por vida","5 años"],"explanation":"Una segunda infracción mayor, en cualquier combinación y derivada de incidentes separados, resulta en una descalificación de por vida de la CDL. Fuente: Manual CDL del MA RMV; M.G.L. c. 90F; 49 CFR 383.51(b)."},"43":{"q":"En Massachusetts, bajo la regla de consentimiento implícito, un conductor de CDL que se NIEGA a someterse a una prueba de alcohol (química) requerida mientras opera un CMV se considera que ha cometido:","options":["Una violación de tránsito grave (descalificación de 60 días)","Una violación menor con solo una multa","Una infracción mayor (descalificación de 1 año, 3 años si es hazmat)","Una violación de cruce de ferrocarril"],"explanation":"Al operar un CMV, un conductor otorga su consentimiento implícito a las pruebas de alcohol. Negarse a la prueba es una infracción mayor que conlleva la misma sanción que conducir bajo los efectos del alcohol: descalificación de 1 año (3 años si lleva placas de hazmat), y de por vida por una segunda ocurrencia. Fuente: Manual CDL del MA RMV; 49 CFR 383.51(b); M.G.L. c. 90F."},"44":{"q":"¿Cuántas violaciones de tránsito GRAVES dentro de un período de 3 años (en incidentes separados) provocan una descalificación de la CDL de 60 días en Massachusetts?","options":["1","2","3","4"],"explanation":"Una segunda violación de tránsito grave dentro de un período de 3 años resulta en una descalificación de 60 días; una tercera dentro de 3 años resulta en 120 días. Una sola violación grave por sí misma no descalifica. Fuente: Manual CDL del MA RMV; 49 CFR 383.51(c)."},"45":{"q":"En Massachusetts, TRES violaciones de tránsito graves cometidas dentro de un período de 3 años resultan en una descalificación de la CDL de:","options":["60 días","90 días","120 días","180 días"],"explanation":"Una tercera violación de tránsito grave dentro de un período de 3 años resulta en una descalificación de 120 días (una segunda dentro de 3 años es de 60 días). Fuente: Manual CDL del MA RMV; 49 CFR 383.51(c)."},"46":{"q":"¿Cuál de las siguientes se clasifica como una violación de tránsito GRAVE para un conductor de CDL de Massachusetts?","options":["Conducir un CMV con un BAC de 0.04 o más","Negarse a una prueba de alcohol","Conducir a 15 mph o más por encima del límite de velocidad indicado","Conducir un CMV mientras su CDL está suspendida"],"explanation":"Exceder el límite de velocidad en 15 mph o más es una violación de tránsito grave. Conducir con un BAC de 0.04+, negarse a una prueba y conducir con una CDL suspendida son todas infracciones MAYORES, no violaciones graves. Fuente: Manual CDL del MA RMV; 49 CFR 383.51(c)."},"47":{"q":"Según las reglas de CDL de Massachusetts, violar una ley que prohíbe ENVIAR MENSAJES DE TEXTO mientras se conduce un CMV se clasifica como:","options":["Una infracción mayor","Una violación de tránsito grave","Una violación de una orden de fuera de servicio","Una violación de cruce de ferrocarril"],"explanation":"Enviar mensajes de texto mientras se conduce un CMV es una violación de tránsito grave; acumular dos dentro de 3 años causa una descalificación de 60 días, y tres dentro de 3 años causa 120 días. Fuente: Manual CDL del MA RMV; 49 CFR 383.51(c); M.G.L. c. 90 sec. 13B."},"48":{"q":"Usar un teléfono móvil DE MANO mientras se conduce un CMV, para fines de descalificación de la CDL de Massachusetts, se considera:","options":["Una violación de tránsito grave","Una infracción mayor","Una violación de fuera de servicio","No es una violación que conlleve descalificación"],"explanation":"Usar un teléfono de mano mientras se conduce un CMV es una violación de tránsito grave que cuenta para los umbrales de descalificación de 2 en 3 años (60 días) y 3 en 3 años (120 días). Fuente: Manual CDL del MA RMV; 49 CFR 383.51(c); M.G.L. c. 90 sec. 13B."},"49":{"q":"Según la Ley de Manos Libres de Massachusetts (M.G.L. c. 90 sec. 13B), la multa por una PRIMERA infracción de dispositivo de mano es:","options":["$35","$100","$250","$500"],"explanation":"La Ley de Manos Libres de Massachusetts establece multas de $100 por una primera infracción, $250 por una segunda y $500 por una tercera o posterior, con la obligación de un programa de conducción distraída para los infractores reincidentes. Fuente: M.G.L. c. 90 sec. 13B."},"50":{"q":"Según la Ley de Manos Libres de Massachusetts, la multa por una TERCERA infracción de dispositivo de mano o posterior es:","options":["$100","$250","$500","$1,000"],"explanation":"Las multas aumentan a $500 por una tercera infracción o posterior ($100 la primera, $250 la segunda). Una segunda infracción o posterior también requiere completar un programa de conducción distraída. Fuente: M.G.L. c. 90 sec. 13B."},"51":{"q":"¿Cuál es el período de descalificación por una PRIMERA violación de cruce a nivel entre ferrocarril y carretera cometida por un conductor de CDL de Massachusetts?","options":["No menos de 30 días","No menos de 60 días","No menos de 120 días","No menos de 1 año"],"explanation":"Una primera violación de cruce a nivel entre ferrocarril y carretera resulta en una descalificación de no menos de 60 días. Fuente: Manual CDL del MA RMV; 49 CFR 383.51(d)."},"52":{"q":"Para un conductor de CDL de Massachusetts, una SEGUNDA violación de cruce a nivel entre ferrocarril y carretera dentro de un período de 3 años resulta en una descalificación de:","options":["No menos de 60 días","No menos de 120 días","No menos de 1 año","No menos de 3 años"],"explanation":"Una segunda violación de cruce de ferrocarril dentro de 3 años resulta en una descalificación de no menos de 120 días (la primera es de 60 días, la tercera dentro de 3 años es de no menos de 1 año). Fuente: Manual CDL del MA RMV; 49 CFR 383.51(d)."},"53":{"q":"Una TERCERA violación de cruce a nivel entre ferrocarril y carretera dentro de un período de 3 años descalifica a un conductor de CDL de Massachusetts por:","options":["No menos de 120 días","No menos de 180 días","No menos de 1 año","De por vida"],"explanation":"Tres violaciones de cruce de ferrocarril dentro de un período de 3 años resultan en una descalificación de no menos de 1 año. Fuente: Manual CDL del MA RMV; 49 CFR 383.51(d)."},"54":{"q":"En Massachusetts, una PRIMERA condena por violar una orden de fuera de servicio (OOS) de un conductor (sin hazmat, sin pasajeros) resulta en una descalificación de:","options":["No menos de 60 días","No menos de 90 días","No menos de 180 días ni más de 1 año","No menos de 1 año ni más de 5 años"],"explanation":"Una primera violación de orden de fuera de servicio resulta en una descalificación de no menos de 180 días y no más de 1 año. Fuente: Manual CDL del MA RMV; 49 CFR 383.51(e)."},"55":{"q":"Una SEGUNDA violación de orden de fuera de servicio dentro de un período de 10 años descalifica a un conductor de CDL de Massachusetts por:","options":["No menos de 180 días ni más de 1 año","No menos de 2 años ni más de 5 años","No menos de 1 año ni más de 3 años","De por vida"],"explanation":"Una segunda violación de orden de fuera de servicio dentro de 10 años resulta en una descalificación de no menos de 2 años y no más de 5 años. Fuente: Manual CDL del MA RMV; 49 CFR 383.51(e)."},"56":{"q":"Una PRIMERA violación de orden de fuera de servicio mientras se transportan materiales peligrosos con placas o se opera un vehículo diseñado para 16 o más pasajeros resulta en una descalificación de la CDL de Massachusetts de:","options":["No menos de 180 días ni más de 1 año","No menos de 180 días ni más de 2 años","No menos de 1 año ni más de 3 años","No menos de 3 años ni más de 5 años"],"explanation":"Una primera violación de fuera de servicio que involucra hazmat con placas o un vehículo de 16 o más pasajeros conlleva una sanción agravada: no menos de 180 días y no más de 2 años. Fuente: Manual CDL del MA RMV; 49 CFR 383.51(e)."},"57":{"q":"¿Cuál de las siguientes se considera una infracción MAYOR que descalifica a un conductor de CDL de Massachusetts, incluso cuando se comete en el vehículo personal (no comercial) del conductor?","options":["Seguir demasiado de cerca","Cambio de carril indebido","Abandonar la escena de un accidente","Usar un teléfono de mano"],"explanation":"Abandonar la escena de un accidente es una infracción mayor que descalifica la CDL ya sea que se cometa en un CMV o en un vehículo personal. Las demás son violaciones de tránsito graves solo cuando se cometen mientras se conduce un CMV. Fuente: Manual CDL del MA RMV; 49 CFR 383.51(b)."},"58":{"q":"Un conductor de CDL de Massachusetts que usa cualquier vehículo de motor para cometer un delito grave que involucra la fabricación, distribución o dispensación de una sustancia controlada es descalificado por:","options":["1 año","3 años","10 años","De por vida sin posibilidad de reinstauración"],"explanation":"Usar un vehículo de motor para cometer un delito grave que involucra sustancias controladas (fabricación, distribución o dispensación) resulta en una descalificación de por vida que NO está sujeta a reinstauración. Fuente: Manual CDL del MA RMV; M.G.L. c. 90F; 49 CFR 383.51(b)."},"59":{"q":"Según la ley de cruces ferroviarios de Massachusetts, un autobús escolar o un vehículo que transporta explosivos o líquidos inflamables como carga debe detenerse por completo dentro de qué zona respecto al riel más cercano?","options":["No menos de 15 feet y no más de 50 feet","No menos de 10 feet y no más de 40 feet","No menos de 5 feet y no más de 25 feet","No menos de 20 feet y no más de 75 feet"],"explanation":"Las Leyes Generales de Massachusetts c. 90, s. 15 exigen que un autobús escolar o un vehículo que transporta explosivos o líquidos inflamables como carga se detenga a no menos de 15 feet y no más de 50 feet de la vía más cercana antes de cruzar. Fuente: MGL c. 90, s. 15."},"60":{"q":"¿En cuál estatuto de Massachusetts se basa la ley 'Move Over' del estado, y cuál es el requisito básico al acercarse a un vehículo de emergencia, mantenimiento o auxilio detenido que muestra luces intermitentes?","options":["MGL c. 89, s. 7C; cámbiese a un carril no adyacente si es posible, o reduzca a una velocidad segura y razonable si no puede","MGL c. 90, s. 14; deténgase por completo hasta que se apaguen las luces","MGL c. 85, s. 2; toque la bocina y continúe a la velocidad indicada","MGL c. 90, s. 17; reduzca la velocidad a no más de 20 mph y mantenga su carril"],"explanation":"La ley Move Over de Massachusetts, MGL c. 89, s. 7C (vigente desde marzo de 2009), exige que los conductores que se acercan a un vehículo de emergencia, mantenimiento o auxilio detenido con luces intermitentes se cambien a un carril no adyacente cuando sea seguro, y si no pueden, que reduzcan a una velocidad segura y razonable. Fuente: MGL c. 89, s. 7C; Mass.gov Move Over Law."},"61":{"q":"¿Cuál es la sanción (multa) en Massachusetts por una infracción de la ley Move Over bajo la MGL c. 89, s. 7C?","options":["$100","$35","$250","$500"],"explanation":"Una infracción de la ley Move Over de Massachusetts (MGL c. 89, s. 7C) conlleva una multa de $100. Fuente: MGL c. 89, s. 7C; página de la ley Move Over de la Policía Estatal de Massachusetts."},"62":{"q":"En Massachusetts, ¿cuándo NO está obligado a detenerse un conductor que se acerca a un autobús escolar detenido con luces rojas intermitentes?","options":["Cuando se acerca desde el sentido contrario en una carretera dividida","Cuando el conductor viaja a menos de 20 mph","Cuando el conductor está a más de dos largos de auto detrás del autobús","Cuando el autobús está detenido dentro de un distrito comercial"],"explanation":"Según la MGL c. 90, s. 14, todo conductor debe detenerse antes de llegar a un autobús escolar que muestra luces rojas intermitentes, excepto cuando se acerca desde el sentido contrario en una carretera dividida. Fuente: MGL c. 90, s. 14."},"63":{"q":"¿Cuál es la multa mínima en Massachusetts por una primera infracción de no detenerse ante, o adelantar ilegalmente a, un autobús escolar detenido con luces rojas intermitentes?","options":["$250","$100","$50","$500"],"explanation":"Según la MGL c. 90, s. 14, una primera infracción de la ley de detención ante autobuses escolares conlleva una multa de al menos $250; una segunda infracción es de $500-$1,000 con una suspensión de licencia de 6 meses. Fuente: MGL c. 90, s. 14."},"64":{"q":"En una carretera dividida, recta y a nivel, ¿dónde debe colocar un conductor con CDL los tres triángulos reflectantes de emergencia después de detenerse en el acotamiento?","options":["A menos de 10 feet de la parte trasera, a unos 100 feet hacia atrás, y a unos 200 feet hacia atrás","A menos de 25 feet, a unos 75 feet, y a unos 150 feet hacia atrás","A menos de 5 feet, a unos 50 feet, y a unos 100 feet hacia atrás","A menos de 15 feet, a unos 150 feet, y a unos 300 feet hacia atrás"],"explanation":"El Manual de CDL de Massachusetts (que adopta 49 CFR 392.22) indica colocar un triángulo a menos de 10 feet de la parte trasera del vehículo, uno a unos 100 feet hacia atrás, y uno a unos 200 feet hacia atrás en una vía dividida o de un solo sentido. Fuente: Manual de CDL de Massachusetts, Conducción Segura (49 CFR 392.22)."},"65":{"q":"Si un vehículo comercial se detiene a menos de 500 feet de una colina, curva u otra obstrucción que limita la visibilidad, ¿cómo debe ajustar un conductor con CDL la colocación de los triángulos de emergencia?","options":["Mover el triángulo más alejado hacia atrás para que quede de 100 a 500 feet del vehículo, en dirección a la obstrucción, para dar más advertencia a los conductores que se acercan","Retirar todos los triángulos y depender únicamente de las luces intermitentes de cuatro vías","Colocar los tres triángulos a menos de 50 feet del vehículo para que se mantengan juntos","Colocar solo un triángulo, directamente detrás del vehículo, a no más de 10 feet de distancia"],"explanation":"Según el Manual de CDL de Massachusetts (49 CFR 392.22), si un vehículo se detiene a menos de 500 feet de una curva, la cima de una colina u otra obstrucción, el dispositivo de advertencia hacia la obstrucción debe colocarse de 100 a 500 feet del vehículo para dar al tránsito que se acerca una advertencia adecuada. Fuente: Manual de CDL de Massachusetts; 49 CFR 392.22."},"66":{"q":"En la Massachusetts Turnpike (I-90) entre el Intercambio 14 en Weston y el Intercambio 9 en Sturbridge, ¿qué carriles de circulación puede usar un vehículo comercial pesado (que no sea autobús)?","options":["Solo el carril del extremo derecho, o el siguiente carril adyacente al rebasar y adelantar","Cualquier carril, sin restricción de carril para camiones en la Turnpike","Solo el carril del extremo izquierdo para dejar libre el tránsito más lento","Solo los dos carriles más a la izquierda durante las horas de luz del día"],"explanation":"700 CMR 7.09 restringe a un vehículo comercial pesado (que no sea autobús) entre el Intercambio 14 (Weston) y el Intercambio 9 (Sturbridge) al carril de circulación del extremo derecho, o al siguiente carril adyacente solo al rebasar y adelantar, salvo en una emergencia. Fuente: 700 CMR 7.09."},"67":{"q":"¿Por qué los camiones tipo caja, camiones de mudanza y otros vehículos comerciales tienen prohibido circular por Storrow Drive y Soldiers Field Road en Boston (la causa del llamado 'Storrowing')?","options":["Son parkways del DCR 'solo para autos' con pasos elevados de poca altura libre (aproximadamente 10 feet o menos), y los camiones/autobuses están prohibidos","Tienen un peaje que solo acepta transpondedores comerciales","Están reservados para vehículos de alta ocupación durante la hora pico","Tienen un límite de velocidad para camiones demasiado bajo para la carga interestatal"],"explanation":"Storrow Drive y Soldiers Field Road son parkways del Department of Conservation and Recreation (DCR) restringidos a vehículos de pasajeros ('solo para autos'), con poca altura libre en los puentes de alrededor de 10 feet o menos; los camiones, autobuses y vehículos similares están prohibidos, y los camiones demasiado altos chocan habitualmente contra los pasos elevados. Fuente: 302 CMR 11.00; campaña Storrowing de Mass.gov / DCR."},"68":{"q":"Fuera de un distrito densamente poblado o comercial en una carretera no dividida de Massachusetts sin límite de velocidad indicado, ¿cuál es la velocidad legal por encima de la cual se presume que está excediendo el límite?","options":["40 mph","30 mph","50 mph","55 mph"],"explanation":"Según la MGL c. 90, s. 17, en una vía no dividida fuera de un distrito densamente poblado o comercial sin límite indicado, exceder las 40 mph durante al menos un cuarto de milla es evidencia prima facie de exceso de velocidad (la cifra para carretera dividida es 50 mph). Fuente: MGL c. 90, s. 17."},"69":{"q":"Dentro de un distrito densamente poblado o comercial en Massachusetts, ¿cuál es el límite de velocidad legal donde no hay ninguno indicado?","options":["30 mph","25 mph","20 mph","35 mph"],"explanation":"Según la MGL c. 90, s. 17, la velocidad legal en un distrito densamente poblado o comercial donde no se indica un límite especial es de 30 mph (un distrito densamente poblado se define como territorio donde las casas habitación están separadas, en promedio, menos de 200 feet entre sí). Fuente: MGL c. 90, s. 17."},"70":{"q":"En Massachusetts, un conductor de autobús escolar que se detiene en un cruce ferroviario debe hacer cuál de las siguientes acciones además de detenerse en la zona de 15 a 50 feet?","options":["Abrir la puerta de servicio, asegurarse de que es seguro cruzar, y luego cerrar la puerta antes de proseguir","Tocar la bocina tres veces antes de cruzar","Colocar triángulos reflectantes a cada lado de las vías","Poner la marcha más alta disponible antes de cruzar"],"explanation":"Según la MGL c. 90, s. 15, un operador de autobús escolar debe detenerse a entre 15 y 50 feet del riel más cercano, abrir la puerta de servicio, comprobar que es seguro cruzar, y luego cerrar la puerta antes de proseguir. Fuente: MGL c. 90, s. 15."},"71":{"q":"Según el Manual de CDL de Massachusetts, ¿qué debe hacer un conductor con las marchas al conducir un vehículo comercial a través de las vías del ferrocarril?","options":["Cruzar en una marcha lo suficientemente baja para poder despejar las vías sin cambiar de marcha","Subir de marcha mientras está sobre las vías para despejarlas más rápido","Poner punto muerto y cruzar las vías por inercia","Reducir de marcha en medio del cruce para disminuir la velocidad"],"explanation":"El Manual de CDL de Massachusetts indica a los conductores elegir una marcha que permita al vehículo cruzar las vías por completo sin cambiar de marcha, y no cambiar de marcha mientras se está sobre las vías. Fuente: Manual de CDL de Massachusetts, Cruces Ferroviarios (49 CFR 392.10)."},"72":{"q":"¿Cuál es el peso bruto vehicular máximo con el que un camión puede operar en Massachusetts en el sistema de carreteras federales sin un permiso de sobrepeso?","options":["80,000 pounds","73,280 pounds","99,000 pounds","100,000 pounds"],"explanation":"Massachusetts sigue el límite federal de 80,000 pounds de peso bruto vehicular sin un permiso especial; las cargas superiores a eso requieren un permiso de sobrepeso de MassDOT. Fuente: Permisos para Camiones Comerciales de MassDOT; límites federales de peso aplicados en Massachusetts."},"73":{"q":"Sin un permiso de sobredimensión, ¿cuál es el ancho máximo legal del vehículo/carga permitido en las carreteras de Massachusetts?","options":["8 feet 6 inches (102 inches)","8 feet 0 inches (96 inches)","10 feet 0 inches (120 inches)","9 feet 0 inches (108 inches)"],"explanation":"El ancho máximo legal en Massachusetts sin un permiso de sobredimensión es de 8 feet 6 inches (102 inches); las cargas más anchas requieren un permiso de sobredimensión de MassDOT. Fuente: regulaciones de sobredimensión/sobrepeso de MassDOT; Permisos para Camiones Comerciales de Mass.gov."},"74":{"q":"Sin un permiso de sobredimensión, ¿cuál es la altura máxima legal para un vehículo y su carga en las carreteras de Massachusetts?","options":["13 feet 6 inches","13 feet 0 inches","14 feet 0 inches","12 feet 6 inches"],"explanation":"Massachusetts establece la altura máxima legal en 13 feet 6 inches; las cargas más altas requieren un permiso de sobredimensión de MassDOT y pueden necesitar un estudio de ruta. Fuente: regulaciones de sobredimensión/sobrepeso de MassDOT; Permisos para Camiones Comerciales de Mass.gov."},"75":{"q":"En la Massachusetts Turnpike, ¿cómo trata a los autobuses la restricción de carril para vehículos comerciales pesados entre Weston y Sturbridge?","options":["Los autobuses están exentos de esa restricción de circular solo por el carril derecho","Los autobuses deben permanecer en el carril izquierdo en todo momento","Los autobuses están totalmente prohibidos en ese tramo","Los autobuses deben circular solo de noche"],"explanation":"Según 700 CMR 7.09, la restricción de circular solo por el carril derecho entre el Intercambio 14 (Weston) y el Intercambio 9 (Sturbridge) aplica a los vehículos comerciales pesados 'que no sean autobús', por lo que los autobuses están exentos de esa restricción en particular. Fuente: 700 CMR 7.09."},"76":{"q":"Según la ley de Massachusetts, después de que un conductor obligado a detenerse ante un autobús escolar se ha detenido, ¿cuándo puede proseguir ese conductor?","options":["Cuando las señales de advertencia rojas intermitentes del autobús se desactivan, a menos que un oficial de policía indique lo contrario","Después de esperar 10 segundos fijos sin importar las luces","Tan pronto como las luces ámbar (amarillas) del autobús comiencen a parpadear","Inmediatamente, siempre que no haya niños visibles"],"explanation":"La MGL c. 90, s. 14 exige que el conductor detenido permanezca detenido hasta que las señales rojas intermitentes del autobús escolar se desactiven, a menos que un oficial de policía le indique proseguir. Fuente: MGL c. 90, s. 14."},"77":{"q":"Según la MGL c. 90, s. 14, ¿a qué distancia mínima puede seguir un vehículo detrás de un autobús escolar en una vía pública de Massachusetts?","options":["No a menos de 100 feet","No a menos de 50 feet","No a menos de 200 feet","No a menos de 25 feet"],"explanation":"La MGL c. 90, s. 14 prohíbe operar un vehículo a menos de 100 feet detrás de un autobús escolar (excepto al rebasarlo y adelantarlo donde esté permitido). Fuente: MGL c. 90, s. 14."},"78":{"q":"¿Qué agencia emite las Licencias de Conducir Comerciales (CDL) en Massachusetts?","options":["El Registry of Motor Vehicles (RMV), parte de MassDOT","La Federal Motor Carrier Safety Administration (FMCSA)","El Departamento de Seguridad Pública de Massachusetts","La Sección de Vehículos Comerciales de la Policía Estatal de Massachusetts"],"explanation":"En Massachusetts, las CDL son emitidas por el Registry of Motor Vehicles (RMV), una división del Massachusetts Department of Transportation (MassDOT). La FMCSA establece los estándares federales pero no emite la licencia. Fuente: páginas de Licencias de Conducir Comerciales (CDL) del RMV en Mass.gov."},"79":{"q":"Antes de poder presentar cualquier examen de habilidades (de manejo) de la CDL en Massachusetts, primero debe obtener cuál documento?","options":["Un Permiso de Aprendiz Comercial (CLP)","Una CDL Clase A completa","Una autoridad federal de operación interestatal (número MC)","Un endoso de materiales peligrosos"],"explanation":"Para operar un vehículo motorizado comercial con fines de práctica y para calificar al examen de habilidades, un solicitante de Massachusetts primero debe aprobar el o los exámenes de conocimientos y obtener un Permiso de Aprendiz Comercial (CLP). Fuente: páginas de CDL del RMV en Mass.gov; 49 CFR 383."},"80":{"q":"¿Cuánto tiempo debe esperar un titular de un CLP de Massachusetts después de que se emite el CLP antes de ser elegible para presentar el examen de habilidades de la CDL?","options":["Al menos 14 days","Al menos 24 hours","Al menos 30 days","Al menos 60 days"],"explanation":"Un CLP debe mantenerse durante un mínimo de 14 days antes de que el solicitante pueda presentar el examen de habilidades de la CDL. Este es un requisito federal (49 CFR 383.37) que Massachusetts aplica. Fuente: páginas de CDL del RMV en Mass.gov; 49 CFR 383.37."},"81":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Massachusetts?","options":["180 days, renovable una vez por 180 days adicionales","30 days, sin renovación permitida","1 year, renovable dos veces","90 days, renovable una vez por 90 days adicionales"],"explanation":"Un CLP de Massachusetts es válido por 180 days y puede renovarse una vez por 180 days adicionales sin volver a presentar los exámenes de conocimientos; después de eso, el solicitante debe volver a aplicar. Fuente: páginas de CDL del RMV en Mass.gov; 49 CFR 383.25."},"82":{"q":"¿De cuáles tres partes se compone el examen de habilidades de la CDL de Massachusetts?","options":["Inspección previaje, control básico del vehículo, y manejo en carretera","Examen escrito, evaluación de la vista, y manejo en carretera","Revisión de frenos de aire, manejo de materiales peligrosos, y manejo en carretera","Acoplamiento/desacoplamiento, revisión de bitácora, y manejo en carretera"],"explanation":"El examen de habilidades de la CDL de Massachusetts tiene tres segmentos: la inspección previaje (del vehículo), el control básico del vehículo (habilidades de control como el retroceso), y el examen de manejo en carretera. Fuente: Hoja Informativa del Examen de Habilidades de la CDL del RMV en Mass.gov / Estándar Modernizado del Examen de Habilidades de la CDL."},"83":{"q":"¿Entre cuántas categorías de autocertificación debe elegir un solicitante de CDL/CLP de Massachusetts al certificar el tipo de manejo que realiza?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Las reglas federales y de Massachusetts exigen que el conductor se autocertifique en una de cuatro categorías de comercio. Fuente: 'Autocertificación de la Licencia de Conducir Comercial (CDL)' de Mass.gov; 49 CFR 383.71."},"84":{"q":"¿Cuál de las siguientes es una de las cuatro categorías de autocertificación de la CDL utilizadas en Massachusetts?","options":["Non-Excepted Interstate (NI)","Restricted Commercial (RC)","Federal Excepted Operator (FEO)","Limited Intrastate Hauler (LIH)"],"explanation":"Las cuatro categorías son Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), y Excepted Intrastate (EA). Las demás opciones no son categorías reales. Fuente: Autocertificación de la CDL de Mass.gov; 49 CFR 383.71."},"85":{"q":"Según las reglas de Massachusetts/FMCSA, un conductor que se autocertifica como 'Non-Excepted Interstate (NI)' ¿qué declaración está haciendo sobre su operación?","options":["Opera cruzando líneas estatales y debe cumplir con los requisitos federales de la tarjeta médica del DOT","Opera solo dentro de Massachusetts y no necesita certificado médico","Opera cruzando líneas estatales pero está exento de los requisitos médicos","Opera solo dentro de Massachusetts y cumple solo con las reglas médicas estatales"],"explanation":"Non-Excepted Interstate (NI) significa que el conductor opera (o espera operar) en comercio interestatal y está obligado a cumplir con los requisitos del certificado del examinador médico del DOT federal. Fuente: Autocertificación de la CDL de Mass.gov; 49 CFR 383.71/391."},"86":{"q":"Un conductor que se autocertifica como 'Excepted Intrastate (EA)' en Massachusetts está indicando cuál de las siguientes?","options":["Opera solo dentro de Massachusetts y no está obligado a cumplir con los requisitos de la tarjeta médica del DOT federal","Opera cruzando líneas estatales y debe portar una tarjeta médica federal","Opera solo dentro de Massachusetts y debe tener una tarjeta médica del DOT federal","Está restringido únicamente al transporte de materiales peligrosos"],"explanation":"Excepted Intrastate (EA) significa que el conductor opera únicamente en comercio intraestatal (dentro del estado) y está exceptuado de los requisitos de la tarjeta médica del DOT federal. Fuente: Autocertificación de la CDL de Mass.gov; 49 CFR 383.71."},"87":{"q":"Cuando un conductor con CDL de Massachusetts de tipo interestatal no exceptuado aprueba un examen físico del DOT, ¿qué documento emite el examinador médico certificado?","options":["Un Certificado del Examinador Médico (Formulario MCSA-5876)","Una exención de visión Clase D del RMV de Massachusetts","Una carta de exención federal de Horas de Servicio","Un certificado de autoridad de operación de la FMCSA"],"explanation":"Un examinador del National Registry de la FMCSA que determina que el conductor está calificado emite un Certificado del Examinador Médico (Formulario MCSA-5876). Fuente: Autocertificación de la CDL / Certificación Médica de Mass.gov; National Registry de la FMCSA."},"88":{"q":"Un examinador médico de la CDL de Massachusetts que realiza exámenes físicos del DOT debe estar incluido ¿dónde?","options":["En el FMCSA National Registry of Certified Medical Examiners","En el registro de médicos aprobados del RMV de Massachusetts","En la lista de CDL de la Junta de Registro en Medicina de Massachusetts","En la lista de proveedores de la División de Carreteras de MassDOT"],"explanation":"Los exámenes físicos del DOT para fines de la CDL deben ser realizados por un examinador médico incluido en el FMCSA National Registry of Certified Medical Examiners. Fuente: Autocertificación de la CDL de Mass.gov; National Registry de la FMCSA."},"89":{"q":"A mediados de 2025, ¿cómo llega al RMV la información de certificación médica de la mayoría de los conductores con CDL de Massachusetts?","options":["Electrónicamente desde el FMCSA National Registry, por lo que generalmente no es necesario entregar una tarjeta física","Solo si el conductor envía por correo una tarjeta física al RMV dentro de 5 days","Solo si el empleador envía la tarjeta por fax a MassDOT","Automáticamente desde la aseguradora del conductor"],"explanation":"A partir del 23 de junio de 2025, el RMV recibe la información de certificación médica electrónicamente desde el FMCSA National Registry, por lo que la mayoría de los conductores no necesitan entregar una copia física (los conductores solo intraestatales aún pueden entregar una si no se carga). Fuente: Autocertificación de la CDL de Mass.gov."},"90":{"q":"¿Qué capacitación debe completar un solicitante primerizo de Clase A o Clase B en Massachusetts antes de que el RMV programe el examen de habilidades de la CDL?","options":["Entry-Level Driver Training (ELDT) de un proveedor registrado ante la FMCSA","Un curso de manejo defensivo de 40 horas de MassDOT","Un aprendizaje estatal en un centro de servicio del RMV","Solo una orientación de seguridad vial emitida por el empleador"],"explanation":"Desde el 7 de febrero de 2022, los solicitantes primerizos de Clase A/B (y los endosos primerizos S, P o H) deben completar el Entry-Level Driver Training (ELDT) de un proveedor incluido en el FMCSA Training Provider Registry antes de que el RMV programe el examen de habilidades. Fuente: guía de ELDT de Mass.gov; 49 CFR Part 380 Subpart F."},"91":{"q":"El Entry-Level Driver Training (ELDT) requerido antes del examen de habilidades de la CDL de Massachusetts consta de cuáles dos componentes?","options":["Instrucción teórica e instrucción detrás del volante","Un examen escrito y una evaluación de la vista","Instrucción solo en aula y una verificación federal de antecedentes","Un examen médico y una prueba de detección de drogas"],"explanation":"El ELDT requiere completar exitosamente un programa prescrito de instrucción teórica y detrás del volante antes de presentar el examen de habilidades de la CDL. Fuente: guía de ELDT de Mass.gov; FMCSA 49 CFR Part 380 Subpart F."},"92":{"q":"Además de los solicitantes primerizos de Clase A/B, el ELDT también debe completarse antes de solicitar por primera vez cuál endoso?","options":["Materiales peligrosos (H), pasajeros (P), o autobús escolar (S)","Vehículo cisterna (N) únicamente","Remolques dobles/triples (T) únicamente","Frenos de aire (sin restricción)"],"explanation":"El ELDT aplica a las CDL primerizas de Clase A/B, a las actualizaciones de Clase B a A, y a los endosos primerizos de materiales peligrosos (H), pasajeros (P), y autobús escolar (S). Fuente: guía de ELDT de Mass.gov; 49 CFR Part 380."},"93":{"q":"¿Por cuánto tiempo es válida una CDL de Massachusetts antes de que deba renovarse?","options":["5 years","2 years","8 years","10 years"],"explanation":"Una CDL de Massachusetts es válida por 5 years y generalmente vence en el cumpleaños del titular. Fuente: páginas de renovación de licencia del RMV en Mass.gov."},"94":{"q":"¿Cuál es la edad mínima para obtener una CDL solo intraestatal (solo de Massachusetts), y la edad mínima para operar de forma interestatal?","options":["18 para intraestatal y 21 para interestatal","16 para intraestatal y 18 para interestatal","18 tanto para intraestatal como para interestatal","21 tanto para intraestatal como para interestatal"],"explanation":"Un solicitante debe tener al menos 18 años para obtener una CDL/CLP intraestatal (dentro de Massachusetts) y al menos 21 años para operar en comercio interestatal. Fuente: páginas de CDL del RMV en Mass.gov; 49 CFR 383.3/391.11."},"95":{"q":"Al solicitar un CLP/CDL de Massachusetts, ¿qué conjunto de documentos debe proporcionar generalmente el solicitante?","options":["Comprobante de identidad/presencia legal, un número de Seguro Social, y residencia en Massachusetts","Solo un pasaporte vigente y un registro vehicular","Solo una carta del empleador y un título del vehículo","Un acta de nacimiento y un reporte de crédito"],"explanation":"Los solicitantes de CDL de Massachusetts deben comprobar identidad/presencia legal, proporcionar un número de Seguro Social, y comprobar residencia en Massachusetts, los mismos estándares de identidad usados para otras credenciales del RMV. Fuente: requisitos de CDL e identificación del RMV en Mass.gov."},"96":{"q":"En el examen escrito de conocimientos generales de la CDL de Massachusetts, ¿qué puntaje aprobatorio se requiere?","options":["Al menos 80% correcto","Al menos 60% correcto","Al menos 70% correcto","Un perfecto 100% correcto"],"explanation":"Los exámenes de conocimientos de la CDL de Massachusetts, incluido el examen de conocimientos generales, requieren un puntaje aprobatorio de al menos 80% correcto. Fuente: Manual de CDL de Massachusetts; páginas de exámenes de CDL del RMV en Mass.gov."}},"hi":{"0":{"q":"मैसाचुसेट्स की सड़कों पर, शीशों (मिरर), टर्न सिग्नल और कुछ सुरक्षा उपकरणों को छोड़कर, किसी वाणिज्यिक मोटर वाहन की अधिकतम कानूनी चौड़ाई कितनी है?","options":["96 इंच (8 फीट)","102 इंच (8 फीट 6 इंच)","108 इंच (9 फीट)","120 इंच (10 फीट)"],"explanation":"मैसाचुसेट्स वाहन की चौड़ाई को 102 इंच (8 फीट 6 इंच) तक सीमित करता है, जिसमें शीशे, टर्न सिग्नल और कुछ सुरक्षा उपकरण शामिल नहीं हैं। स्रोत: MGL Chapter 90, Section 19; Massachusetts RMV CDL Manual।"},"1":{"q":"बिना परमिट के मैसाचुसेट्स के राजमार्गों पर किसी वाहन और उसके लदान (लोड) की अधिकतम कानूनी ऊंचाई कितनी है?","options":["13 फीट","13 फीट 6 इंच","14 फीट","14 फीट 6 इंच"],"explanation":"मैसाचुसेट्स वाहन-और-लदान की अधिकतम ऊंचाई 13 फीट 6 इंच निर्धारित करता है। 10 फीट से अधिक ऊंचे वाहनों को अपनी ऊंचाई प्रदर्शित करनी चाहिए। स्रोत: MGL Chapter 90, Section 19; MassDOT वाणिज्यिक ट्रक ऊंचाई सीमाएं।"},"2":{"q":"विशेष परमिट के बिना, मैसाचुसेट्स में ट्रैक्टर-सेमीट्रेलर संयोजन में एक सेमीट्रेलर की अधिकतम लंबाई कितनी है?","options":["48 फीट","53 फीट","57 फीट","60 फीट"],"explanation":"मैसाचुसेट्स में ट्रैक्टर-सेमीट्रेलर इकाई में एक सेमीट्रेलर 53 फीट तक लंबा हो सकता है। स्रोत: MGL Chapter 90, Section 19; Massachusetts RMV CDL Manual।"},"3":{"q":"तीन या अधिक एक्सल वाले वाहन के लिए, बिना परमिट के, मैसाचुसेट्स की सड़कों पर अनुमत अधिकतम सकल वाहन भार (gross vehicle weight) कितना है?","options":["73,280 पाउंड","80,000 पाउंड","88,000 पाउंड","99,000 पाउंड"],"explanation":"मैसाचुसेट्स तीन या अधिक एक्सल वाले वाहनों के लिए सकल वाहन भार को 80,000 पाउंड पर सीमित करता है, जो संघीय अंतरराज्यीय अधिकतम के समान है। स्रोत: MGL Chapter 90, Section 19A।"},"4":{"q":"ओवरवेट परमिट के बिना मैसाचुसेट्स एक एकल एक्सल पर अधिकतम कितना भार अनुमति देता है?","options":["18,000 पाउंड","20,000 पाउंड","22,400 पाउंड","24,000 पाउंड"],"explanation":"मैसाचुसेट्स एक एकल एक्सल पर 22,400 पाउंड तक की अनुमति देता है, जो 20,000-पाउंड के संघीय अंतरराज्यीय सीमा से अधिक है। स्रोत: MGL Chapter 90, Section 19A।"},"5":{"q":"ओवरवेट परमिट के बिना मैसाचुसेट्स एक टैंडम एक्सल (दो एक्सल) पर अधिकतम कितना भार अनुमति देता है?","options":["32,000 पाउंड","34,000 पाउंड","36,000 पाउंड","40,000 पाउंड"],"explanation":"मैसाचुसेट्स टैंडम-एक्सल सीमा को 34,000 पाउंड पर निर्धारित करता है, जो संघीय मानक के अनुरूप है। स्रोत: MGL Chapter 90, Section 19A।"},"6":{"q":"मैसाचुसेट्स में, वाहन पर ऊंचाई के चिह्न प्रदर्शित करना अनिवार्य होने से पहले एक सीधे (एकल) ट्रक की अधिकतम ऊंचाई कितनी है?","options":["8 फीट","10 फीट","12 फीट","13 फीट 6 इंच"],"explanation":"मैसाचुसेट्स में 10 फीट से अधिक ऊंचे वाहनों को अपनी ऊंचाई चिह्नों में प्रदर्शित करना आवश्यक है, भले ही कानूनी अधिकतम ऊंचाई 13 फीट 6 इंच हो। स्रोत: MGL Chapter 90, Section 19।"},"7":{"q":"मैसाचुसेट्स की कौन सी एजेंसी राज्य राजमार्गों पर यात्रा के लिए ओवरसाइज और ओवरवेट परमिट जारी करती है?","options":["The Registry of Motor Vehicles (RMV)","The MassDOT Highway Division","The Massachusetts State Police","The Federal Motor Carrier Safety Administration"],"explanation":"राज्य राजमार्गों के लिए ओवरसाइज/ओवरवेट परमिट MassDOT Highway Division द्वारा उसके Truck Permit Office के माध्यम से जारी किए जाते हैं। स्रोत: Mass.gov Commercial Truck Permits; MassDOT।"},"8":{"q":"वाणिज्यिक ओवरसाइज/ओवरवेट ट्रक परमिट और मार्ग निर्धारण का अनुरोध करने के लिए उपयोग की जाने वाली MassDOT ऑनलाइन प्रणाली का नाम क्या है?","options":["ATLAS","OASIS","PRISM","UCR"],"explanation":"MassDOT का वेब-आधारित Oversize/Overweight Permitting and Routing Application OASIS कहलाता है, जिसका उपयोग वाणिज्यिक ट्रक परमिट के लिए आवेदन करने हेतु किया जाता है। स्रोत: MassDOT Highway Division; Mass.gov।"},"9":{"q":"किसी वाहन को MassDOT ओवरसाइज/ओवरवेट परमिट प्राप्त करना कब आवश्यक होता है?","options":["केवल जब वह किसी राज्य की सीमा पार करता है","जब भी वह चौड़ाई, ऊंचाई, लंबाई या भार की कानूनी सीमाओं से अधिक हो","केवल जब वह खतरनाक सामग्री ले जा रहा हो","केवल जब वह रात में यात्रा कर रहा हो"],"explanation":"जब भी कोई वाहन या लदान चौड़ाई (102 in), ऊंचाई (13'6\"), लंबाई, या भार (80,000 lb) की कानूनी सीमाओं से अधिक होता है, तब परमिट आवश्यक होता है। स्रोत: MGL Chapter 90, Section 19/19A; MassDOT।"},"10":{"q":"मैसाचुसेट्स दो या अधिक लगातार एक्सल के समूह पर भार के लिए संघीय Bridge Formula लागू करता है। उस सूत्र W = 500[LN/(N-1) + 12N + 36] में उपयोग किया जाने वाला स्थिर गुणक (constant multiplier) क्या है?","options":["100","250","500","1,000"],"explanation":"मैसाचुसेट्स में अपनाया गया संघीय Bridge Formula स्थिरांक 500 का उपयोग करता है: W = 500[LN/(N-1) + 12N + 36], जहां L एक्सल का फैलाव है और N एक्सल की संख्या है। स्रोत: MGL Chapter 90, Section 19A; FHWA Bridge Formula।"},"11":{"q":"मैसाचुसेट्स में उपयोग किए जाने वाले संघीय Bridge Formula में, चर (variable) 'L' किसका प्रतिनिधित्व करता है?","options":["पाउंड में कानूनी लदान भार","समूह के चरम (बाहरी) एक्सल के बीच फीट में दूरी","राजमार्ग की लेन चौड़ाई","ट्रेलर की लंबाई फीट में"],"explanation":"W = 500[LN/(N-1) + 12N + 36] में, 'L' दो या अधिक लगातार एक्सल के किसी भी समूह के चरम एक्सल के बीच फीट में दूरी है। स्रोत: MGL Chapter 90, Section 19A; FHWA Bridge Formula।"},"12":{"q":"बिना परमिट के, केवल दो एक्सल वाले वाहन पर मैसाचुसेट्स अधिकतम कितना सकल भार अनुमति देता है?","options":["34,000 पाउंड","40,000 पाउंड","46,000 पाउंड","54,000 पाउंड"],"explanation":"मैसाचुसेट्स में दो-एक्सल वाला वाहन 46,000 पाउंड सकल तक सीमित है, जबकि तीन-या-अधिक-एक्सल वाले वाहन 80,000 पाउंड तक पहुंच सकते हैं। स्रोत: MGL Chapter 90, Section 19A।"},"13":{"q":"मैसाचुसेट्स में, यदि दो एकल एक्सल 6 फीट से कम दूरी पर रखे गए हैं, तो ऐसे प्रत्येक एक्सल पर अधिकतम कितना भार अनुमत है?","options":["16,000 पाउंड","18,000 पाउंड","20,000 पाउंड","22,400 पाउंड"],"explanation":"जब एक्सल 6 फीट से कम दूरी पर रखे जाते हैं, तो एकल-एक्सल भत्ता प्रत्येक के लिए 22,400 पाउंड से घटकर 18,000 पाउंड हो जाता है। स्रोत: MGL Chapter 90, Section 19A।"},"14":{"q":"इंटरस्टेट राजमार्गों पर मैसाचुसेट्स की अधिकतम चौड़ाई और ऊंचाई सीमाएं अन्य राज्य राजमार्गों पर लागू सीमाओं की तुलना में कैसी हैं?","options":["चौड़ाई और ऊंचाई सीमाएं दोनों पर समान हैं (102 in चौड़ी, 13'6\" ऊंची)","इंटरस्टेट अधिक चौड़े 8'6\" की अनुमति देते हैं लेकिन अन्य सड़कें केवल 8'","इंटरस्टेट 14 फीट ऊंचाई की अनुमति देते हैं लेकिन अन्य सड़कें केवल 13'6\"","अन्य राज्य सड़कें इंटरस्टेट की तुलना में चौड़े वाहनों की अनुमति देती हैं"],"explanation":"मैसाचुसेट्स में 102-इंच चौड़ाई और 13-फीट-6-इंच ऊंचाई सीमाएं इंटरस्टेट/National Network और अन्य राज्य राजमार्गों दोनों पर समान रूप से लागू होती हैं। स्रोत: MGL Chapter 90, Section 19; J.J. Keller MA size/weight summary।"},"15":{"q":"संघीय अंतरराज्यीय एकल-एक्सल सीमा की तुलना में, मैसाचुसेट्स का एकल-एक्सल भत्ता है:","options":["कम (मैसाचुसेट्स 18,000 lb की अनुमति देता है बनाम संघीय 20,000 lb)","समान (दोनों 20,000 lb)","अधिक (मैसाचुसेट्स 22,400 lb की अनुमति देता है बनाम संघीय 20,000 lb)","राज्य सड़कों पर असीमित"],"explanation":"मैसाचुसेट्स एक एकल एक्सल पर 22,400 पाउंड की अनुमति देता है, जो 20,000-पाउंड के संघीय अंतरराज्यीय मानक से अधिक है। स्रोत: MGL Chapter 90, Section 19A।"},"16":{"q":"बिना परमिट के, मैसाचुसेट्स में एक सीधे (एकल-इकाई) ट्रक की अधिकतम लंबाई कितनी है?","options":["33 फीट","40 फीट","45 फीट","53 फीट"],"explanation":"मैसाचुसेट्स में एक सीधा ट्रक (एकल इकाई) 40 फीट तक लंबा हो सकता है; संयोजन में एक सेमीट्रेलर 53 फीट तक हो सकता है। स्रोत: MGL Chapter 90, Section 19।"},"17":{"q":"एक कैरियर को मैसाचुसेट्स राज्य राजमार्ग पर 14 फीट चौड़ा लदान ले जाना है। कैरियर को क्या करना चाहिए?","options":["कुछ नहीं, क्योंकि 14 फीट कानूनी चौड़ाई सीमा के भीतर है","यात्रा से पहले MassDOT Highway Division से एक ओवरसाइज परमिट प्राप्त करें","केवल स्थानीय पुलिस विभाग को सूचित करें","एक CDL एंडोर्समेंट के लिए आवेदन करें"],"explanation":"14 फीट चौड़ा होने पर लदान 102-इंच (8'6\") कानूनी चौड़ाई से अधिक हो जाता है, इसलिए यात्रा से पहले MassDOT Highway Division से (OASIS के माध्यम से) एक ओवरसाइज परमिट प्राप्त करना होगा। स्रोत: MGL Chapter 90, Section 19; MassDOT।"},"18":{"q":"मैसाचुसेट्स कानून के तहत, जुड़वां/टैंडम ट्रेलर वाले ट्रैक्टर के लिए (प्रत्येक ट्रेलर अपनी कानूनी लंबाई पर) अधिकतम कानूनी कुल लंबाई कितनी है?","options":["प्रत्येक ट्रेलर 28 फीट तक, जब ट्रेलर कानूनी हों तो कोई कुल संयोजन लंबाई सीमा नहीं","ट्रेलर की लंबाई की परवाह किए बिना एक निश्चित 65-फीट कुल सीमा","एक निश्चित 53-फीट कुल सीमा","मैसाचुसेट्स में जुड़वां ट्रेलर निषिद्ध हैं"],"explanation":"ट्रैक्टर जुड़वां-ट्रेलर संयोजन में, प्रत्येक ट्रेलर (टैंडम इकाई) 28 फीट तक हो सकता है, और जब ट्रेलर कानूनी हों तो कोई कुल संयोजन लंबाई सीमा नहीं होती। स्रोत: MGL Chapter 90, Section 19; J.J. Keller MA size/weight summary।"},"19":{"q":"मैसाचुसेट्स में, 26,001 lbs. या उससे अधिक के सकल वाहन भार रेटिंग (GVWR) वाले एकल वाहन को चलाने के लिए कौन सी CDL श्रेणी आवश्यक है, जो 10,000 lbs. से अधिक के ट्रेलर को नहीं खींच रहा हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"मैसाचुसेट्स में 26,001 lbs. या उससे अधिक GVWR वाले किसी भी एकल वाहन, या 10,000 lbs. से अधिक के ट्रेलर को न खींचने वाले ऐसे वाहन (जैसे बॉक्स ट्रक, डंप ट्रक, सीधे ट्रक) को चलाने के लिए Class B CDL आवश्यक है। स्रोत: Mass.gov 'CDL classes and endorsements' और Massachusetts CDL Manual (RMV)।"},"20":{"q":"एक मैसाचुसेट्स चालक 80,000 lbs. के सकल संयोजन भार रेटिंग वाले ट्रैक्टर-ट्रेलर संयोजन को खींचना चाहता है जहां खींचा जाने वाला ट्रेलर 10,000 lbs. से अधिक रेटेड है। कौन सी CDL श्रेणी आवश्यक है?","options":["Class B","Class C","Class A","Class D"],"explanation":"मैसाचुसेट्स में किसी भी वाहन संयोजन के लिए Class A CDL आवश्यक है जिसका GCWR 26,001 lbs. या उससे अधिक हो और जहां खींची जाने वाली इकाई(याँ) 10,000 lbs. GVWR से अधिक हों। स्रोत: Mass.gov 'CDL classes and endorsements' और Massachusetts CDL Manual (RMV)।"},"21":{"q":"मैसाचुसेट्स नियमों के तहत, एक वाहन जो Class A या B भार सीमा को पूरा नहीं करता लेकिन 16 या अधिक यात्रियों (चालक सहित) को ले जाने या प्लेकार्ड वाली खतरनाक सामग्री के परिवहन के लिए डिज़ाइन किया गया है, के लिए कौन सी CDL श्रेणी आवश्यक है?","options":["Class C","Class A","Class B","Class M"],"explanation":"मैसाचुसेट्स में ऐसे वाहन के लिए Class C CDL आवश्यक है जो Class A या B के रूप में योग्य नहीं है लेकिन 16 या अधिक लोगों (चालक सहित) के परिवहन के लिए डिज़ाइन किया गया है या प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री ले जाने के लिए उपयोग किया जाता है। स्रोत: Mass.gov 'CDL classes and endorsements' और Massachusetts CDL Manual (RMV)।"},"22":{"q":"INTRASTATE (केवल-मैसाचुसेट्स) वाणिज्य तक सीमित मैसाचुसेट्स CDL या Commercial Learner's Permit प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["16 वर्ष","17 वर्ष","18 वर्ष","21 वर्ष"],"explanation":"मैसाचुसेट्स में इंट्रास्टेट (केवल-मैसाचुसेट्स) CDL/CLP के लिए आवेदकों का कम से कम 18 वर्ष का होना आवश्यक है। अंतरराज्यीय वाणिज्य में गाड़ी चलाने के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: Mass.gov 'Apply for a Commercial Learner's Permit (CLP)' (RMV)।"},"23":{"q":"मैसाचुसेट्स CDL के तहत INTERSTATE वाणिज्य में वाणिज्यिक मोटर वाहन चलाने के लिए आवश्यक न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","20 वर्ष","21 वर्ष"],"explanation":"राज्य की सीमाओं के पार (अंतरराज्यीय वाणिज्य) CMV चलाने के लिए चालक का कम से कम 21 वर्ष का होना आवश्यक है। 18-20 वर्ष के चालक इंट्रास्टेट (केवल-मैसाचुसेट्स) संचालन तक सीमित हैं। स्रोत: Mass.gov RMV CLP/CDL पृष्ठ, 49 CFR 391.11 के अनुरूप।"},"24":{"q":"बड़ी बस जैसे यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाने के लिए मैसाचुसेट्स CDL पर कौन सा एंडोर्समेंट कोड आवश्यक है?","options":["Code N","Code P","Code T","Code H"],"explanation":"मैसाचुसेट्स में यात्रियों के परिवहन के लिए डिज़ाइन किए गए वाहन (जैसे बसें) को चलाने के लिए Passenger (P) एंडोर्समेंट आवश्यक है। इसके लिए एक नॉलेज टेस्ट और एक प्रतिनिधि वाहन में स्किल्स टेस्ट पास करना आवश्यक है। स्रोत: Mass.gov 'CDL classes and endorsements' और Massachusetts CDL Manual (RMV)।"},"25":{"q":"मैसाचुसेट्स में प्लेकार्ड की आवश्यकता वाली मात्रा में खतरनाक सामग्री के परिवहन के लिए कौन सा CDL एंडोर्समेंट आवश्यक है?","options":["N (Tanker)","T (Doubles/Triples)","H (Hazardous Materials)","S (School Bus)"],"explanation":"प्लेकार्ड योग्य मात्रा में खतरनाक सामग्री ढोने के लिए H (Hazardous Materials) एंडोर्समेंट आवश्यक है। इसके लिए एक नॉलेज टेस्ट, एक TSA सुरक्षा खतरा आकलन, और पहली बार आवेदकों के लिए ELDT थ्योरी प्रशिक्षण आवश्यक है। स्रोत: Mass.gov 'CDL classes and endorsements' और TSA HazMat endorsement program।"},"26":{"q":"मैसाचुसेट्स में, दोहरे या तिहरे ट्रेलर खींचने के लिए कौन सा एंडोर्समेंट आवश्यक है?","options":["T endorsement","N endorsement","X endorsement","P endorsement"],"explanation":"एक से अधिक ट्रेलर खींचने के लिए T (Doubles/Triples) एंडोर्समेंट आवश्यक है। इसे केवल एक नॉलेज टेस्ट पास करके प्राप्त किया जाता है (कोई अलग स्किल्स टेस्ट नहीं)। स्रोत: Mass.gov 'CDL classes and endorsements' और Massachusetts CDL Manual (RMV)।"},"27":{"q":"एक तरल या गैसीय लदान ढोने वाले टैंक वाहन को चलाने के लिए मैसाचुसेट्स CDL धारक को कौन सा एंडोर्समेंट चाहिए?","options":["H endorsement","T endorsement","N endorsement","S endorsement"],"explanation":"थोक में तरल या गैस ढोने के लिए डिज़ाइन किए गए टैंक वाहन को चलाने के लिए N (Tank Vehicle) एंडोर्समेंट आवश्यक है। इसे टैंक वाहन नॉलेज टेस्ट पास करके प्राप्त किया जाता है। स्रोत: Mass.gov 'CDL classes and endorsements' और Massachusetts CDL Manual (RMV)।"},"28":{"q":"मैसाचुसेट्स में, School Bus (S) एंडोर्समेंट प्राप्त करने से पहले एक चालक को (पूर्व-शर्त के रूप में) कौन सा एंडोर्समेंट पहले से धारण करना चाहिए?","options":["H (Hazardous Materials)","P (Passenger)","N (Tank Vehicle)","T (Doubles/Triples)"],"explanation":"मैसाचुसेट्स में School Bus (S) एंडोर्समेंट अर्जित करने के लिए Passenger (P) एंडोर्समेंट को पूर्व-शर्त के रूप में आवश्यक करता है। एक चालक को P और S नॉलेज टेस्ट और स्कूल बस स्किल्स टेस्ट पास करना होगा। स्रोत: Mass.gov 'CDL classes and endorsements' और 'Apply for a school bus learner's permit' (RMV)।"},"29":{"q":"Massachusetts RMV द्वारा लागू संघीय नियमों के तहत, CDL स्किल्स (रोड) टेस्ट देने के लिए पात्र होने से पहले एक आवेदक को Commercial Learner's Permit कितने समय तक धारण करना चाहिए?","options":["कम से कम 7 दिन","कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 60 दिन"],"explanation":"संघीय विनियमन (49 CFR 383.25), जिसे Massachusetts RMV लागू करता है, के अनुसार आवेदक के स्किल्स टेस्ट देने से पहले CLP को कम से कम 14 दिन तक धारण करना आवश्यक है। घड़ी परमिट जारी होने के दिन से शुरू होती है। स्रोत: Mass.gov RMV CLP पृष्ठ और FMCSA 49 CFR 383.25।"},"30":{"q":"नवीनीकरण या स्किल्स टेस्ट पूरा करने से पहले एक मैसाचुसेट्स Commercial Learner's Permit (CLP) कितने समय तक वैध है?","options":["90 दिन","180 दिन","1 वर्ष","2 वर्ष"],"explanation":"एक मैसाचुसेट्स CLP 180 दिन के लिए वैध है। इसे संघीय सीमाओं के अनुरूप, सामान्य नॉलेज टेस्ट दोबारा दिए बिना अतिरिक्त 180 दिन के लिए एक बार नवीनीकृत किया जा सकता है। स्रोत: Mass.gov 'Apply for a Commercial Learner's Permit (CLP)' (RMV)।"},"31":{"q":"मैसाचुसेट्स Commercial Learner's Permit पर गाड़ी चलाते समय, CLP धारक के साथ एक ऐसा व्यक्ति होना चाहिए जो:","options":["किसी भी ड्राइवर लाइसेंस के साथ कम से कम 25 वर्ष का हो","उचित श्रेणी और एंडोर्समेंट का एक वैध CDL धारण करता हो, चालक के बगल में बैठा हो","केवल एक प्रमाणित ड्राइविंग प्रशिक्षक हो","कम से कम 5 वर्ष का वाणिज्यिक ड्राइविंग अनुभव हो"],"explanation":"एक CLP धारक केवल तभी CMV चला सकता है जब उसके साथ एक ऐसा व्यक्ति हो जो उपयुक्त श्रेणी और एंडोर्समेंट के साथ एक वैध CDL धारण करता हो, और जो चालक के बगल में सामने की सीट पर बैठा हो। स्रोत: Mass.gov RMV CLP पृष्ठ और 49 CFR 383.25।"},"32":{"q":"CDL या CLP के लिए पात्रता स्थापित करने हेतु एक आवेदक को Massachusetts RMV के समक्ष कौन सा दस्तावेज़ संयोजन प्रस्तुत करना चाहिए?","options":["पहचान/वैध उपस्थिति का प्रमाण, Social Security नंबर, और मैसाचुसेट्स निवास","केवल एक Social Security कार्ड","केवल एक वर्तमान पासपोर्ट","एक हाई स्कूल डिप्लोमा और निवास का प्रमाण"],"explanation":"Massachusetts RMV को CLP/CDL जारी करने के लिए पहचान और अमेरिका में वैध उपस्थिति का प्रमाण, एक Social Security नंबर, और मैसाचुसेट्स निवास का प्रमाण आवश्यक है। स्रोत: Mass.gov RMV CDL/CLP application requirements और 49 CFR 383.71।"},"33":{"q":"पहली बार मैसाचुसेट्स Class A CDL स्किल्स टेस्ट से पहले आवश्यक Entry-Level Driver Training (ELDT) एक ऐसे प्रदाता द्वारा पूरा किया जाना चाहिए जो:","options":["केवल Massachusetts RMV द्वारा अनुमोदित हो","FMCSA Training Provider Registry (TPR) पर सूचीबद्ध हो","U.S. Department of Education द्वारा प्रमाणित हो","कोई भी लाइसेंस प्राप्त मैसाचुसेट्स ड्राइविंग स्कूल"],"explanation":"ELDT FMCSA Training Provider Registry (TPR) पर सूचीबद्ध एक प्रदाता के साथ पूरा किया जाना चाहिए। केवल TPR-पंजीकृत प्रदाता ही आवश्यक थ्योरी और बिहाइंड-द-व्हील प्रशिक्षण प्रदान कर सकते हैं। स्रोत: Mass.gov 'Entry-Level Driver Training (ELDT)' guide और FMCSA TPR (49 CFR Part 380)।"},"34":{"q":"मैसाचुसेट्स में पहली बार Hazardous Materials (H) एंडोर्समेंट के लिए, किस प्रकार का ELDT पूरा किया जाना चाहिए और कब?","options":["केवल थ्योरी प्रशिक्षण, नॉलेज टेस्ट देने से पहले","केवल बिहाइंड-द-व्हील प्रशिक्षण, स्किल्स टेस्ट से पहले","थ्योरी और बिहाइंड-द-व्हील दोनों, रोड टेस्ट से पहले","H एंडोर्समेंट के लिए कोई ELDT आवश्यक नहीं है"],"explanation":"H एंडोर्समेंट के लिए, ELDT में केवल थ्योरी निर्देश शामिल होता है और इसे State HazMat नॉलेज टेस्ट देने से पहले पूरा किया जाना चाहिए। H एंडोर्समेंट के लिए कोई अलग स्किल्स टेस्ट नहीं है। स्रोत: Mass.gov ELDT guide और FMCSA TPR (49 CFR Part 380)।"},"35":{"q":"एक मैसाचुसेट्स चालक जो केवल मैसाचुसेट्स के भीतर संचालन करता है और जिसे राज्य की चिकित्सा योग्यता आवश्यकताओं को पूरा करना होगा, उसे किस श्रेणी के तहत स्व-प्रमाणन (self-certify) करना चाहिए?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Non-Excepted Intrastate (NA) उन चालकों पर लागू होता है जो केवल इंट्रास्टेट वाणिज्य में संचालन करते हैं और जिन्हें मैसाचुसेट्स के चिकित्सा/चालक-योग्यता मानकों को पूरा करना होगा और एक मेडिकल एग्जामिनर का प्रमाणपत्र धारण करना होगा। स्रोत: Mass.gov 'CDL Self-Certification' (RMV) और 49 CFR 383.71।"},"36":{"q":"एक चालक जो मैसाचुसेट्स में Non-Excepted Interstate (NI) के रूप में स्व-प्रमाणन करता है, उसे RMV के पास एक ऐसे एग्जामिनर से एक वैध मेडिकल प्रमाणपत्र फाइल पर रखना चाहिए जो:","options":["मैसाचुसेट्स में कोई भी लाइसेंस प्राप्त चिकित्सक","FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध हो","चालक के नियोक्ता द्वारा अनुमोदित हो","एक Massachusetts RMV स्टाफ एग्जामिनर"],"explanation":"Non-Excepted Interstate चालकों को FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध एक मेडिकल एग्जामिनर द्वारा किया गया DOT फिजिकल पास करना होगा और मेडिकल प्रमाणपत्र को RMV के पास वर्तमान रखना होगा। स्रोत: Mass.gov 'Medical standards for CDL' और 49 CFR 391.41-391.43।"},"37":{"q":"ELDT थ्योरी पूरा करने और नॉलेज टेस्ट पास करने के अलावा, मैसाचुसेट्स में Hazardous Materials (H) एंडोर्समेंट के लिए आवेदक को यह भी आवश्यक है कि वह:","options":["खतरनाक लदान के लिए एक बिहाइंड-द-व्हील रोड टेस्ट पूरा करे","फिंगरप्रिंटिंग सहित एक TSA सुरक्षा खतरा आकलन पास करे","पहले एक Tank (N) एंडोर्समेंट धारण करे","कम से कम 25 वर्ष की आयु का हो"],"explanation":"H एंडोर्समेंट के लिए एक TSA सुरक्षा खतरा आकलन आवश्यक है, जिसमें नॉलेज टेस्ट और ELDT थ्योरी के अतिरिक्त फिंगरप्रिंट और जीवनी संबंधी डेटा जमा करना और एक आपराधिक/आव्रजन/आतंकवादी-वॉचलिस्ट जांच से गुजरना शामिल है। स्रोत: Mass.gov 'CDL classes and endorsements' और TSA HazMat endorsement program (49 CFR 1572)।"},"38":{"q":"चालकों का कौन सा समूह मैसाचुसेट्स में Entry-Level Driver Training (ELDT) आवश्यकताओं के अधीन है?","options":["केवल मौजूदा CDL का नवीनीकरण करने वाले चालक","पहली बार Class A या B CDL प्राप्त करने वाले, Class B से Class A में अपग्रेड करने वाले, या पहली बार S, P, या H एंडोर्समेंट प्राप्त करने वाले चालक","केवल CDL स्थानांतरित करने वाले राज्य के बाहर के चालक","केवल 21 वर्ष से अधिक आयु के चालक"],"explanation":"ELDT पहली बार Class A या B CDL प्राप्त करने वाले, Class B को Class A में अपग्रेड करने वाले, या पहली बार स्कूल बस (S), passenger (P), या hazardous materials (H) एंडोर्समेंट प्राप्त करने वाले आवेदकों पर लागू होता है। स्रोत: Mass.gov 'Entry-Level Driver Training (ELDT)' guide और FMCSA TPR (49 CFR Part 380)।"},"39":{"q":"मैसाचुसेट्स में, अधिकतम रक्त अल्कोहल सांद्रता (BAC) क्या है जिस पर एक व्यक्ति कानूनी रूप से एक वाणिज्यिक मोटर वाहन (CMV) चला सकता है?","options":["0.08","0.04","0.02","0.00"],"explanation":"मैसाचुसेट्स संघीय मानक का पालन करता है: 0.04 या उससे अधिक BAC के साथ CMV चलाना एक प्रमुख अपराध और एक अयोग्यता संबंधी उल्लंघन है। 0.08 की सीमा गैर-वाणिज्यिक चालकों पर लागू होती है। स्रोत: MA RMV CDL Manual, Section 1 (Disqualifications); 49 CFR 383.51।"},"40":{"q":"मैसाचुसेट्स CDL नियमों के तहत, एक चालक जो पहले प्रमुख अपराध के लिए 0.04 या उससे अधिक BAC के साथ CMV चलाता है (और प्लेकार्ड वाली खतरनाक सामग्री नहीं ले जा रहा है) कितने समय के लिए अयोग्य घोषित किया जाता है?","options":["60 दिन","90 दिन","1 वर्ष","3 वर्ष"],"explanation":"पहला प्रमुख अपराध, जैसे 0.04 या उससे अधिक BAC के साथ CMV चलाना, न्यूनतम 1 वर्ष की अयोग्यता में परिणत होता है (यदि प्लेकार्ड वाली खतरनाक सामग्री का परिवहन कर रहे हों तो 3 वर्ष)। स्रोत: MA RMV CDL Manual; M.G.L. c. 90F; 49 CFR 383.51।"},"41":{"q":"मैसाचुसेट्स में, यदि कोई CDL चालक प्लेकार्ड वाली खतरनाक सामग्री का परिवहन करते समय CMV चलाते हुए पहला प्रमुख अपराध करता है, तो अयोग्यता अवधि बढ़ाकर कितनी कर दी जाती है:","options":["1 वर्ष","2 वर्ष","3 वर्ष","5 वर्ष"],"explanation":"जब CMV के खतरनाक सामग्री के लिए प्लेकार्ड लगे होने पर पहला प्रमुख अपराध होता है, तो अयोग्यता 1 वर्ष से बढ़ाकर 3 वर्ष कर दी जाती है। स्रोत: MA RMV CDL Manual (Disqualifications); 49 CFR 383.51(b)।"},"42":{"q":"अलग-अलग घटनाओं से उत्पन्न होने वाले दूसरे प्रमुख अपराध (जैसे दूसरा OUI या दूसरी इनकारी) के लिए मैसाचुसेट्स CDL अयोग्यता अवधि क्या है?","options":["3 वर्ष","10 वर्ष","आजीवन","5 वर्ष"],"explanation":"दूसरा प्रमुख अपराध, किसी भी संयोजन में और अलग-अलग घटनाओं से उत्पन्न होने पर, आजीवन CDL अयोग्यता में परिणत होता है। स्रोत: MA RMV CDL Manual; M.G.L. c. 90F; 49 CFR 383.51(b)।"},"43":{"q":"मैसाचुसेट्स में, अंतर्निहित-सहमति नियम (implied-consent rule) के तहत, एक CDL चालक जो CMV चलाते समय आवश्यक अल्कोहल (रासायनिक) परीक्षण कराने से इनकार करता है, उसे यह माना जाता है कि उसने किया है:","options":["एक गंभीर यातायात उल्लंघन (60-दिन की अयोग्यता)","केवल जुर्माने के साथ एक मामूली उल्लंघन","एक प्रमुख अपराध (1-वर्ष की अयोग्यता, hazmat होने पर 3 वर्ष)","एक रेलमार्ग-क्रॉसिंग उल्लंघन"],"explanation":"CMV चलाकर, एक चालक अल्कोहल परीक्षण के लिए अंतर्निहित सहमति देता है। परीक्षण से इनकार करना एक प्रमुख अपराध है जो नशे में गाड़ी चलाने के समान दंड वहन करता है: 1-वर्ष की अयोग्यता (hazmat के लिए प्लेकार्ड होने पर 3 वर्ष), और दूसरी बार होने पर आजीवन। स्रोत: MA RMV CDL Manual; 49 CFR 383.51(b); M.G.L. c. 90F।"},"44":{"q":"मैसाचुसेट्स में 3-वर्ष की अवधि के भीतर (अलग-अलग घटनाओं में) कितने गंभीर यातायात उल्लंघन 60-दिन की CDL अयोग्यता को ट्रिगर करते हैं?","options":["1","2","3","4"],"explanation":"3-वर्ष की अवधि के भीतर दूसरा गंभीर यातायात उल्लंघन 60-दिन की अयोग्यता में परिणत होता है; 3 वर्षों के भीतर तीसरा 120 दिन में परिणत होता है। अकेले एक गंभीर उल्लंघन अयोग्य नहीं ठहराता। स्रोत: MA RMV CDL Manual; 49 CFR 383.51(c)।"},"45":{"q":"मैसाचुसेट्स में, 3-वर्ष की अवधि के भीतर किए गए तीन गंभीर यातायात उल्लंघन कितनी CDL अयोग्यता में परिणत होते हैं:","options":["60 दिन","90 दिन","120 दिन","180 दिन"],"explanation":"3-वर्ष की अवधि के भीतर तीसरा गंभीर यातायात उल्लंघन 120-दिन की अयोग्यता में परिणत होता है (3 वर्षों के भीतर दूसरा 60 दिन है)। स्रोत: MA RMV CDL Manual; 49 CFR 383.51(c)।"},"46":{"q":"निम्नलिखित में से किसे एक मैसाचुसेट्स CDL चालक के लिए गंभीर यातायात उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["0.04 या उससे अधिक BAC के साथ CMV चलाना","एक अल्कोहल परीक्षण से इनकार करना","पोस्ट की गई गति सीमा से 15 mph या अधिक गति से गाड़ी चलाना","अपना CDL निलंबित होने के दौरान CMV चलाना"],"explanation":"सीमा से 15 mph या अधिक गति से गाड़ी चलाना एक गंभीर यातायात उल्लंघन है। 0.04+ BAC के साथ गाड़ी चलाना, परीक्षण से इनकार करना, और निलंबित CDL पर गाड़ी चलाना ये सभी प्रमुख अपराध हैं, गंभीर उल्लंघन नहीं। स्रोत: MA RMV CDL Manual; 49 CFR 383.51(c)।"},"47":{"q":"मैसाचुसेट्स CDL नियमों के तहत, CMV चलाते समय TEXTING पर रोक लगाने वाले कानून का उल्लंघन किस रूप में वर्गीकृत है:","options":["एक प्रमुख अपराध","एक गंभीर यातायात उल्लंघन","एक आउट-ऑफ-सर्विस ऑर्डर उल्लंघन","एक रेलमार्ग-क्रॉसिंग उल्लंघन"],"explanation":"CMV चलाते समय टेक्स्टिंग एक गंभीर यातायात उल्लंघन है; 3 वर्षों के भीतर दो जमा होने पर 60-दिन की अयोग्यता होती है, 3 वर्षों के भीतर तीन होने पर 120 दिन होते हैं। स्रोत: MA RMV CDL Manual; 49 CFR 383.51(c); M.G.L. c. 90 sec. 13B।"},"48":{"q":"CMV चलाते समय एक हैंड-हेल्ड मोबाइल टेलीफोन का उपयोग करना, मैसाचुसेट्स CDL अयोग्यता उद्देश्यों के लिए, किस रूप में माना जाता है:","options":["एक गंभीर यातायात उल्लंघन","एक प्रमुख अपराध","एक आउट-ऑफ-सर्विस उल्लंघन","अयोग्य ठहराने वाला उल्लंघन नहीं"],"explanation":"CMV चलाते समय हैंड-हेल्ड फोन का उपयोग करना एक गंभीर यातायात उल्लंघन है जो 2-इन-3-वर्ष (60 दिन) और 3-इन-3-वर्ष (120 दिन) अयोग्यता सीमाओं की ओर गिना जाता है। स्रोत: MA RMV CDL Manual; 49 CFR 383.51(c); M.G.L. c. 90 sec. 13B।"},"49":{"q":"मैसाचुसेट्स के Hands-Free Law (M.G.L. c. 90 sec. 13B) के तहत, पहले हैंडहेल्ड-डिवाइस अपराध के लिए जुर्माना है:","options":["$35","$100","$250","$500"],"explanation":"मैसाचुसेट्स Hands-Free Law पहले अपराध के लिए $100, दूसरे के लिए $250, और तीसरे या बाद के अपराध के लिए $500 का जुर्माना निर्धारित करता है, बार-बार अपराध करने वालों के लिए एक आवश्यक distracted-driving कार्यक्रम के साथ। स्रोत: M.G.L. c. 90 sec. 13B।"},"50":{"q":"मैसाचुसेट्स Hands-Free Law के तहत, तीसरे या बाद के हैंडहेल्ड-डिवाइस अपराध के लिए जुर्माना है:","options":["$100","$250","$500","$1,000"],"explanation":"जुर्माना तीसरे या बाद के अपराध के लिए बढ़कर $500 हो जाता है ($100 पहला, $250 दूसरा)। दूसरे या बाद के अपराध के लिए एक distracted-driving कार्यक्रम पूरा करना भी आवश्यक है। स्रोत: M.G.L. c. 90 sec. 13B।"},"51":{"q":"एक मैसाचुसेट्स CDL चालक द्वारा पहले रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए अयोग्यता अवधि क्या है?","options":["30 दिन से कम नहीं","60 दिन से कम नहीं","120 दिन से कम नहीं","1 वर्ष से कम नहीं"],"explanation":"पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन 60 दिन से कम नहीं की अयोग्यता में परिणत होता है। स्रोत: MA RMV CDL Manual; 49 CFR 383.51(d)।"},"52":{"q":"एक मैसाचुसेट्स CDL चालक के लिए, 3-वर्ष की अवधि के भीतर दूसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन कितनी अयोग्यता में परिणत होता है:","options":["60 दिन से कम नहीं","120 दिन से कम नहीं","1 वर्ष से कम नहीं","3 वर्ष से कम नहीं"],"explanation":"3 वर्षों के भीतर दूसरा रेलमार्ग-क्रॉसिंग उल्लंघन 120 दिन से कम नहीं की अयोग्यता में परिणत होता है (पहला 60 दिन है, 3 वर्षों के भीतर तीसरा 1 वर्ष से कम नहीं है)। स्रोत: MA RMV CDL Manual; 49 CFR 383.51(d)।"},"53":{"q":"3-वर्ष की अवधि के भीतर तीसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन एक मैसाचुसेट्स CDL चालक को कितने समय के लिए अयोग्य ठहराता है:","options":["120 दिन से कम नहीं","180 दिन से कम नहीं","1 वर्ष से कम नहीं","आजीवन"],"explanation":"3-वर्ष की अवधि के भीतर तीन रेलमार्ग-क्रॉसिंग उल्लंघन 1 वर्ष से कम नहीं की अयोग्यता में परिणत होते हैं। स्रोत: MA RMV CDL Manual; 49 CFR 383.51(d)।"},"54":{"q":"मैसाचुसेट्स में, एक चालक आउट-ऑफ-सर्विस (OOS) ऑर्डर (गैर-hazmat, गैर-यात्री) के उल्लंघन के लिए पहली दोषसिद्धि कितनी अयोग्यता में परिणत होती है:","options":["60 दिन से कम नहीं","90 दिन से कम नहीं","180 दिन से कम नहीं और 1 वर्ष से अधिक नहीं","1 वर्ष से कम नहीं और 5 वर्ष से अधिक नहीं"],"explanation":"पहला आउट-ऑफ-सर्विस ऑर्डर उल्लंघन 180 दिन से कम नहीं और 1 वर्ष से अधिक नहीं की अयोग्यता में परिणत होता है। स्रोत: MA RMV CDL Manual; 49 CFR 383.51(e)।"},"55":{"q":"10-वर्ष की अवधि के भीतर दूसरा आउट-ऑफ-सर्विस ऑर्डर उल्लंघन एक मैसाचुसेट्स CDL चालक को कितने समय के लिए अयोग्य ठहराता है:","options":["180 दिन से कम नहीं और 1 वर्ष से अधिक नहीं","2 वर्ष से कम नहीं और 5 वर्ष से अधिक नहीं","1 वर्ष से कम नहीं और 3 वर्ष से अधिक नहीं","आजीवन"],"explanation":"10 वर्षों के भीतर दूसरा आउट-ऑफ-सर्विस ऑर्डर उल्लंघन 2 वर्ष से कम नहीं और 5 वर्ष से अधिक नहीं की अयोग्यता में परिणत होता है। स्रोत: MA RMV CDL Manual; 49 CFR 383.51(e)।"},"56":{"q":"प्लेकार्ड वाली खतरनाक सामग्री का परिवहन करते समय या 16+ यात्रियों के लिए डिज़ाइन किए गए वाहन को चलाते समय पहला आउट-ऑफ-सर्विस ऑर्डर उल्लंघन कितनी मैसाचुसेट्स CDL अयोग्यता में परिणत होता है:","options":["180 दिन से कम नहीं और 1 वर्ष से अधिक नहीं","180 दिन से कम नहीं और 2 वर्ष से अधिक नहीं","1 वर्ष से कम नहीं और 3 वर्ष से अधिक नहीं","3 वर्ष से कम नहीं और 5 वर्ष से अधिक नहीं"],"explanation":"प्लेकार्ड वाली hazmat या 16+ यात्री वाहन से जुड़ा पहला आउट-ऑफ-सर्विस उल्लंघन एक बढ़ा हुआ दंड वहन करता है: 180 दिन से कम नहीं और 2 वर्ष से अधिक नहीं। स्रोत: MA RMV CDL Manual; 49 CFR 383.51(e)।"},"57":{"q":"निम्नलिखित में से किसे एक प्रमुख अपराध माना जाता है जो एक मैसाचुसेट्स CDL चालक को अयोग्य ठहराता है, भले ही चालक के निजी (गैर-वाणिज्यिक) वाहन में किया गया हो?","options":["बहुत पास से पीछा करना","अनुचित लेन परिवर्तन","दुर्घटना स्थल से चले जाना","एक हैंड-हेल्ड फोन का उपयोग करना"],"explanation":"दुर्घटना स्थल से चले जाना एक प्रमुख अपराध है जो CMV या निजी वाहन में किए जाने पर CDL को अयोग्य ठहराता है। अन्य केवल तभी गंभीर यातायात उल्लंघन हैं जब CMV चलाते समय किए जाएं। स्रोत: MA RMV CDL Manual; 49 CFR 383.51(b)।"},"58":{"q":"एक मैसाचुसेट्स CDL चालक जो किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से जुड़े अपराध (felony) को करने के लिए किसी भी मोटर वाहन का उपयोग करता है, कितने समय के लिए अयोग्य घोषित किया जाता है:","options":["1 वर्ष","3 वर्ष","10 वर्ष","बिना पुनर्बहाली के आजीवन"],"explanation":"नियंत्रित पदार्थों (निर्माण, वितरण, या वितरण) से जुड़े अपराध (felony) को करने के लिए एक मोटर वाहन का उपयोग करना एक आजीवन अयोग्यता में परिणत होता है जो पुनर्बहाली के अधीन नहीं है। स्रोत: MA RMV CDL Manual; M.G.L. c. 90F; 49 CFR 383.51(b)।"},"59":{"q":"मैसाचुसेट्स के रेलरोड-क्रॉसिंग कानून के तहत, एक स्कूल बस या विस्फोटक अथवा ज्वलनशील तरल पदार्थ को माल के रूप में ले जाने वाले वाहन को निकटतम रेल से किस क्षेत्र के भीतर पूरी तरह रुकना चाहिए?","options":["15 feet से कम नहीं और 50 feet से अधिक नहीं","10 feet से कम नहीं और 40 feet से अधिक नहीं","5 feet से कम नहीं और 25 feet से अधिक नहीं","20 feet से कम नहीं और 75 feet से अधिक नहीं"],"explanation":"Massachusetts General Laws c. 90, s. 15 के अनुसार एक स्कूल बस या विस्फोटक अथवा ज्वलनशील तरल पदार्थ को माल के रूप में ले जाने वाले वाहन को क्रॉसिंग से पहले निकटतम ट्रैक से 15 feet से कम नहीं और 50 feet से अधिक नहीं की दूरी पर रुकना आवश्यक है। स्रोत: MGL c. 90, s. 15।"},"60":{"q":"मैसाचुसेट्स का 'Move Over' कानून किस राज्य के क़ानून (statute) पर आधारित है, और चमकती लाइटों वाले एक खड़े आपातकालीन, रखरखाव, या रिकवरी वाहन के पास पहुँचते समय बुनियादी आवश्यकता क्या है?","options":["MGL c. 89, s. 7C; यदि संभव हो तो किसी गैर-निकटवर्ती लेन में चले जाएँ, या यदि आप ऐसा नहीं कर सकते तो एक सुरक्षित और उचित गति तक धीमे हो जाएँ","MGL c. 90, s. 14; लाइटें बंद होने तक पूरी तरह रुक जाएँ","MGL c. 85, s. 2; अपना हॉर्न बजाएँ और निर्धारित गति पर चलते रहें","MGL c. 90, s. 17; गति को 20 mph से अधिक न करें और अपनी लेन में बने रहें"],"explanation":"मैसाचुसेट्स का Move Over कानून, MGL c. 89, s. 7C (मार्च 2009 से प्रभावी), चमकती लाइटों वाले एक खड़े आपातकालीन, रखरखाव, या रिकवरी वाहन के पास पहुँचने वाले चालकों से अपेक्षा करता है कि जब सुरक्षित हो तो वे किसी गैर-निकटवर्ती लेन में चले जाएँ, और यदि ऐसा करने में असमर्थ हों तो एक सुरक्षित और उचित गति तक धीमे हो जाएँ। स्रोत: MGL c. 89, s. 7C; Mass.gov Move Over Law।"},"61":{"q":"MGL c. 89, s. 7C के तहत Move Over कानून के उल्लंघन के लिए मैसाचुसेट्स में जुर्माना (fine) क्या है?","options":["$100","$35","$250","$500"],"explanation":"मैसाचुसेट्स Move Over कानून (MGL c. 89, s. 7C) के उल्लंघन पर $100 का जुर्माना लगता है। स्रोत: MGL c. 89, s. 7C; Massachusetts State Police Move Over Law page।"},"62":{"q":"मैसाचुसेट्स में, लाल लाइटें चमकाती हुई एक रुकी हुई स्कूल बस के पास पहुँचने वाले चालक को कब रुकना आवश्यक नहीं होता?","options":["जब किसी विभाजित राजमार्ग (divided highway) पर विपरीत दिशा से पहुँच रहे हों","जब चालक 20 mph से कम गति पर चल रहा हो","जब चालक बस से दो कार-लंबाई से अधिक पीछे हो","जब बस किसी व्यापारिक क्षेत्र (business district) के भीतर रुकी हो"],"explanation":"MGL c. 90, s. 14 के तहत, हर चालक को चमकती लाल लाइटें दिखाती स्कूल बस तक पहुँचने से पहले रुकना चाहिए, सिवाय इसके कि वह किसी विभाजित राजमार्ग पर विपरीत दिशा से पहुँच रहा हो। स्रोत: MGL c. 90, s. 14।"},"63":{"q":"लाल लाइटें चमकाती हुई एक रुकी हुई स्कूल बस के लिए रुकने में विफल रहने या उसे अवैध रूप से पार करने के पहले अपराध के लिए मैसाचुसेट्स में न्यूनतम जुर्माना क्या है?","options":["$250","$100","$50","$500"],"explanation":"MGL c. 90, s. 14 के तहत, स्कूल बस रुकने वाले कानून के पहले उल्लंघन पर कम से कम $250 का जुर्माना लगता है; दूसरे अपराध पर 6-महीने के लाइसेंस निलंबन के साथ $500-$1,000 का जुर्माना होता है। स्रोत: MGL c. 90, s. 14।"},"64":{"q":"एक समतल, सीधे, विभाजित राजमार्ग पर, किनारे (shoulder) पर रुकने के बाद एक CDL चालक को तीन आपातकालीन परावर्तक त्रिकोण (reflective triangles) कहाँ रखने चाहिए?","options":["पिछले हिस्से के 10 feet के भीतर, लगभग 100 feet पीछे, और लगभग 200 feet पीछे","25 feet के भीतर, लगभग 75 feet, और लगभग 150 feet पीछे","5 feet के भीतर, लगभग 50 feet, और लगभग 100 feet पीछे","15 feet के भीतर, लगभग 150 feet, और लगभग 300 feet पीछे"],"explanation":"Massachusetts CDL Manual (49 CFR 392.22 को अपनाते हुए) निर्देश देता है कि किसी विभाजित या एकतरफा सड़क पर एक त्रिकोण वाहन के पिछले हिस्से के 10 feet के भीतर, एक लगभग 100 feet पीछे, और एक लगभग 200 feet पीछे रखा जाए। स्रोत: Massachusetts CDL Manual, Driving Safely (49 CFR 392.22)।"},"65":{"q":"यदि कोई वाणिज्यिक वाहन किसी पहाड़ी, मोड़, या दृश्यता सीमित करने वाली अन्य बाधा के 500 feet के भीतर रुका हो, तो एक CDL चालक को आपातकालीन-त्रिकोण की स्थिति कैसे समायोजित करनी चाहिए?","options":["सबसे पीछे वाले त्रिकोण को बाधा की ओर पीछे की ओर खिसकाएँ ताकि वह वाहन से 100 से 500 feet दूर हो, जिससे आने वाले चालकों को अधिक चेतावनी मिले","सभी त्रिकोण हटा दें और केवल चार-तरफा फ्लैशरों पर निर्भर रहें","तीनों त्रिकोणों को वाहन के 50 feet के भीतर रखें ताकि वे एक साथ रहें","केवल एक त्रिकोण रखें, सीधे वाहन के पीछे, 10 feet से अधिक दूर नहीं"],"explanation":"Massachusetts CDL Manual (49 CFR 392.22) के अनुसार, यदि कोई वाहन किसी मोड़, पहाड़ी की चोटी, या अन्य बाधा के 500 feet के भीतर रुका हो, तो बाधा की ओर वाला चेतावनी उपकरण वाहन से 100 से 500 feet दूर रखा जाना चाहिए ताकि आने वाले यातायात को पर्याप्त चेतावनी मिल सके। स्रोत: Massachusetts CDL Manual; 49 CFR 392.22।"},"66":{"q":"Massachusetts Turnpike (I-90) पर Weston में Interchange 14 और Sturbridge में Interchange 9 के बीच, एक भारी वाणिज्यिक वाहन (बस के अलावा) किन यात्रा लेनों का उपयोग कर सकता है?","options":["केवल सबसे दाईं ओर वाली लेन, या ओवरटेक करते और पास करते समय अगली निकटवर्ती लेन","कोई भी लेन, Turnpike पर ट्रकों के लिए कोई लेन-प्रतिबंध नहीं","धीमे यातायात को साफ रखने के लिए केवल सबसे बाईं ओर वाली लेन","दिन के उजाले के घंटों में केवल सबसे बाईं ओर की दो लेन"],"explanation":"700 CMR 7.09 एक भारी वाणिज्यिक वाहन (बस के अलावा) को Interchange 14 (Weston) और Interchange 9 (Sturbridge) के बीच सबसे दाईं ओर वाली यात्रा लेन तक सीमित करता है, या केवल ओवरटेक करते और पास करते समय अगली निकटवर्ती लेन तक, सिवाय आपात स्थिति के। स्रोत: 700 CMR 7.09।"},"67":{"q":"Boston में Storrow Drive और Soldiers Field Road पर बॉक्स ट्रकों, मूविंग ट्रकों, और अन्य वाणिज्यिक वाहनों को क्यों प्रतिबंधित किया गया है (तथाकथित 'Storrowing' का कारण)?","options":["ये DCR 'केवल कारों' वाले पार्कवे हैं जिनमें कम ऊँचाई वाले ओवरपास क्लीयरेंस (लगभग 10 feet या उससे कम) हैं, और ट्रकों/बसों पर प्रतिबंध है","इन पर एक टोल है जो केवल वाणिज्यिक ट्रांसपोंडर स्वीकार करता है","ये व्यस्त समय (rush hour) के दौरान उच्च-अधिभोग वाहनों के लिए आरक्षित हैं","इन पर अंतरराज्यीय माल ढुलाई के लिए बहुत कम ट्रक गति सीमा निर्धारित है"],"explanation":"Storrow Drive और Soldiers Field Road, Department of Conservation and Recreation (DCR) पार्कवे हैं जो यात्री वाहनों ('केवल कारों') तक सीमित हैं, जिनमें लगभग 10 feet या उससे कम के कम पुल क्लीयरेंस हैं; ट्रकों, बसों, और इसी तरह के वाहनों पर प्रतिबंध है, और अधिक-ऊँचाई वाले ट्रक अक्सर ओवरपासों से टकराते हैं। स्रोत: 302 CMR 11.00; Mass.gov / DCR Storrowing campaign।"},"68":{"q":"एक घनी बसावट वाले या व्यापारिक क्षेत्र के बाहर बिना निर्धारित गति सीमा वाले एक अविभाजित मैसाचुसेट्स राजमार्ग पर, वह वैधानिक गति क्या है जिससे ऊपर आपको तेज गति (speeding) का अनुमान लगाया जाता है?","options":["40 mph","30 mph","50 mph","55 mph"],"explanation":"MGL c. 90, s. 17 के तहत, बिना निर्धारित सीमा वाले घनी बसावट वाले या व्यापारिक क्षेत्र के बाहर एक अविभाजित मार्ग पर, कम से कम एक चौथाई मील तक 40 mph से अधिक गति तेज गति का प्रथम-दृष्टया (prima facie) प्रमाण है (विभाजित-राजमार्ग के लिए आँकड़ा 50 mph है)। स्रोत: MGL c. 90, s. 17।"},"69":{"q":"मैसाचुसेट्स में एक घनी बसावट वाले या व्यापारिक क्षेत्र के भीतर, जहाँ कोई गति सीमा निर्धारित नहीं है वहाँ वैधानिक गति सीमा क्या है?","options":["30 mph","25 mph","20 mph","35 mph"],"explanation":"MGL c. 90, s. 17 के तहत, एक घनी बसावट वाले या व्यापारिक क्षेत्र में जहाँ कोई विशेष सीमा निर्धारित नहीं है वहाँ वैधानिक गति 30 mph है (एक घनी बसावट वाले क्षेत्र को ऐसे इलाके के रूप में परिभाषित किया जाता है जहाँ आवासीय घरों के बीच औसत दूरी 200 feet से कम हो)। स्रोत: MGL c. 90, s. 17।"},"70":{"q":"मैसाचुसेट्स में, किसी रेलरोड क्रॉसिंग पर रुकने वाले एक स्कूल बस चालक को 15-से-50-feet के क्षेत्र में रुकने के अतिरिक्त निम्नलिखित में से क्या करना चाहिए?","options":["सर्विस दरवाज़ा खोलें, सुनिश्चित करें कि पार करना सुरक्षित है, फिर आगे बढ़ने से पहले दरवाज़ा बंद कर दें","पार करने से पहले हॉर्न तीन बार बजाएँ","ट्रैक के दोनों ओर परावर्तक त्रिकोण रखें","पार करने से पहले उपलब्ध सबसे ऊँचे गियर में बदल जाएँ"],"explanation":"MGL c. 90, s. 15 के तहत, एक स्कूल बस संचालक को निकटतम रेल से 15-50 feet के भीतर रुकना चाहिए, सर्विस दरवाज़ा खोलना चाहिए, यह सुनिश्चित करना चाहिए कि पार करना सुरक्षित है, और फिर आगे बढ़ने से पहले दरवाज़ा बंद कर देना चाहिए। स्रोत: MGL c. 90, s. 15।"},"71":{"q":"Massachusetts CDL Manual के अनुसार, एक वाणिज्यिक वाहन को रेलरोड ट्रैकों के पार चलाते समय चालक को गियरों के साथ क्या करना चाहिए?","options":["इतने नीचे गियर में पार करें कि ट्रैकों को बिना गियर बदले पार किया जा सके","ट्रैकों को तेज़ी से पार करने के लिए ट्रैकों पर रहते हुए गियर ऊपर बदलते जाएँ","न्यूट्रल में डालें और ट्रैकों के पार लुढ़कते हुए (coast) चलें","गति कम करने के लिए क्रॉसिंग के बीच में डाउनशिफ्ट करें"],"explanation":"Massachusetts CDL Manual चालकों को निर्देश देता है कि ऐसा गियर चुनें जो वाहन को बिना गियर बदले ट्रैकों को पूरी तरह पार करने दे, और ट्रैकों पर रहते हुए गियर न बदलें। स्रोत: Massachusetts CDL Manual, Railroad Crossings (49 CFR 392.10)।"},"72":{"q":"बिना ओवरवेट परमिट के, मैसाचुसेट्स में संघीय राजमार्ग प्रणाली पर एक ट्रक अधिकतम कितने सकल वाहन वजन (gross vehicle weight) पर संचालित हो सकता है?","options":["80,000 pounds","73,280 pounds","99,000 pounds","100,000 pounds"],"explanation":"मैसाचुसेट्स बिना विशेष परमिट के 80,000 pounds सकल वाहन वजन की संघीय सीमा का पालन करता है; इससे अधिक भार के लिए MassDOT ओवरवेट परमिट आवश्यक है। स्रोत: MassDOT Commercial Truck Permits; मैसाचुसेट्स में लागू संघीय वजन सीमाएँ।"},"73":{"q":"बिना ओवरसाइज़ परमिट के, मैसाचुसेट्स राजमार्गों पर अनुमत अधिकतम वैध वाहन/भार चौड़ाई क्या है?","options":["8 feet 6 inches (102 inches)","8 feet 0 inches (96 inches)","10 feet 0 inches (120 inches)","9 feet 0 inches (108 inches)"],"explanation":"बिना ओवरसाइज़ परमिट के मैसाचुसेट्स में वैध अधिकतम चौड़ाई 8 feet 6 inches (102 inches) है; इससे चौड़े भार के लिए MassDOT ओवरसाइज़ परमिट आवश्यक है। स्रोत: MassDOT oversize/overweight regulations; Mass.gov Commercial Truck Permits।"},"74":{"q":"बिना ओवरसाइज़ परमिट के, मैसाचुसेट्स राजमार्गों पर एक वाहन और भार के लिए अधिकतम वैध ऊँचाई क्या है?","options":["13 feet 6 inches","13 feet 0 inches","14 feet 0 inches","12 feet 6 inches"],"explanation":"मैसाचुसेट्स वैध अधिकतम ऊँचाई 13 feet 6 inches निर्धारित करता है; इससे ऊँचे भार के लिए MassDOT ओवरसाइज़ परमिट आवश्यक है और एक मार्ग सर्वेक्षण (route survey) की आवश्यकता हो सकती है। स्रोत: MassDOT oversize/overweight regulations; Mass.gov Commercial Truck Permits।"},"75":{"q":"Massachusetts Turnpike पर, Weston और Sturbridge के बीच भारी-वाणिज्यिक-वाहन लेन प्रतिबंध बसों के साथ कैसा व्यवहार करता है?","options":["बसें उस केवल-दाईं-लेन वाले प्रतिबंध से छूट प्राप्त हैं","बसों को हर समय बाईं लेन में रहना चाहिए","उस खंड से बसें पूरी तरह प्रतिबंधित हैं","बसें केवल रात में यात्रा कर सकती हैं"],"explanation":"700 CMR 7.09 के तहत, Interchange 14 (Weston) और Interchange 9 (Sturbridge) के बीच केवल-दाईं-लेन वाला प्रतिबंध 'बस के अलावा' भारी वाणिज्यिक वाहनों पर लागू होता है, इसलिए बसें उस विशेष प्रतिबंध से छूट प्राप्त हैं। स्रोत: 700 CMR 7.09।"},"76":{"q":"मैसाचुसेट्स कानून के तहत, स्कूल बस के लिए रुकने के लिए आवश्यक एक चालक के रुक जाने के बाद, वह चालक कब आगे बढ़ सकता है?","options":["जब बस के चमकते लाल चेतावनी संकेत निष्क्रिय हो जाएँ, सिवाय इसके कि किसी पुलिस अधिकारी द्वारा अन्यथा निर्देश दिया जाए","लाइटों की परवाह किए बिना एक निश्चित 10 सेकंड प्रतीक्षा करने के बाद","जैसे ही बस की पीली (amber) लाइटें चमकना शुरू करें","तुरंत, जब तक कोई बच्चा दिखाई न दे"],"explanation":"MGL c. 90, s. 14 के अनुसार रुके हुए चालक को तब तक रुके रहना चाहिए जब तक स्कूल बस के चमकते लाल संकेत निष्क्रिय न हो जाएँ, सिवाय इसके कि किसी पुलिस अधिकारी द्वारा आगे बढ़ने का निर्देश दिया जाए। स्रोत: MGL c. 90, s. 14।"},"77":{"q":"MGL c. 90, s. 14 के तहत, किसी मैसाचुसेट्स सार्वजनिक मार्ग पर एक वाहन एक स्कूल बस के पीछे कितने पास तक चल सकता है?","options":["100 feet से अधिक पास नहीं","50 feet से अधिक पास नहीं","200 feet से अधिक पास नहीं","25 feet से अधिक पास नहीं"],"explanation":"MGL c. 90, s. 14 एक वाहन को स्कूल बस के 100 feet के भीतर पीछे चलाने पर प्रतिबंध लगाता है (सिवाय जहाँ अनुमति हो वहाँ उसे ओवरटेक करते और पास करते समय)। स्रोत: MGL c. 90, s. 14।"},"78":{"q":"मैसाचुसेट्स में Commercial Driver's Licenses (CDLs) कौन सी एजेंसी जारी करती है?","options":["Registry of Motor Vehicles (RMV), जो MassDOT का हिस्सा है","Federal Motor Carrier Safety Administration (FMCSA)","Massachusetts Department of Public Safety","Massachusetts State Police Commercial Vehicle Section"],"explanation":"मैसाचुसेट्स में, CDLs को Registry of Motor Vehicles (RMV) द्वारा जारी किया जाता है, जो Massachusetts Department of Transportation (MassDOT) का एक प्रभाग है। FMCSA संघीय मानक निर्धारित करता है लेकिन लाइसेंस जारी नहीं करता। स्रोत: Mass.gov RMV Commercial Driver's Licenses (CDL) pages।"},"79":{"q":"मैसाचुसेट्स में कोई भी CDL स्किल्स (रोड) टेस्ट देने से पहले, आपको पहले कौन सा दस्तावेज़ प्राप्त करना होगा?","options":["एक Commercial Learner's Permit (CLP)","एक पूर्ण Class A CDL","एक संघीय अंतरराज्यीय संचालन प्राधिकरण (MC number)","एक खतरनाक सामग्री समर्थन (hazardous materials endorsement)"],"explanation":"अभ्यास के लिए एक वाणिज्यिक मोटर वाहन संचालित करने और स्किल्स टेस्ट के लिए योग्य होने के लिए, एक मैसाचुसेट्स आवेदक को पहले ज्ञान परीक्षण(ओं) में उत्तीर्ण होना चाहिए और एक Commercial Learner's Permit (CLP) प्राप्त करना चाहिए। स्रोत: Mass.gov RMV CDL pages; 49 CFR 383।"},"80":{"q":"एक मैसाचुसेट्स CLP धारक को CLP जारी होने के बाद CDL स्किल्स टेस्ट देने के लिए योग्य होने से पहले कितने समय प्रतीक्षा करनी चाहिए?","options":["कम से कम 14 days","कम से कम 24 hours","कम से कम 30 days","कम से कम 60 days"],"explanation":"आवेदक के CDL स्किल्स टेस्ट देने से पहले एक CLP को न्यूनतम 14 days तक धारण किया जाना चाहिए। यह एक संघीय आवश्यकता (49 CFR 383.37) है जिसे मैसाचुसेट्स लागू करता है। स्रोत: Mass.gov RMV CDL pages; 49 CFR 383.37।"},"81":{"q":"एक मैसाचुसेट्स Commercial Learner's Permit (CLP) कितने समय के लिए वैध होता है?","options":["180 days, एक बार अतिरिक्त 180 days के लिए नवीकरणीय","30 days, कोई नवीनीकरण अनुमति नहीं","1 साल, दो बार नवीकरणीय","90 days, एक बार अतिरिक्त 90 days के लिए नवीकरणीय"],"explanation":"एक मैसाचुसेट्स CLP 180 days के लिए वैध होता है और ज्ञान परीक्षण दोबारा दिए बिना अतिरिक्त 180 days के लिए एक बार नवीकृत किया जा सकता है; उसके बाद आवेदक को फिर से आवेदन करना होगा। स्रोत: Mass.gov RMV CDL pages; 49 CFR 383.25।"},"82":{"q":"मैसाचुसेट्स CDL स्किल्स टेस्ट किन तीन भागों से मिलकर बना है?","options":["प्री-ट्रिप निरीक्षण (pre-trip inspection), बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग","लिखित परीक्षा, दृष्टि जाँच (vision screening), और सड़क ड्राइविंग","एयर ब्रेक जाँच, hazmat हैंडलिंग, और सड़क पर ड्राइविंग","कपलिंग/अनकपलिंग, लॉगबुक समीक्षा, और सड़क पर ड्राइविंग"],"explanation":"मैसाचुसेट्स CDL स्किल्स टेस्ट के तीन खंड हैं: प्री-ट्रिप (वाहन) निरीक्षण, बुनियादी वाहन नियंत्रण (बैकिंग जैसी नियंत्रण कुशलताएँ), और सड़क पर ड्राइविंग टेस्ट। स्रोत: Mass.gov RMV CDL Skills Test Information Sheet / Modernized CDL Skills Exam Standard।"},"83":{"q":"एक मैसाचुसेट्स CDL/CLP आवेदक को अपने द्वारा किए जाने वाले ड्राइविंग के प्रकार को प्रमाणित करते समय कितनी स्व-प्रमाणन (self-certification) श्रेणियों में से चुनना होता है?","options":["चार","दो","तीन","पाँच"],"explanation":"संघीय और मैसाचुसेट्स नियमों के अनुसार चालक को वाणिज्य की चार श्रेणियों में से एक में स्व-प्रमाणित करना आवश्यक है। स्रोत: Mass.gov 'Commercial Driver's License (CDL) Self-Certification'; 49 CFR 383.71।"},"84":{"q":"निम्नलिखित में से कौन सी मैसाचुसेट्स में उपयोग की जाने वाली चार CDL स्व-प्रमाणन श्रेणियों में से एक है?","options":["Non-Excepted Interstate (NI)","Restricted Commercial (RC)","Federal Excepted Operator (FEO)","Limited Intrastate Hauler (LIH)"],"explanation":"चार श्रेणियाँ हैं Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), और Excepted Intrastate (EA)। अन्य विकल्प वास्तविक श्रेणियाँ नहीं हैं। स्रोत: Mass.gov CDL Self-Certification; 49 CFR 383.71।"},"85":{"q":"मैसाचुसेट्स/FMCSA नियमों के तहत, एक चालक जो 'Non-Excepted Interstate (NI)' के रूप में स्व-प्रमाणित करता है, वह अपने संचालन के बारे में क्या कथन दे रहा है?","options":["वे राज्य की सीमाओं के पार संचालन करते हैं और उन्हें संघीय DOT मेडिकल कार्ड आवश्यकताओं को पूरा करना होगा","वे केवल मैसाचुसेट्स के भीतर संचालन करते हैं और उन्हें किसी मेडिकल प्रमाणपत्र की आवश्यकता नहीं है","वे राज्य की सीमाओं के पार संचालन करते हैं लेकिन मेडिकल आवश्यकताओं से छूट प्राप्त हैं","वे केवल मैसाचुसेट्स के भीतर संचालन करते हैं और केवल राज्य के मेडिकल नियमों को पूरा करते हैं"],"explanation":"Non-Excepted Interstate (NI) का अर्थ है कि चालक अंतरराज्यीय वाणिज्य में संचालन करता है (या करने की अपेक्षा करता है) और उसे संघीय DOT मेडिकल परीक्षक के प्रमाणपत्र की आवश्यकताओं को पूरा करना आवश्यक है। स्रोत: Mass.gov CDL Self-Certification; 49 CFR 383.71/391।"},"86":{"q":"एक चालक जो मैसाचुसेट्स में 'Excepted Intrastate (EA)' के रूप में स्व-प्रमाणित करता है, वह निम्नलिखित में से क्या संकेत दे रहा है?","options":["वे केवल मैसाचुसेट्स के भीतर संचालन करते हैं और उन्हें संघीय DOT मेडिकल कार्ड आवश्यकताओं को पूरा करना आवश्यक नहीं है","वे राज्य की सीमाओं के पार संचालन करते हैं और उन्हें एक संघीय मेडिकल कार्ड रखना होगा","वे केवल मैसाचुसेट्स के भीतर संचालन करते हैं और उन्हें एक संघीय DOT मेडिकल कार्ड रखना होगा","वे केवल खतरनाक सामग्री परिवहन तक सीमित हैं"],"explanation":"Excepted Intrastate (EA) का अर्थ है कि चालक केवल अंतरराज्यीय (राज्य-के-भीतर) वाणिज्य में संचालन करता है और संघीय DOT मेडिकल कार्ड आवश्यकताओं से छूट प्राप्त है। स्रोत: Mass.gov CDL Self-Certification; 49 CFR 383.71।"},"87":{"q":"जब एक non-excepted interstate मैसाचुसेट्स CDL चालक एक DOT शारीरिक जाँच (physical) में उत्तीर्ण होता है, तो प्रमाणित मेडिकल परीक्षक कौन सा दस्तावेज़ जारी करता है?","options":["एक Medical Examiner's Certificate (Form MCSA-5876)","एक Massachusetts RMV Class D vision waiver","एक संघीय Hours-of-Service छूट पत्र","एक FMCSA संचालन प्राधिकरण प्रमाणपत्र"],"explanation":"FMCSA National Registry का एक परीक्षक जो चालक को योग्य पाता है, एक Medical Examiner's Certificate (Form MCSA-5876) जारी करता है। स्रोत: Mass.gov CDL Self-Certification / Medical Certification; FMCSA National Registry।"},"88":{"q":"एक मैसाचुसेट्स CDL मेडिकल परीक्षक जो DOT शारीरिक जाँच करता है, उसका नाम कहाँ सूचीबद्ध होना चाहिए?","options":["FMCSA National Registry of Certified Medical Examiners पर","Massachusetts RMV approved physician roster पर","Massachusetts Board of Registration in Medicine CDL list पर","MassDOT Highway Division provider list पर"],"explanation":"CDL प्रयोजनों के लिए DOT शारीरिक जाँच FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध एक मेडिकल परीक्षक द्वारा की जानी चाहिए। स्रोत: Mass.gov CDL Self-Certification; FMCSA National Registry।"},"89":{"q":"2025 के मध्य तक, अधिकांश मैसाचुसेट्स CDL चालकों के लिए मेडिकल प्रमाणन जानकारी RMV तक कैसे पहुँचती है?","options":["FMCSA National Registry से इलेक्ट्रॉनिक रूप से, इसलिए आमतौर पर एक कागज़ी कार्ड जमा करने की आवश्यकता नहीं होती","केवल चालक द्वारा 5 दिनों के भीतर RMV को एक कागज़ी कार्ड डाक से भेजकर","केवल नियोक्ता द्वारा MassDOT को कार्ड फैक्स करके","चालक की बीमा कंपनी से स्वचालित रूप से"],"explanation":"23 June 2025 से, RMV को FMCSA National Registry से मेडिकल प्रमाणन जानकारी इलेक्ट्रॉनिक रूप से प्राप्त होती है, इसलिए अधिकांश चालकों को भौतिक प्रति जमा करने की आवश्यकता नहीं है (केवल-अंतरराज्यीय चालक अभी भी एक जमा कर सकते हैं यदि अपलोड न की गई हो)। स्रोत: Mass.gov CDL Self-Certification।"},"90":{"q":"एक पहली बार के Class A या Class B मैसाचुसेट्स आवेदक को RMV द्वारा CDL स्किल्स टेस्ट निर्धारित करने से पहले कौन सा प्रशिक्षण पूरा करना होगा?","options":["एक FMCSA-पंजीकृत प्रदाता से Entry-Level Driver Training (ELDT)","एक 40-घंटे का MassDOT रक्षात्मक-ड्राइविंग पाठ्यक्रम","एक RMV सेवा केंद्र पर राज्य-संचालित प्रशिक्षुता (apprenticeship)","केवल एक नियोक्ता-जारी सड़क सुरक्षा अभिविन्यास (orientation)"],"explanation":"7 February 2022 से, पहली बार के Class A/B आवेदकों (और पहली बार के S, P, या H समर्थन) को RMV द्वारा स्किल्स टेस्ट निर्धारित करने से पहले FMCSA Training Provider Registry पर सूचीबद्ध एक प्रदाता से Entry-Level Driver Training (ELDT) पूरा करना होगा। स्रोत: Mass.gov ELDT guide; 49 CFR Part 380 Subpart F।"},"91":{"q":"मैसाचुसेट्स CDL स्किल्स टेस्ट से पहले आवश्यक Entry-Level Driver Training (ELDT) किन दो घटकों से मिलकर बना है?","options":["सैद्धांतिक निर्देश (theory instruction) और वाहन-संचालन निर्देश (behind-the-wheel instruction)","एक लिखित परीक्षा और एक दृष्टि जाँच (vision screening)","केवल-कक्षा निर्देश और एक संघीय पृष्ठभूमि जाँच","एक मेडिकल परीक्षा और एक ड्रग जाँच (drug screening)"],"explanation":"ELDT के लिए CDL स्किल्स टेस्ट देने से पहले सैद्धांतिक और वाहन-संचालन निर्देश के एक निर्धारित कार्यक्रम को सफलतापूर्वक पूरा करना आवश्यक है। स्रोत: Mass.gov ELDT guide; FMCSA 49 CFR Part 380 Subpart F।"},"92":{"q":"पहली बार के Class A/B आवेदकों के अलावा, पहली बार किस समर्थन (endorsement) के लिए आवेदन करने से पहले भी ELDT पूरा करना होगा?","options":["खतरनाक सामग्री (H), यात्री (P), या स्कूल बस (S)","केवल टैंक वाहन (N)","केवल डबल/ट्रिपल ट्रेलर (T)","एयर ब्रेक (कोई प्रतिबंध नहीं)"],"explanation":"ELDT पहली बार के Class A/B CDLs, Class B-से-A अपग्रेड, और पहली बार के खतरनाक सामग्री (H), यात्री (P), और स्कूल बस (S) समर्थनों पर लागू होता है। स्रोत: Mass.gov ELDT guide; 49 CFR Part 380।"},"93":{"q":"एक मैसाचुसेट्स CDL कितने समय के लिए वैध होता है जिसके बाद इसे नवीकृत किया जाना चाहिए?","options":["5 years","2 years","8 years","10 years"],"explanation":"एक मैसाचुसेट्स CDL 5 years के लिए वैध होता है और आमतौर पर धारक के जन्मदिन पर समाप्त होता है। स्रोत: Mass.gov RMV license renewal pages।"},"94":{"q":"एक केवल-अंतरराज्यीय (केवल-मैसाचुसेट्स) CDL प्राप्त करने के लिए न्यूनतम आयु क्या है, और अंतरराज्यीय संचालन के लिए न्यूनतम आयु क्या है?","options":["अंतरराज्यीय (intrastate) के लिए 18 और अंतरराज्यीय (interstate) के लिए 21","अंतरराज्यीय (intrastate) के लिए 16 और अंतरराज्यीय (interstate) के लिए 18","अंतरराज्यीय (intrastate) और अंतरराज्यीय (interstate) दोनों के लिए 18","अंतरराज्यीय (intrastate) और अंतरराज्यीय (interstate) दोनों के लिए 21"],"explanation":"एक आवेदक को अंतरराज्यीय (मैसाचुसेट्स के भीतर) CDL/CLP प्राप्त करने के लिए कम से कम 18 का होना चाहिए और अंतरराज्यीय (interstate) वाणिज्य में संचालन के लिए कम से कम 21 का होना चाहिए। स्रोत: Mass.gov RMV CDL pages; 49 CFR 383.3/391.11।"},"95":{"q":"एक मैसाचुसेट्स CLP/CDL के लिए आवेदन करते समय, आवेदक को आमतौर पर कौन सा दस्तावेज़ों का समूह प्रदान करना होगा?","options":["पहचान/वैध उपस्थिति का प्रमाण, एक Social Security number, और मैसाचुसेट्स निवास","केवल एक वैध पासपोर्ट और एक वाहन पंजीकरण","केवल एक नियोक्ता पत्र और एक वाहन शीर्षक (vehicle title)","एक जन्म प्रमाणपत्र और एक क्रेडिट रिपोर्ट"],"explanation":"मैसाचुसेट्स CDL आवेदकों को पहचान/वैध उपस्थिति सिद्ध करनी चाहिए, एक Social Security number प्रदान करना चाहिए, और मैसाचुसेट्स निवास सिद्ध करना चाहिए, वही पहचान मानक जो अन्य RMV प्रमाण-पत्रों के लिए उपयोग किए जाते हैं। स्रोत: Mass.gov RMV CDL and identification requirements।"},"96":{"q":"मैसाचुसेट्स CDL सामान्य ज्ञान लिखित परीक्षा में, उत्तीर्ण होने के लिए कौन सा स्कोर आवश्यक है?","options":["कम से कम 80% सही","कम से कम 60% सही","कम से कम 70% सही","पूर्ण 100% सही"],"explanation":"मैसाचुसेट्स CDL ज्ञान परीक्षण, सामान्य ज्ञान परीक्षण सहित, उत्तीर्ण होने के लिए कम से कम 80% सही स्कोर की आवश्यकता होती है। स्रोत: Massachusetts CDL Manual; Mass.gov RMV CDL testing pages।"}},"ar":{"0":{"q":"على الطرق في ولاية ماساتشوستس، ما هو الحد الأقصى القانوني لعرض المركبة التجارية الآلية، باستثناء المرايا وإشارات الانعطاف وبعض أجهزة السلامة؟","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"تحدّ ولاية ماساتشوستس عرض المركبة بمقدار 102 inches (8 feet 6 inches)، دون احتساب المرايا وإشارات الانعطاف وبعض أجهزة السلامة. المصدر: MGL Chapter 90, Section 19؛ دليل CDL الصادر عن Massachusetts RMV."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة وحمولتها على الطرق السريعة في ماساتشوستس دون الحصول على تصريح؟","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"تحدد ولاية ماساتشوستس الحد الأقصى لارتفاع المركبة وحمولتها بمقدار 13 feet 6 inches. ويجب على المركبات التي يتجاوز ارتفاعها 10 feet أن تعرض ارتفاعها. المصدر: MGL Chapter 90, Section 19؛ حدود ارتفاع الشاحنات التجارية لدى MassDOT."},"2":{"q":"دون تصريح خاص، ما هو الحد الأقصى لطول المقطورة النصفية في تركيبة الجرّار والمقطورة النصفية في ماساتشوستس؟","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"يجوز أن يصل طول المقطورة النصفية في وحدة الجرّار والمقطورة النصفية إلى 53 feet في ماساتشوستس. المصدر: MGL Chapter 90, Section 19؛ دليل CDL الصادر عن Massachusetts RMV."},"3":{"q":"ما هو الحد الأقصى لوزن المركبة الإجمالي المسموح به على الطرق في ماساتشوستس، دون تصريح، لمركبة ذات ثلاثة محاور أو أكثر؟","options":["73,280 pounds","80,000 pounds","88,000 pounds","99,000 pounds"],"explanation":"تحدد ولاية ماساتشوستس سقف وزن المركبة الإجمالي بمقدار 80,000 pounds للمركبات ذات الثلاثة محاور أو أكثر، بما يتوافق مع الحد الأقصى الفيدرالي للطرق بين الولايات. المصدر: MGL Chapter 90, Section 19A."},"4":{"q":"ما هو الحد الأقصى للوزن الذي تسمح به ماساتشوستس على محور مفرد دون تصريح للوزن الزائد؟","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"تسمح ولاية ماساتشوستس بما يصل إلى 22,400 pounds على المحور المفرد، وهو أعلى من الحد الفيدرالي للطرق بين الولايات البالغ 20,000-pound. المصدر: MGL Chapter 90, Section 19A."},"5":{"q":"ما هو الحد الأقصى للوزن الذي تسمح به ماساتشوستس على محور مزدوج (محورين) دون تصريح للوزن الزائد؟","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"تحدد ولاية ماساتشوستس حدّ المحور المزدوج بمقدار 34,000 pounds، بما يتوافق مع المعيار الفيدرالي. المصدر: MGL Chapter 90, Section 19A."},"6":{"q":"في ماساتشوستس، ما هو الحد الأقصى لارتفاع الشاحنة المستقيمة (وحدة واحدة) قبل أن يُطلب عرض علامات الارتفاع على المركبة؟","options":["8 feet","10 feet","12 feet","13 feet 6 inches"],"explanation":"تشترط ولاية ماساتشوستس على المركبات التي يتجاوز ارتفاعها 10 feet أن تعرض ارتفاعها بعلامات، رغم أن الحد الأقصى القانوني للارتفاع هو 13 feet 6 inches. المصدر: MGL Chapter 90, Section 19."},"7":{"q":"أي جهة في ماساتشوستس تصدر تصاريح الأبعاد الزائدة والأوزان الزائدة للسفر على الطرق السريعة للولاية؟","options":["سجل المركبات الآلية (RMV)","شعبة الطرق السريعة في MassDOT","شرطة ولاية ماساتشوستس","الإدارة الفيدرالية لسلامة شركات النقل بالمركبات"],"explanation":"تصدر تصاريح الأبعاد/الأوزان الزائدة للطرق السريعة للولاية عن شعبة الطرق السريعة في MassDOT من خلال مكتب تصاريح الشاحنات التابع لها. المصدر: تصاريح الشاحنات التجارية على Mass.gov؛ MassDOT."},"8":{"q":"ما اسم النظام الإلكتروني التابع لـ MassDOT المستخدم لطلب تصاريح الشاحنات التجارية ذات الأبعاد/الأوزان الزائدة وتحديد المسارات؟","options":["ATLAS","OASIS","PRISM","UCR"],"explanation":"يُسمى تطبيق تصاريح وتحديد مسارات الأبعاد/الأوزان الزائدة عبر الويب التابع لـ MassDOT باسم OASIS، ويُستخدم لتقديم طلبات تصاريح الشاحنات التجارية. المصدر: شعبة الطرق السريعة في MassDOT؛ Mass.gov."},"9":{"q":"متى يُطلب من المركبة الحصول على تصريح الأبعاد/الأوزان الزائدة من MassDOT؟","options":["فقط عند عبور حدود ولاية","كلما تجاوزت الحدود القانونية للعرض أو الارتفاع أو الطول أو الوزن","فقط عند نقل المواد الخطرة","فقط عند السفر ليلاً"],"explanation":"يُطلب التصريح في أي وقت تتجاوز فيه المركبة أو الحمولة الحدود القانونية للعرض (102 in) أو الارتفاع (13'6\") أو الطول أو الوزن (80,000 lb). المصدر: MGL Chapter 90, Section 19/19A؛ MassDOT."},"10":{"q":"تطبّق ماساتشوستس معادلة الجسور الفيدرالية على الوزن المحمول على مجموعة من محورين متتاليين أو أكثر. ما هو المضاعِف الثابت المستخدم في تلك المعادلة، W = 500[LN/(N-1) + 12N + 36]؟","options":["100","250","500","1,000"],"explanation":"تستخدم معادلة الجسور الفيدرالية المعتمدة في ماساتشوستس الثابت 500: W = 500[LN/(N-1) + 12N + 36]، حيث L هي المسافة بين المحاور وN هو عدد المحاور. المصدر: MGL Chapter 90, Section 19A؛ معادلة الجسور لدى FHWA."},"11":{"q":"في معادلة الجسور الفيدرالية المستخدمة في ماساتشوستس، ماذا يمثّل المتغير 'L'؟","options":["وزن الحمولة القانوني بالأرطال","المسافة بالأقدام بين المحاور الطرفية (الخارجية) للمجموعة","عرض حارة الطريق السريع","طول المقطورة بالأقدام"],"explanation":"في المعادلة W = 500[LN/(N-1) + 12N + 36]، يمثّل 'L' المسافة بالأقدام بين المحاور الطرفية لأي مجموعة من محورين متتاليين أو أكثر. المصدر: MGL Chapter 90, Section 19A؛ معادلة الجسور لدى FHWA."},"12":{"q":"ما هو الحد الأقصى للوزن الإجمالي الذي تسمح به ماساتشوستس على مركبة ذات محورين فقط، دون تصريح؟","options":["34,000 pounds","40,000 pounds","46,000 pounds","54,000 pounds"],"explanation":"تقتصر المركبة ذات المحورين على 46,000 pounds إجمالاً في ماساتشوستس، بينما يجوز للمركبات ذات الثلاثة محاور أو أكثر أن تبلغ 80,000 pounds. المصدر: MGL Chapter 90, Section 19A."},"13":{"q":"في ماساتشوستس، إذا كان محوران مفردان متباعدين بأقل من 6 feet، فما هو الحد الأقصى للوزن المسموح به على كل من هذين المحورين؟","options":["16,000 pounds","18,000 pounds","20,000 pounds","22,400 pounds"],"explanation":"عندما تكون المحاور متباعدة بأقل من 6 feet، ينخفض السماح للمحور المفرد من 22,400 pounds إلى 18,000 pounds لكل منهما. المصدر: MGL Chapter 90, Section 19A."},"14":{"q":"كيف تُقارن الحدود القصوى للعرض والارتفاع في ماساتشوستس على الطرق السريعة بين الولايات (Interstate) بتلك المعمول بها على الطرق السريعة الأخرى للولاية؟","options":["حدود العرض والارتفاع متماثلة (102 in عرضاً، 13'6\" ارتفاعاً) على كليهما","تسمح الطرق بين الولايات بعرض أوسع 8'6\" بينما تسمح الطرق الأخرى بـ 8' فقط","تسمح الطرق بين الولايات بارتفاع 14 feet بينما تسمح الطرق الأخرى بـ 13'6\" فقط","تسمح الطرق الأخرى للولاية بمركبات أوسع من الطرق بين الولايات"],"explanation":"ينطبق حدّا العرض البالغ 102-inch والارتفاع البالغ 13-foot-6-inch بشكل موحّد على كل من الشبكة بين الولايات/الوطنية والطرق السريعة الأخرى للولاية في ماساتشوستس. المصدر: MGL Chapter 90, Section 19؛ ملخص الأبعاد/الأوزان لـ MA من J.J. Keller."},"15":{"q":"مقارنةً بالحد الفيدرالي للمحور المفرد على الطرق بين الولايات، فإن سماح المحور المفرد في ماساتشوستس هو:","options":["أقل (تسمح ماساتشوستس بـ 18,000 lb مقابل 20,000 lb فيدرالياً)","متماثل (كلاهما 20,000 lb)","أعلى (تسمح ماساتشوستس بـ 22,400 lb مقابل 20,000 lb فيدرالياً)","غير محدود على طرق الولاية"],"explanation":"تسمح ولاية ماساتشوستس بـ 22,400 pounds على المحور المفرد، وهو أعلى من المعيار الفيدرالي للطرق بين الولايات البالغ 20,000-pound. المصدر: MGL Chapter 90, Section 19A."},"16":{"q":"دون تصريح، ما هو الحد الأقصى لطول الشاحنة المستقيمة (وحدة واحدة) في ماساتشوستس؟","options":["33 feet","40 feet","45 feet","53 feet"],"explanation":"يجوز أن يصل طول الشاحنة المستقيمة (وحدة واحدة) إلى 40 feet في ماساتشوستس؛ بينما يجوز أن يصل طول المقطورة النصفية في تركيبة إلى 53 feet. المصدر: MGL Chapter 90, Section 19."},"17":{"q":"تحتاج شركة نقل إلى نقل حمولة عرضها 14 feet على طريق سريع للولاية في ماساتشوستس. ماذا يجب على الشركة أن تفعل؟","options":["لا شيء، لأن 14 feet ضمن الحد القانوني للعرض","الحصول على تصريح للأبعاد الزائدة من شعبة الطرق السريعة في MassDOT قبل السفر","إبلاغ دائرة الشرطة المحلية فقط","التقدّم للحصول على تظهير CDL"],"explanation":"عند عرض 14 feet تتجاوز الحمولة الحد القانوني للعرض البالغ 102-inch (8'6\")، لذا يجب الحصول على تصريح للأبعاد الزائدة من شعبة الطرق السريعة في MassDOT (عبر OASIS) قبل السفر. المصدر: MGL Chapter 90, Section 19؛ MassDOT."},"18":{"q":"بموجب قانون ماساتشوستس، ما هو الحد الأقصى القانوني للطول الإجمالي لجرّار مع مقطورتين توأم/مزدوجتين (كل مقطورة بطولها القانوني)؟","options":["كل مقطورة حتى 28 feet، دون حد أقصى لطول التركيبة الإجمالي عندما تكون المقطورتان قانونيتين","حد إجمالي ثابت 65-foot بغض النظر عن طول المقطورة","حد إجمالي ثابت 53-foot","المقطورات التوأم محظورة في ماساتشوستس"],"explanation":"في تركيبة الجرّار والمقطورتين التوأم، يجوز أن يصل طول كل مقطورة (وحدة مزدوجة) إلى 28 feet، ولا يوجد حد أقصى لطول التركيبة الإجمالي عندما تكون المقطورتان قانونيتين. المصدر: MGL Chapter 90, Section 19؛ ملخص الأبعاد/الأوزان لـ MA من J.J. Keller."},"19":{"q":"في ماساتشوستس، أي فئة من CDL مطلوبة لتشغيل مركبة مفردة بتصنيف وزن إجمالي للمركبة (GVWR) يبلغ 26,001 lbs. أو أكثر ولا تقطر مقطورة يتجاوز وزنها 10,000 lbs.؟","options":["Class A","Class B","Class C","Class D"],"explanation":"تشترط ولاية ماساتشوستس Class B CDL لتشغيل أي مركبة مفردة بتصنيف GVWR يبلغ 26,001 lbs. أو أكثر، أو مركبة كهذه تقطر مقطورة لا يتجاوز وزنها 10,000 lbs. (مثل الشاحنات الصندوقية وشاحنات القلب والشاحنات المستقيمة). المصدر: 'فئات CDL والتظهيرات' على Mass.gov ودليل CDL لماساتشوستس (RMV)."},"20":{"q":"يرغب سائق في ماساتشوستس في قطر تركيبة جرّار ومقطورة بتصنيف وزن إجمالي مركّب يبلغ 80,000 lbs. حيث يتجاوز تصنيف المقطورة المقطورة 10,000 lbs. أي فئة من CDL مطلوبة؟","options":["Class B","Class C","Class A","Class D"],"explanation":"تُطلب Class A CDL في ماساتشوستس لأي تركيبة مركبات بتصنيف GCWR يبلغ 26,001 lbs. أو أكثر حيث تتجاوز الوحدة (الوحدات) المقطورة 10,000 lbs. GVWR. المصدر: 'فئات CDL والتظهيرات' على Mass.gov ودليل CDL لماساتشوستس (RMV)."},"21":{"q":"بموجب قواعد ماساتشوستس، المركبة التي لا تستوفي عتبات الوزن للفئة Class A أو Class B لكنها مصممة لنقل 16 راكباً أو أكثر (بمن فيهم السائق) أو لنقل مواد خطرة موسومة بلوحات تحذيرية تتطلب أي فئة من CDL؟","options":["Class C","Class A","Class B","Class M"],"explanation":"تشترط ولاية ماساتشوستس Class C CDL للمركبة التي لا تنطبق عليها مواصفات Class A أو Class B لكنها مصممة لنقل 16 شخصاً أو أكثر (بمن فيهم السائق) أو تُستخدم لنقل مواد خطرة تتطلب لوحات تحذيرية. المصدر: 'فئات CDL والتظهيرات' على Mass.gov ودليل CDL لماساتشوستس (RMV)."},"22":{"q":"ما هو الحد الأدنى للعمر للحصول على CDL أو رخصة متعلّم تجارية (CLP) في ماساتشوستس مقيّدة بالتجارة داخل الولاية (INTRASTATE) (ضمن ماساتشوستس فقط)؟","options":["16 years old","17 years old","18 years old","21 years old"],"explanation":"تشترط ولاية ماساتشوستس أن يكون عمر المتقدمين 18 عاماً على الأقل للحصول على CDL/CLP للتجارة داخل الولاية (ضمن ماساتشوستس فقط). أما القيادة في التجارة بين الولايات فتتطلب عمر 21 عاماً. المصدر: 'التقدّم للحصول على رخصة متعلّم تجارية (CLP)' على Mass.gov (RMV)."},"23":{"q":"ما هو الحد الأدنى للعمر المطلوب لقيادة مركبة آلية تجارية في التجارة بين الولايات (INTERSTATE) بموجب CDL لماساتشوستس؟","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"يجب أن يكون عمر السائق 21 عاماً على الأقل لتشغيل CMV عبر حدود الولايات (التجارة بين الولايات). أما السائقون من عمر 18-20 فيقتصرون على التشغيل داخل الولاية (ضمن ماساتشوستس فقط). المصدر: صفحات CLP/CDL لـ RMV على Mass.gov، بما يتوافق مع 49 CFR 391.11."},"24":{"q":"أي رمز تظهير مطلوب على CDL لماساتشوستس لقيادة مركبة مصممة لنقل الركاب، مثل حافلة كبيرة؟","options":["Code N","Code P","Code T","Code H"],"explanation":"تُطلب تظهير الركاب (P) في ماساتشوستس لتشغيل مركبة مصممة لنقل الركاب (مثل الحافلات). ويتطلب اجتياز اختبار معرفي واختبار مهارات في مركبة ممثّلة. المصدر: 'فئات CDL والتظهيرات' على Mass.gov ودليل CDL لماساتشوستس (RMV)."},"25":{"q":"أي تظهير من CDL مطلوب لنقل المواد الخطرة بكميات تتطلب لوحات تحذيرية في ماساتشوستس؟","options":["N (صهريج)","T (مقطورتان/ثلاث مقطورات)","H (مواد خطرة)","S (حافلة مدرسية)"],"explanation":"تُطلب تظهير H (المواد الخطرة) لنقل كميات من المواد الخطرة تتطلب لوحات تحذيرية. وتتطلب اختباراً معرفياً وتقييم تهديد أمني من TSA وتدريب ELDT النظري للمتقدمين لأول مرة. المصدر: 'فئات CDL والتظهيرات' على Mass.gov وبرنامج تظهير HazMat لدى TSA."},"26":{"q":"في ماساتشوستس، أي تظهير مطلوب لقطر مقطورتين أو ثلاث مقطورات؟","options":["تظهير T","تظهير N","تظهير X","تظهير P"],"explanation":"تُطلب تظهير T (مقطورتان/ثلاث مقطورات) لقطر أكثر من مقطورة واحدة. ويُحصل عليه باجتياز اختبار معرفي فقط (دون اختبار مهارات منفصل). المصدر: 'فئات CDL والتظهيرات' على Mass.gov ودليل CDL لماساتشوستس (RMV)."},"27":{"q":"أي تظهير يحتاجه حامل CDL في ماساتشوستس لقيادة مركبة صهريجية تحمل حمولة سائلة أو غازية؟","options":["تظهير H","تظهير T","تظهير N","تظهير S"],"explanation":"تُطلب تظهير N (المركبة الصهريجية) لتشغيل مركبة صهريجية مصممة لنقل السوائل أو الغازات بالجملة. ويُحصل عليه باجتياز الاختبار المعرفي للمركبة الصهريجية. المصدر: 'فئات CDL والتظهيرات' على Mass.gov ودليل CDL لماساتشوستس (RMV)."},"28":{"q":"في ماساتشوستس، أي تظهير يجب أن يحمله السائق بالفعل (كشرط مسبق) قبل الحصول على تظهير الحافلة المدرسية (S)؟","options":["H (مواد خطرة)","P (ركاب)","N (مركبة صهريجية)","T (مقطورتان/ثلاث مقطورات)"],"explanation":"تشترط ولاية ماساتشوستس تظهير الركاب (P) كشرط مسبق للحصول على تظهير الحافلة المدرسية (S). ويجب على السائق اجتياز اختباري P وS المعرفيين واختبار مهارات الحافلة المدرسية. المصدر: 'فئات CDL والتظهيرات' و'التقدّم للحصول على رخصة متعلّم حافلة مدرسية' على Mass.gov (RMV)."},"29":{"q":"بموجب القواعد الفيدرالية التي تطبّقها Massachusetts RMV، كم يجب أن يحمل المتقدم رخصة المتعلّم التجارية قبل أن يكون مؤهلاً لإجراء اختبار مهارات CDL (اختبار الطريق)؟","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"explanation":"تشترط اللائحة الفيدرالية (49 CFR 383.25)، التي تطبّقها Massachusetts RMV، حمل CLP لمدة لا تقل عن 14 days قبل أن يتمكن المتقدم من إجراء اختبار المهارات. ويبدأ احتساب المدة من اليوم الذي تُصدر فيه الرخصة. المصدر: صفحة CLP لـ RMV على Mass.gov وFMCSA 49 CFR 383.25."},"30":{"q":"كم تبلغ مدة صلاحية رخصة المتعلّم التجارية (CLP) في ماساتشوستس قبل وجوب تجديدها أو إكمال اختبار المهارات؟","options":["90 days","180 days","1 year","2 years"],"explanation":"تكون CLP في ماساتشوستس صالحة لمدة 180 days. ويجوز تجديدها مرة واحدة لمدة 180 days إضافية دون إعادة إجراء الاختبار المعرفي العام، بما يتوافق مع الحدود الفيدرالية. المصدر: 'التقدّم للحصول على رخصة متعلّم تجارية (CLP)' على Mass.gov (RMV)."},"31":{"q":"أثناء القيادة برخصة متعلّم تجارية في ماساتشوستس، يجب أن يكون حامل CLP مصحوباً بشخص:","options":["عمره 25 عاماً على الأقل ويحمل أي رخصة قيادة","يحمل CDL صالحة من الفئة والتظهيرات المناسبة، جالساً بجانب السائق","مدرّب قيادة معتمد فقط","لديه خبرة قيادة تجارية لا تقل عن 5 سنوات"],"explanation":"لا يجوز لحامل CLP تشغيل CMV إلا عندما يكون مصحوباً بشخص يحمل CDL صالحة من الفئة والتظهيرات المناسبة، جالساً في المقعد الأمامي بجانب السائق. المصدر: صفحة CLP لـ RMV على Mass.gov و49 CFR 383.25."},"32":{"q":"أي مجموعة من المستندات يجب على المتقدم تقديمها إلى Massachusetts RMV لإثبات الأهلية للحصول على CDL أو CLP؟","options":["إثبات الهوية/الوجود القانوني، ورقم الضمان الاجتماعي، والإقامة في ماساتشوستس","بطاقة الضمان الاجتماعي فقط","جواز سفر ساري المفعول فقط","شهادة الثانوية العامة وإثبات الإقامة"],"explanation":"تشترط Massachusetts RMV إثبات الهوية والوجود القانوني في الولايات المتحدة، ورقم الضمان الاجتماعي، وإثبات الإقامة في ماساتشوستس لإصدار CLP/CDL. المصدر: متطلبات طلب CDL/CLP لـ RMV على Mass.gov و49 CFR 383.71."},"33":{"q":"تدريب السائق المبتدئ (ELDT) المطلوب قبل اختبار مهارات CDL من الفئة Class A لأول مرة في ماساتشوستس يجب أن يُكمل لدى مزوّد:","options":["معتمد من Massachusetts RMV فقط","مُدرَج في سجل مزوّدي التدريب التابع لـ FMCSA (TPR)","معتمد من وزارة التعليم الأمريكية","أي مدرسة قيادة مرخّصة في ماساتشوستس"],"explanation":"يجب إكمال ELDT لدى مزوّد مُدرَج في سجل مزوّدي التدريب التابع لـ FMCSA (TPR). ولا يجوز إلا للمزوّدين المسجّلين في TPR تقديم التدريب النظري والتدريب العملي خلف عجلة القيادة المطلوبين. المصدر: دليل 'تدريب السائق المبتدئ (ELDT)' على Mass.gov وFMCSA TPR (49 CFR Part 380)."},"34":{"q":"بالنسبة لتظهير المواد الخطرة (H) لأول مرة في ماساتشوستس، ما نوع ELDT الذي يجب إكماله ومتى؟","options":["تدريب نظري فقط، قبل إجراء الاختبار المعرفي","تدريب عملي خلف عجلة القيادة فقط، قبل اختبار المهارات","كلاهما النظري والعملي خلف عجلة القيادة، قبل اختبار الطريق","لا يُطلب ELDT لتظهير H"],"explanation":"بالنسبة لتظهير H، يتألف ELDT من تدريب نظري فقط ويجب إكماله قبل إجراء اختبار معرفة المواد الخطرة في الولاية. ولا يوجد اختبار مهارات منفصل لتظهير H. المصدر: دليل ELDT على Mass.gov وFMCSA TPR (49 CFR Part 380)."},"35":{"q":"السائق في ماساتشوستس الذي يعمل ضمن ماساتشوستس فقط ويجب أن يستوفي متطلبات التأهيل الطبي للولاية ينبغي أن يصدّق ذاتياً تحت أي فئة؟","options":["غير معفى بين الولايات (NI)","معفى بين الولايات (EI)","غير معفى داخل الولاية (NA)","معفى داخل الولاية (EA)"],"explanation":"تنطبق فئة غير معفى داخل الولاية (NA) على السائقين الذين يعملون في التجارة داخل الولاية فقط ويجب أن يستوفوا معايير التأهيل الطبي/السائق في ماساتشوستس ويحملوا شهادة فاحص طبي. المصدر: 'التصديق الذاتي لـ CDL' على Mass.gov (RMV) و49 CFR 383.71."},"36":{"q":"السائق الذي يصدّق ذاتياً كغير معفى بين الولايات (NI) في ماساتشوستس يجب أن يحتفظ في ملفه لدى RMV بشهادة طبية صالحة من فاحص:","options":["أي طبيب مرخّص في ماساتشوستس","مُدرَج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA","معتمد من صاحب عمل السائق","فاحص من موظفي Massachusetts RMV"],"explanation":"يجب على السائقين غير المعفيين بين الولايات اجتياز فحص DOT البدني الذي يجريه فاحص طبي مُدرَج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA والاحتفاظ بالشهادة الطبية سارية لدى RMV. المصدر: 'المعايير الطبية لـ CDL' على Mass.gov و49 CFR 391.41-391.43."},"37":{"q":"إلى جانب إكمال نظرية ELDT واجتياز الاختبار المعرفي، يتطلب تظهير المواد الخطرة (H) في ماساتشوستس أيضاً من المتقدم أن:","options":["يكمل اختبار طريق عملياً خلف عجلة القيادة للحمولات الخطرة","يجتاز تقييم تهديد أمني من TSA يشمل أخذ البصمات","يحمل تظهير الصهريج (N) أولاً","يكون عمره 25 عاماً على الأقل"],"explanation":"يتطلب تظهير H تقييم تهديد أمني من TSA، يشمل تقديم البصمات والبيانات الشخصية والخضوع لفحص جنائي/هجرة/قوائم مراقبة الإرهاب، إضافة إلى الاختبار المعرفي ونظرية ELDT. المصدر: 'فئات CDL والتظهيرات' على Mass.gov وبرنامج تظهير HazMat لدى TSA (49 CFR 1572)."},"38":{"q":"أي مجموعة من السائقين تخضع لمتطلبات تدريب السائق المبتدئ (ELDT) في ماساتشوستس؟","options":["فقط السائقون الذين يجدّدون CDL قائمة","السائقون الذين يحصلون على CDL من الفئة Class A أو Class B لأول مرة، أو يرفّعون من Class B إلى Class A، أو يحصلون على تظهير S أو P أو H لأول مرة","فقط السائقون من خارج الولاية الذين ينقلون CDL","فقط السائقون الذين تجاوزوا عمر 21 عاماً"],"explanation":"ينطبق ELDT على المتقدمين الذين يحصلون على CDL من الفئة Class A أو Class B لأول مرة، أو يرفّعون من Class B إلى Class A، أو يحصلون على تظهير الحافلة المدرسية (S) أو الركاب (P) أو المواد الخطرة (H) لأول مرة. المصدر: دليل 'تدريب السائق المبتدئ (ELDT)' على Mass.gov وFMCSA TPR (49 CFR Part 380)."},"39":{"q":"في ماساتشوستس، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده للشخص أن يشغّل مركبة آلية تجارية (CMV) بشكل قانوني؟","options":["0.08","0.04","0.02","0.00"],"explanation":"تتّبع ولاية ماساتشوستس المعيار الفيدرالي: يُعدّ تشغيل CMV بتركيز BAC يبلغ 0.04 أو أكثر مخالفة كبرى وانتهاكاً يؤدي إلى إسقاط الأهلية. وينطبق حد 0.08 على السائقين غير التجاريين. المصدر: دليل CDL لـ MA RMV، القسم 1 (إسقاط الأهلية)؛ 49 CFR 383.51."},"40":{"q":"بموجب قواعد CDL في ماساتشوستس، السائق الذي يشغّل CMV بتركيز BAC يبلغ 0.04 أو أكثر لأول مخالفة كبرى (وهو لا يحمل مواد خطرة موسومة بلوحات تحذيرية) يُسقَط حقه في الأهلية لأي مدة؟","options":["60 days","90 days","1 year","3 years"],"explanation":"تؤدي أول مخالفة كبرى، مثل قيادة CMV بتركيز BAC يبلغ 0.04 أو أكثر، إلى إسقاط الأهلية لمدة 1-year كحد أدنى (3 years إذا كان ينقل مواد خطرة موسومة بلوحات تحذيرية). المصدر: دليل CDL لـ MA RMV؛ M.G.L. c. 90F؛ 49 CFR 383.51."},"41":{"q":"في ماساتشوستس، إذا ارتكب سائق CDL أول مخالفة كبرى أثناء تشغيل CMV ينقل مواد خطرة موسومة بلوحات تحذيرية، تُرفع مدة إسقاط الأهلية إلى:","options":["1 year","2 years","3 years","5 years"],"explanation":"عندما تقع أول مخالفة كبرى أثناء كون CMV موسومة بلوحات تحذيرية للمواد الخطرة، يُرفع إسقاط الأهلية من 1 year إلى 3 years. المصدر: دليل CDL لـ MA RMV (إسقاط الأهلية)؛ 49 CFR 383.51(b)."},"42":{"q":"ما هي مدة إسقاط أهلية CDL في ماساتشوستس لثاني مخالفة كبرى (مثل ثاني قيادة تحت تأثير الكحول أو ثاني رفض)، ناشئة عن حوادث منفصلة؟","options":["3 years","10 years","مدى الحياة","5 years"],"explanation":"تؤدي ثاني مخالفة كبرى، بأي مزيج وناشئة عن حوادث منفصلة، إلى إسقاط أهلية CDL مدى الحياة. المصدر: دليل CDL لـ MA RMV؛ M.G.L. c. 90F؛ 49 CFR 383.51(b)."},"43":{"q":"في ماساتشوستس، بموجب قاعدة الموافقة الضمنية، سائق CDL الذي يرفض الخضوع لاختبار كحول (كيميائي) مطلوب أثناء تشغيل CMV يُعامَل على أنه ارتكب:","options":["مخالفة مرورية جسيمة (إسقاط أهلية 60 يوماً)","مخالفة بسيطة بغرامة فقط","مخالفة كبرى (إسقاط أهلية لسنة واحدة، 3 سنوات إذا كان ينقل مواد خطرة)","مخالفة معبر سكة حديد"],"explanation":"بتشغيل CMV، يمنح السائق موافقة ضمنية على اختبار الكحول. ويُعدّ رفض الاختبار مخالفة كبرى تحمل العقوبة نفسها لقيادة المركبة تحت التأثير: إسقاط أهلية لسنة واحدة (3 سنوات إذا كانت موسومة بلوحات تحذيرية للمواد الخطرة)، ومدى الحياة عند حدوثها للمرة الثانية. المصدر: دليل CDL لـ MA RMV؛ 49 CFR 383.51(b)؛ M.G.L. c. 90F."},"44":{"q":"كم عدد المخالفات المرورية الجسيمة خلال فترة 3 years (في حوادث منفصلة) التي تؤدي إلى إسقاط أهلية CDL لمدة 60 يوماً في ماساتشوستس؟","options":["1","2","3","4"],"explanation":"تؤدي ثاني مخالفة مرورية جسيمة خلال فترة 3 years إلى إسقاط أهلية لمدة 60 يوماً؛ وثالثة خلال 3 years تؤدي إلى 120 يوماً. ولا تؤدي مخالفة جسيمة واحدة بمفردها إلى إسقاط الأهلية. المصدر: دليل CDL لـ MA RMV؛ 49 CFR 383.51(c)."},"45":{"q":"في ماساتشوستس، ثلاث مخالفات مرورية جسيمة تُرتكب خلال فترة 3 years تؤدي إلى إسقاط أهلية CDL لمدة:","options":["60 days","90 days","120 days","180 days"],"explanation":"تؤدي ثالث مخالفة مرورية جسيمة خلال فترة 3 years إلى إسقاط أهلية لمدة 120 days (الثانية خلال 3 years تكون 60 days). المصدر: دليل CDL لـ MA RMV؛ 49 CFR 383.51(c)."},"46":{"q":"أي مما يلي يُصنّف كمخالفة مرورية جسيمة لسائق CDL في ماساتشوستس؟","options":["قيادة CMV بتركيز BAC يبلغ 0.04 أو أكثر","رفض اختبار الكحول","القيادة بسرعة 15 mph أو أكثر فوق حد السرعة المعلن","قيادة CMV أثناء تعليق CDL الخاص بك"],"explanation":"تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد هو مخالفة مرورية جسيمة. أما القيادة بتركيز BAC يبلغ 0.04+، ورفض الاختبار، والقيادة برخصة CDL معلّقة فجميعها مخالفات كبرى، وليست مخالفات جسيمة. المصدر: دليل CDL لـ MA RMV؛ 49 CFR 383.51(c)."},"47":{"q":"بموجب قواعد CDL في ماساتشوستس، انتهاك قانون يحظر الكتابة النصية (التراسل) أثناء قيادة CMV يُصنّف على أنه:","options":["مخالفة كبرى","مخالفة مرورية جسيمة","انتهاك أمر إخراج من الخدمة","مخالفة معبر سكة حديد"],"explanation":"الكتابة النصية أثناء قيادة CMV مخالفة مرورية جسيمة؛ تراكم اثنتين خلال 3 سنوات يؤدي إلى إسقاط أهلية لمدة 60 يوماً، وثلاث خلال 3 سنوات يؤدي إلى 120 يوماً. المصدر: دليل CDL لـ MA RMV؛ 49 CFR 383.51(c)؛ M.G.L. c. 90 sec. 13B."},"48":{"q":"استخدام هاتف محمول باليد أثناء قيادة CMV يُعامَل، لأغراض إسقاط أهلية CDL في ماساتشوستس، على أنه:","options":["مخالفة مرورية جسيمة","مخالفة كبرى","انتهاك إخراج من الخدمة","ليس مخالفة تؤدي إلى إسقاط الأهلية"],"explanation":"استخدام هاتف محمول باليد أثناء قيادة CMV هو مخالفة مرورية جسيمة تُحتسب ضمن عتبتي 2 خلال 3 سنوات (60 يوماً) و3 خلال 3 سنوات (120 يوماً) لإسقاط الأهلية. المصدر: دليل CDL لـ MA RMV؛ 49 CFR 383.51(c)؛ M.G.L. c. 90 sec. 13B."},"49":{"q":"بموجب قانون ماساتشوستس للاستخدام دون اليدين (M.G.L. c. 90 sec. 13B)، تكون غرامة أول مخالفة لاستخدام جهاز محمول باليد:","options":["$35","$100","$250","$500"],"explanation":"يحدد قانون ماساتشوستس للاستخدام دون اليدين غرامات قدرها $100 لأول مخالفة، و$250 للثانية، و$500 للثالثة أو ما بعدها، مع برنامج إلزامي للقيادة المشتتة للمخالفين المتكررين. المصدر: M.G.L. c. 90 sec. 13B."},"50":{"q":"بموجب قانون ماساتشوستس للاستخدام دون اليدين، تكون غرامة المخالفة الثالثة أو ما بعدها لاستخدام جهاز محمول باليد:","options":["$100","$250","$500","$1,000"],"explanation":"تتصاعد الغرامات إلى $500 للمخالفة الثالثة أو ما بعدها ($100 للأولى، $250 للثانية). كما تتطلب المخالفة الثانية أو ما بعدها إكمال برنامج للقيادة المشتتة. المصدر: M.G.L. c. 90 sec. 13B."},"51":{"q":"ما هي مدة إسقاط الأهلية لأول مخالفة معبر سكة حديد-طريق سريع يرتكبها سائق CDL في ماساتشوستس؟","options":["لا تقل عن 30 يوماً","لا تقل عن 60 يوماً","لا تقل عن 120 يوماً","لا تقل عن سنة واحدة"],"explanation":"تؤدي أول مخالفة معبر سكة حديد-طريق سريع إلى إسقاط أهلية لا يقل عن 60 يوماً. المصدر: دليل CDL لـ MA RMV؛ 49 CFR 383.51(d)."},"52":{"q":"بالنسبة لسائق CDL في ماساتشوستس، ثاني مخالفة معبر سكة حديد-طريق سريع خلال فترة 3 years تؤدي إلى إسقاط أهلية مدته:","options":["لا تقل عن 60 يوماً","لا تقل عن 120 يوماً","لا تقل عن سنة واحدة","لا تقل عن 3 سنوات"],"explanation":"تؤدي ثاني مخالفة معبر سكة حديد خلال 3 years إلى إسقاط أهلية لا يقل عن 120 يوماً (الأولى 60 يوماً، والثالثة خلال 3 years لا تقل عن سنة واحدة). المصدر: دليل CDL لـ MA RMV؛ 49 CFR 383.51(d)."},"53":{"q":"ثالث مخالفة معبر سكة حديد-طريق سريع خلال فترة 3 years تُسقط أهلية سائق CDL في ماساتشوستس لمدة:","options":["لا تقل عن 120 يوماً","لا تقل عن 180 يوماً","لا تقل عن سنة واحدة","مدى الحياة"],"explanation":"تؤدي ثلاث مخالفات معبر سكة حديد خلال فترة 3 years إلى إسقاط أهلية لا يقل عن سنة واحدة. المصدر: دليل CDL لـ MA RMV؛ 49 CFR 383.51(d)."},"54":{"q":"في ماساتشوستس، أول إدانة بانتهاك أمر إخراج سائق من الخدمة (OOS) (دون مواد خطرة، دون ركاب) تؤدي إلى إسقاط أهلية مدته:","options":["لا يقل عن 60 يوماً","لا يقل عن 90 يوماً","لا يقل عن 180 يوماً ولا يزيد عن سنة واحدة","لا يقل عن سنة واحدة ولا يزيد عن 5 سنوات"],"explanation":"يؤدي أول انتهاك لأمر الإخراج من الخدمة إلى إسقاط أهلية لا يقل عن 180 يوماً ولا يزيد عن سنة واحدة. المصدر: دليل CDL لـ MA RMV؛ 49 CFR 383.51(e)."},"55":{"q":"ثاني انتهاك لأمر الإخراج من الخدمة خلال فترة 10 years يُسقط أهلية سائق CDL في ماساتشوستس لمدة:","options":["لا تقل عن 180 يوماً ولا تزيد عن سنة واحدة","لا تقل عن سنتين ولا تزيد عن 5 سنوات","لا تقل عن سنة واحدة ولا تزيد عن 3 سنوات","مدى الحياة"],"explanation":"يؤدي ثاني انتهاك لأمر الإخراج من الخدمة خلال 10 years إلى إسقاط أهلية لا يقل عن سنتين ولا يزيد عن 5 سنوات. المصدر: دليل CDL لـ MA RMV؛ 49 CFR 383.51(e)."},"56":{"q":"أول انتهاك لأمر الإخراج من الخدمة أثناء نقل مواد خطرة موسومة بلوحات تحذيرية أو تشغيل مركبة مصممة لـ 16+ راكباً يؤدي إلى إسقاط أهلية CDL في ماساتشوستس مدته:","options":["لا يقل عن 180 يوماً ولا يزيد عن سنة واحدة","لا يقل عن 180 يوماً ولا يزيد عن سنتين","لا يقل عن سنة واحدة ولا يزيد عن 3 سنوات","لا يقل عن 3 سنوات ولا يزيد عن 5 سنوات"],"explanation":"يحمل أول انتهاك للإخراج من الخدمة يتعلق بمواد خطرة موسومة بلوحات تحذيرية أو مركبة لـ 16+ راكباً عقوبة مشددة: لا يقل عن 180 يوماً ولا يزيد عن سنتين. المصدر: دليل CDL لـ MA RMV؛ 49 CFR 383.51(e)."},"57":{"q":"أي مما يلي يُعدّ مخالفة كبرى تُسقط أهلية سائق CDL في ماساتشوستس، حتى عند ارتكابها في المركبة الشخصية (غير التجارية) للسائق؟","options":["الاقتراب أكثر من اللازم","تغيير حارة غير سليم","مغادرة مكان الحادث","استخدام هاتف محمول باليد"],"explanation":"مغادرة مكان الحادث مخالفة كبرى تُسقط أهلية CDL سواء ارتُكبت في CMV أو مركبة شخصية. أما الأخرى فهي مخالفات مرورية جسيمة فقط عند ارتكابها أثناء قيادة CMV. المصدر: دليل CDL لـ MA RMV؛ 49 CFR 383.51(b)."},"58":{"q":"سائق CDL في ماساتشوستس يستخدم أي مركبة آلية لارتكاب جناية تتعلق بتصنيع أو توزيع أو صرف مادة خاضعة للرقابة تُسقط أهليته لمدة:","options":["1 year","3 years","10 years","مدى الحياة دون إعادة استحقاق"],"explanation":"يؤدي استخدام مركبة آلية لارتكاب جناية تتعلق بالمواد الخاضعة للرقابة (التصنيع أو التوزيع أو الصرف) إلى إسقاط أهلية مدى الحياة غير قابل لإعادة الاستحقاق. المصدر: دليل CDL لـ MA RMV؛ M.G.L. c. 90F؛ 49 CFR 383.51(b)."},"59":{"q":"بموجب قانون معابر السكك الحديدية في ولاية ماساتشوستس، يجب على حافلة المدرسة أو المركبة التي تحمل متفجرات أو سوائل قابلة للاشتعال كحمولة أن تتوقف توقفًا تامًا ضمن أي نطاق من أقرب قضيب سكة؟","options":["ليس أقل من 15 feet وليس أكثر من 50 feet","ليس أقل من 10 feet وليس أكثر من 40 feet","ليس أقل من 5 feet وليس أكثر من 25 feet","ليس أقل من 20 feet وليس أكثر من 75 feet"],"explanation":"تشترط قوانين ماساتشوستس العامة الفصل c. 90, s. 15 على حافلة المدرسة أو المركبة التي تحمل متفجرات أو سوائل قابلة للاشتعال كحمولة أن تتوقف على مسافة ليست أقل من 15 feet وليست أكثر من 50 feet من أقرب مسار قبل العبور. المصدر: MGL c. 90, s. 15."},"60":{"q":"على أي قانون من قوانين ماساتشوستس يستند قانون 'الانتقال جانبًا' (Move Over) في الولاية، وما هو المتطلب الأساسي عند الاقتراب من مركبة طوارئ أو صيانة أو إنقاذ متوقفة تعرض أضواءً وامضة؟","options":["MGL c. 89, s. 7C؛ انتقل إلى مسار غير مجاور إن أمكن، أو خفّف السرعة إلى سرعة آمنة ومعقولة إن لم تتمكن","MGL c. 90, s. 14؛ توقف توقفًا تامًا حتى يتم إطفاء الأضواء","MGL c. 85, s. 2؛ أطلق بوقك واستمر بالسرعة المعلنة","MGL c. 90, s. 17؛ خفّف السرعة إلى ما لا يزيد عن 20 mph وابقَ في مسارك"],"explanation":"يشترط قانون الانتقال جانبًا في ماساتشوستس، MGL c. 89, s. 7C (الساري اعتبارًا من مارس 2009)، على السائقين الذين يقتربون من مركبة طوارئ أو صيانة أو إنقاذ متوقفة ذات أضواء وامضة الانتقال إلى مسار غير مجاور عندما يكون ذلك آمنًا، وإن تعذّر ذلك، تخفيف السرعة إلى سرعة آمنة ومعقولة. المصدر: MGL c. 89, s. 7C؛ Mass.gov Move Over Law."},"61":{"q":"ما هي العقوبة (الغرامة) في ماساتشوستس عن مخالفة قانون الانتقال جانبًا بموجب MGL c. 89, s. 7C؟","options":["$100","$35","$250","$500"],"explanation":"تترتب على مخالفة قانون الانتقال جانبًا في ماساتشوستس (MGL c. 89, s. 7C) غرامة قدرها $100. المصدر: MGL c. 89, s. 7C؛ صفحة قانون الانتقال جانبًا الخاصة بشرطة ولاية ماساتشوستس."},"62":{"q":"في ماساتشوستس، متى لا يُطلب من السائق المقترب من حافلة مدرسية متوقفة وأضواؤها الحمراء وامضة أن يتوقف؟","options":["عند الاقتراب من الاتجاه المعاكس على طريق سريع مقسّم","عندما يسير السائق بسرعة أقل من 20 mph","عندما يكون السائق على بُعد أكثر من طولَي سيارة خلف الحافلة","عندما تتوقف الحافلة داخل منطقة تجارية"],"explanation":"بموجب MGL c. 90, s. 14، يجب على كل سائق أن يتوقف قبل الوصول إلى حافلة مدرسية تعرض أضواءً حمراء وامضة، باستثناء حالة الاقتراب من الاتجاه المعاكس على طريق سريع مقسّم. المصدر: MGL c. 90, s. 14."},"63":{"q":"ما هو الحد الأدنى للغرامة في ماساتشوستس عن المخالفة الأولى لعدم التوقف لحافلة مدرسية متوقفة وأضواؤها الحمراء وامضة، أو لتجاوزها بشكل غير قانوني؟","options":["$250","$100","$50","$500"],"explanation":"بموجب MGL c. 90, s. 14، تترتب على المخالفة الأولى لقانون التوقف للحافلات المدرسية غرامة لا تقل عن $250؛ أما المخالفة الثانية فتتراوح بين $500-$1,000 مع تعليق الرخصة لمدة 6 أشهر. المصدر: MGL c. 90, s. 14."},"64":{"q":"على طريق سريع مستوٍ ومستقيم ومقسّم، أين يجب على سائق CDL وضع المثلثات العاكسة الثلاثة للطوارئ بعد التوقف على الكتف؟","options":["ضمن 10 feet من المؤخرة، وعلى بُعد حوالي 100 feet إلى المؤخرة، وعلى بُعد حوالي 200 feet إلى المؤخرة","ضمن 25 feet، وعلى بُعد حوالي 75 feet، وعلى بُعد حوالي 150 feet إلى المؤخرة","ضمن 5 feet، وعلى بُعد حوالي 50 feet، وعلى بُعد حوالي 100 feet إلى المؤخرة","ضمن 15 feet، وعلى بُعد حوالي 150 feet، وعلى بُعد حوالي 300 feet إلى المؤخرة"],"explanation":"يوجّه دليل CDL في ماساتشوستس (المعتمِد للائحة 49 CFR 392.22) إلى وضع مثلث واحد ضمن 10 feet من مؤخرة المركبة، وواحد على بُعد حوالي 100 feet إلى المؤخرة، وواحد على بُعد حوالي 200 feet إلى المؤخرة على طريق مقسّم أو باتجاه واحد. المصدر: دليل CDL في ماساتشوستس، القيادة بأمان (49 CFR 392.22)."},"65":{"q":"إذا توقفت مركبة تجارية على بُعد 500 feet من تلة أو منحنى أو عائق آخر يحدّ من الرؤية، فكيف يجب على سائق CDL تعديل وضع مثلثات الطوارئ؟","options":["حرّك المثلث الأبعد إلى الخلف ليكون على بُعد 100 إلى 500 feet من المركبة، باتجاه العائق، لإعطاء السائقين المقتربين تحذيرًا أكبر","أزِل جميع المثلثات واعتمد على الأضواء الوامضة الرباعية فقط","ضع المثلثات الثلاثة جميعها ضمن 50 feet من المركبة لتبقى متجمعة","ضع مثلثًا واحدًا فقط، خلف المركبة مباشرة، على بُعد لا يزيد عن 10 feet"],"explanation":"وفقًا لدليل CDL في ماساتشوستس (49 CFR 392.22)، إذا توقفت مركبة على بُعد 500 feet من منحنى أو قمة تلة أو عائق آخر، فيجب وضع جهاز التحذير المتجه نحو العائق على بُعد 100 إلى 500 feet من المركبة لإعطاء حركة المرور المقتربة تحذيرًا كافيًا. المصدر: دليل CDL في ماساتشوستس؛ 49 CFR 392.22."},"66":{"q":"على طريق ماساتشوستس السريع برسوم (I-90) بين التقاطع 14 في ويستون والتقاطع 9 في ستربريدج، أي مسارات السير يجوز لمركبة تجارية ثقيلة (غير الحافلة) استخدامها؟","options":["فقط المسار الأقصى يمينًا، أو المسار المجاور التالي عند التجاوز والتخطي","أي مسار، دون أي قيد على مسارات الشاحنات على الطريق السريع برسوم","فقط المسار الأقصى يسارًا لإبقاء حركة المرور الأبطأ بعيدة","فقط المسارين الأقصى يسارًا خلال ساعات النهار"],"explanation":"تقيّد اللائحة 700 CMR 7.09 المركبة التجارية الثقيلة (غير الحافلة) بين التقاطع 14 (ويستون) والتقاطع 9 (ستربريدج) بالمسار الأقصى يمينًا للسير، أو المسار المجاور التالي فقط عند التجاوز والتخطي، إلا في حالة الطوارئ. المصدر: 700 CMR 7.09."},"67":{"q":"لماذا تُمنع الشاحنات الصندوقية وشاحنات النقل وغيرها من المركبات التجارية من السير على Storrow Drive و Soldiers Field Road في بوسطن (سبب ما يُسمى 'Storrowing')؟","options":["إنهما طريقان تابعان لـ DCR مخصصان 'للسيارات فقط' وذوا ارتفاعات منخفضة للجسور العلوية (نحو 10 feet أو أقل)، والشاحنات/الحافلات ممنوعة","بهما رسوم لا تقبل سوى أجهزة الإرسال التجارية","إنهما محجوزان للمركبات عالية الإشغال خلال ساعة الذروة","بهما حد سرعة معلن للشاحنات منخفض جدًا لشحنات الولايات المتعددة"],"explanation":"إن Storrow Drive و Soldiers Field Road طريقان (parkways) تابعان لإدارة الحفظ والترفيه (DCR) مقتصران على مركبات الركاب ('السيارات فقط')، بارتفاعات جسور منخفضة تبلغ نحو 10 feet أو أقل؛ والشاحنات والحافلات والمركبات المماثلة ممنوعة، وكثيرًا ما تصطدم الشاحنات المفرطة الارتفاع بالجسور العلوية. المصدر: 302 CMR 11.00؛ حملة Storrowing على Mass.gov / DCR."},"68":{"q":"خارج منطقة كثيفة السكان أو منطقة تجارية على طريق ماساتشوستس غير مقسّم دون حد سرعة معلن، ما هي السرعة القانونية التي يُفترض فوقها أنك تتجاوز السرعة؟","options":["40 mph","30 mph","50 mph","55 mph"],"explanation":"بموجب MGL c. 90, s. 17، على طريق غير مقسّم خارج منطقة كثيفة السكان أو منطقة تجارية دون حد معلن، يُعد تجاوز 40 mph لمسافة لا تقل عن ربع ميل دليلًا ظاهرًا على تجاوز السرعة (والرقم الخاص بالطريق المقسّم هو 50 mph). المصدر: MGL c. 90, s. 17."},"69":{"q":"داخل منطقة كثيفة السكان أو منطقة تجارية في ماساتشوستس، ما هو حد السرعة القانوني حيث لا يوجد حد معلن؟","options":["30 mph","25 mph","20 mph","35 mph"],"explanation":"بموجب MGL c. 90, s. 17، السرعة القانونية في منطقة كثيفة السكان أو منطقة تجارية حيث لا يوجد حد خاص معلن هي 30 mph (وتُعرَّف المنطقة الكثيفة السكان بأنها إقليم تتباعد فيه المنازل السكنية بمتوسط أقل من 200 feet). المصدر: MGL c. 90, s. 17."},"70":{"q":"في ماساتشوستس، يجب على سائق الحافلة المدرسية المتوقف عند معبر سكة حديدية أن يقوم بأي مما يلي بالإضافة إلى التوقف في نطاق 15 إلى 50 قدمًا؟","options":["فتح باب الخدمة، والتأكد من أن العبور آمن، ثم إغلاق الباب قبل المتابعة","إطلاق البوق ثلاث مرات قبل العبور","وضع مثلثات عاكسة على كل جانب من المسارات","التحويل إلى أعلى ترس متاح قبل العبور"],"explanation":"بموجب MGL c. 90, s. 15، يجب على مشغّل الحافلة المدرسية أن يتوقف ضمن 15-50 feet من أقرب قضيب سكة، ويفتح باب الخدمة، ويتأكد من أن العبور آمن، ثم يغلق الباب قبل المتابعة. المصدر: MGL c. 90, s. 15."},"71":{"q":"وفقًا لدليل CDL في ماساتشوستس، ماذا يجب على السائق أن يفعل بالتروس عند قيادة مركبة تجارية عبر مسارات السكك الحديدية؟","options":["العبور بترس منخفض بما يكفي لاجتياز المسارات دون تبديل التروس","التحويل تصاعديًا عبر التروس أثناء وجوده على المسارات لاجتيازها أسرع","التحويل إلى الوضع المحايد والانزلاق عبر المسارات","التحويل إلى ترس أدنى في منتصف المعبر لتخفيف السرعة"],"explanation":"يوجّه دليل CDL في ماساتشوستس السائقين إلى اختيار ترس يتيح للمركبة عبور المسارات بالكامل دون تبديل التروس، وعدم تغيير التروس أثناء وجودها على المسارات. المصدر: دليل CDL في ماساتشوستس، معابر السكك الحديدية (49 CFR 392.10)."},"72":{"q":"ما هو أقصى وزن إجمالي للمركبة يجوز لشاحنة أن تعمل به في ماساتشوستس على شبكة الطرق السريعة الفيدرالية دون تصريح وزن زائد؟","options":["80,000 pounds","73,280 pounds","99,000 pounds","100,000 pounds"],"explanation":"تتبع ماساتشوستس الحد الفيدرالي البالغ 80,000 pounds للوزن الإجمالي للمركبة دون تصريح خاص؛ أما الحمولات التي تتجاوز ذلك فتتطلب تصريح وزن زائد من MassDOT. المصدر: تصاريح الشاحنات التجارية من MassDOT؛ حدود الوزن الفيدرالية المطبّقة في ماساتشوستس."},"73":{"q":"دون تصريح حجم زائد، ما هو أقصى عرض قانوني مسموح به للمركبة/الحمولة على طرق ماساتشوستس السريعة؟","options":["8 feet 6 inches (102 inches)","8 feet 0 inches (96 inches)","10 feet 0 inches (120 inches)","9 feet 0 inches (108 inches)"],"explanation":"الحد الأقصى القانوني للعرض في ماساتشوستس دون تصريح حجم زائد هو 8 feet 6 inches (102 inches)؛ والحمولات الأعرض تتطلب تصريح حجم زائد من MassDOT. المصدر: لوائح الحجم/الوزن الزائد من MassDOT؛ Mass.gov تصاريح الشاحنات التجارية."},"74":{"q":"دون تصريح حجم زائد، ما هو أقصى ارتفاع قانوني للمركبة والحمولة على طرق ماساتشوستس السريعة؟","options":["13 feet 6 inches","13 feet 0 inches","14 feet 0 inches","12 feet 6 inches"],"explanation":"تحدد ماساتشوستس الحد الأقصى القانوني للارتفاع بـ 13 feet 6 inches؛ والحمولات الأطول تتطلب تصريح حجم زائد من MassDOT وقد تحتاج إلى مسح للمسار. المصدر: لوائح الحجم/الوزن الزائد من MassDOT؛ Mass.gov تصاريح الشاحنات التجارية."},"75":{"q":"على طريق ماساتشوستس السريع برسوم، كيف يتعامل قيد مسار المركبات التجارية الثقيلة بين ويستون وستربريدج مع الحافلات؟","options":["الحافلات معفاة من ذلك القيد المقتصر على المسار الأيمن","يجب على الحافلات البقاء في المسار الأيسر في جميع الأوقات","الحافلات ممنوعة كليًا من ذلك المقطع","يجب على الحافلات السير ليلًا فقط"],"explanation":"بموجب 700 CMR 7.09، يطبَّق القيد المقتصر على المسار الأيمن بين التقاطع 14 (ويستون) والتقاطع 9 (ستربريدج) على المركبات التجارية الثقيلة 'غير الحافلة'، لذا فإن الحافلات معفاة من ذلك القيد بعينه. المصدر: 700 CMR 7.09."},"76":{"q":"بموجب قانون ماساتشوستس، بعد أن يتوقف سائق مُلزَم بالتوقف لحافلة مدرسية، متى يجوز لذلك السائق المتابعة؟","options":["عندما يتم إيقاف إشارات التحذير الحمراء الوامضة للحافلة، ما لم يوجّهه ضابط شرطة بخلاف ذلك","بعد الانتظار لمدة ثابتة قدرها 10 ثوانٍ بصرف النظر عن الأضواء","حالما تبدأ الأضواء الكهرمانية (الصفراء) للحافلة بالوميض","فورًا، طالما لا يوجد أطفال ظاهرون"],"explanation":"يشترط MGL c. 90, s. 14 على السائق المتوقف أن يبقى متوقفًا حتى يتم إيقاف الإشارات الحمراء الوامضة للحافلة المدرسية، ما لم يوجّهه ضابط شرطة بالمتابعة. المصدر: MGL c. 90, s. 14."},"77":{"q":"بموجب MGL c. 90, s. 14، إلى أي مدى من القرب يجوز لمركبة أن تسير خلف حافلة مدرسية على طريق عام في ماساتشوستس؟","options":["ليس أقرب من 100 feet","ليس أقرب من 50 feet","ليس أقرب من 200 feet","ليس أقرب من 25 feet"],"explanation":"يمنع MGL c. 90, s. 14 تشغيل مركبة ضمن 100 feet خلف حافلة مدرسية (إلا عند تجاوزها وتخطيها حيث يُسمح بذلك). المصدر: MGL c. 90, s. 14."},"78":{"q":"أي جهة تصدر رخص القيادة التجارية (CDLs) في ماساتشوستس؟","options":["سجل المركبات الآلية (RMV)، وهو جزء من MassDOT","الإدارة الفيدرالية لسلامة ناقلات النقل بالشاحنات (FMCSA)","إدارة السلامة العامة في ماساتشوستس","قسم المركبات التجارية بشرطة ولاية ماساتشوستس"],"explanation":"في ماساتشوستس، تُصدر رخص CDL عن طريق سجل المركبات الآلية (RMV)، وهو شعبة تابعة لإدارة النقل في ماساتشوستس (MassDOT). تضع FMCSA المعايير الفيدرالية لكنها لا تصدر الرخصة. المصدر: صفحات Mass.gov RMV لرخص القيادة التجارية (CDL)."},"79":{"q":"قبل أن تتمكن من إجراء أي اختبار مهارات (طريق) لرخصة CDL في ماساتشوستس، يجب عليك أولًا الحصول على أي مستند؟","options":["تصريح المتعلّم التجاري (CLP)","رخصة CDL كاملة من الفئة A","سلطة تشغيل فيدرالية بين الولايات (رقم MC)","تصديق المواد الخطرة"],"explanation":"لتشغيل مركبة آلية تجارية لأغراض التدريب وللتأهل لاختبار المهارات، يجب على المتقدّم في ماساتشوستس أولًا اجتياز اختبار (اختبارات) المعرفة والحصول على تصريح المتعلّم التجاري (CLP). المصدر: صفحات Mass.gov RMV لـ CDL؛ 49 CFR 383."},"80":{"q":"كم يجب على حامل CLP في ماساتشوستس أن ينتظر بعد إصدار CLP قبل أن يصبح مؤهلًا لإجراء اختبار مهارات CDL؟","options":["14 days على الأقل","24 hours على الأقل","30 days على الأقل","60 days على الأقل"],"explanation":"يجب الاحتفاظ بـ CLP لمدة 14 days كحد أدنى قبل أن يتمكن المتقدّم من إجراء اختبار مهارات CDL. وهذا متطلب فيدرالي (49 CFR 383.37) تطبّقه ماساتشوستس. المصدر: صفحات Mass.gov RMV لـ CDL؛ 49 CFR 383.37."},"81":{"q":"كم مدة صلاحية تصريح المتعلّم التجاري (CLP) في ماساتشوستس؟","options":["180 days، قابلة للتجديد مرة واحدة لمدة 180 days إضافية","30 days، دون السماح بأي تجديد","سنة واحدة، قابلة للتجديد مرتين","90 days، قابلة للتجديد مرة واحدة لمدة 90 days إضافية"],"explanation":"تصريح CLP في ماساتشوستس صالح لمدة 180 days ويجوز تجديده مرة واحدة لمدة 180 days إضافية دون إعادة إجراء اختبارات المعرفة؛ وبعد ذلك يجب على المتقدّم إعادة التقديم. المصدر: صفحات Mass.gov RMV لـ CDL؛ 49 CFR 383.25."},"82":{"q":"يتكوّن اختبار مهارات CDL في ماساتشوستس من أي ثلاثة أجزاء؟","options":["الفحص قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","الامتحان التحريري، وفحص النظر، والقيادة على الطريق","فحص فرامل الهواء، ومناولة المواد الخطرة، والقيادة على الطريق","الوصل/الفصل، ومراجعة سجل القيادة، والقيادة على الطريق"],"explanation":"يتألف اختبار مهارات CDL في ماساتشوستس من ثلاثة أقسام: الفحص قبل الرحلة (فحص المركبة)، والتحكم الأساسي بالمركبة (مهارات التحكم مثل الرجوع للخلف)، واختبار القيادة على الطريق. المصدر: ورقة معلومات اختبار مهارات CDL من Mass.gov RMV / معيار اختبار مهارات CDL المحدّث."},"83":{"q":"كم عدد فئات الإقرار الذاتي التي يجب على المتقدّم لـ CDL/CLP في ماساتشوستس الاختيار من بينها عند الإقرار بنوع القيادة التي يؤدّيها؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"تشترط القواعد الفيدرالية وقواعد ماساتشوستس على السائق أن يقرّ ذاتيًا بإحدى أربع فئات من التجارة. المصدر: Mass.gov 'الإقرار الذاتي لرخصة القيادة التجارية (CDL)'؛ 49 CFR 383.71."},"84":{"q":"أي مما يلي يُعد إحدى فئات الإقرار الذاتي الأربع لـ CDL المستخدمة في ماساتشوستس؟","options":["بين الولايات غير المستثناة (Non-Excepted Interstate, NI)","تجاري مقيّد (Restricted Commercial, RC)","مشغّل فيدرالي مستثنى (Federal Excepted Operator, FEO)","ناقل محدود داخل الولاية (Limited Intrastate Hauler, LIH)"],"explanation":"الفئات الأربع هي: بين الولايات غير المستثناة (NI)، وبين الولايات المستثناة (EI)، وداخل الولاية غير المستثناة (NA)، وداخل الولاية المستثناة (EA). الخيارات الأخرى ليست فئات حقيقية. المصدر: Mass.gov الإقرار الذاتي لـ CDL؛ 49 CFR 383.71."},"85":{"q":"بموجب قواعد ماساتشوستس/FMCSA، السائق الذي يقرّ ذاتيًا بأنه 'بين الولايات غير المستثنى (NI)' يدلي بأي بيان عن تشغيله؟","options":["أنه يعمل عبر حدود الولايات ويجب أن يستوفي متطلبات بطاقة DOT الطبية الفيدرالية","أنه يعمل فقط داخل ماساتشوستس ولا يحتاج إلى شهادة طبية","أنه يعمل عبر حدود الولايات لكنه معفى من المتطلبات الطبية","أنه يعمل فقط داخل ماساتشوستس ويستوفي فقط القواعد الطبية للولاية"],"explanation":"تعني 'بين الولايات غير المستثنى (NI)' أن السائق يعمل (أو يتوقع أن يعمل) في التجارة بين الولايات ويُطلب منه استيفاء متطلبات شهادة الفاحص الطبي الفيدرالي DOT. المصدر: Mass.gov الإقرار الذاتي لـ CDL؛ 49 CFR 383.71/391."},"86":{"q":"السائق الذي يقرّ ذاتيًا بأنه 'داخل الولاية المستثنى (EA)' في ماساتشوستس يشير إلى أي مما يلي؟","options":["أنه يعمل فقط داخل ماساتشوستس وغير مُلزَم باستيفاء متطلبات بطاقة DOT الطبية الفيدرالية","أنه يعمل عبر حدود الولايات ويجب أن يحمل بطاقة طبية فيدرالية","أنه يعمل فقط داخل ماساتشوستس ويجب أن يحمل بطاقة DOT طبية فيدرالية","أنه مقيّد بنقل المواد الخطرة فقط"],"explanation":"تعني 'داخل الولاية المستثنى (EA)' أن السائق يعمل فقط في التجارة داخل الولاية ومستثنى من متطلبات بطاقة DOT الطبية الفيدرالية. المصدر: Mass.gov الإقرار الذاتي لـ CDL؛ 49 CFR 383.71."},"87":{"q":"عندما يجتاز سائق CDL في ماساتشوستس من فئة 'بين الولايات غير المستثنى' الفحص الطبي DOT، ما المستند الذي يصدره الفاحص الطبي المعتمد؟","options":["شهادة الفاحص الطبي (النموذج MCSA-5876)","إعفاء نظر من الفئة D من RMV في ماساتشوستس","خطاب إعفاء فيدرالي من ساعات الخدمة","شهادة سلطة تشغيل من FMCSA"],"explanation":"يُصدر الفاحص من السجل الوطني لـ FMCSA الذي يجد السائق مؤهلًا شهادة الفاحص الطبي (النموذج MCSA-5876). المصدر: Mass.gov الإقرار الذاتي لـ CDL / التصديق الطبي؛ السجل الوطني لـ FMCSA."},"88":{"q":"الفاحص الطبي لـ CDL في ماساتشوستس الذي يجري الفحوص الطبية DOT يجب أن يكون مدرَجًا أين؟","options":["في السجل الوطني للفاحصين الطبيين المعتمدين لدى FMCSA","في قائمة الأطباء المعتمدين لدى RMV في ماساتشوستس","في قائمة CDL الخاصة بمجلس تسجيل الطب في ماساتشوستس","في قائمة مزوّدي شعبة الطرق السريعة بـ MassDOT"],"explanation":"يجب أن تُجرى الفحوص الطبية DOT لأغراض CDL من قِبل فاحص طبي مدرَج في السجل الوطني للفاحصين الطبيين المعتمدين لدى FMCSA. المصدر: Mass.gov الإقرار الذاتي لـ CDL؛ السجل الوطني لـ FMCSA."},"89":{"q":"اعتبارًا من منتصف عام 2025، كيف تصل معلومات التصديق الطبي لمعظم سائقي CDL في ماساتشوستس إلى RMV؟","options":["إلكترونيًا من السجل الوطني لـ FMCSA، بحيث لا حاجة عادةً لتقديم بطاقة ورقية","فقط عن طريق إرسال السائق بطاقة ورقية بالبريد إلى RMV خلال 5 days","فقط عن طريق إرسال صاحب العمل البطاقة بالفاكس إلى MassDOT","تلقائيًا من شركة تأمين السائق"],"explanation":"ابتداءً من 23 يونيو 2025، يتلقى RMV معلومات التصديق الطبي إلكترونيًا من السجل الوطني لـ FMCSA، بحيث لا يحتاج معظم السائقين إلى تقديم نسخة ورقية (وقد يظل السائقون داخل الولاية فقط بحاجة إلى تقديم نسخة إن لم يتم تحميلها). المصدر: Mass.gov الإقرار الذاتي لـ CDL."},"90":{"q":"أي تدريب يجب على المتقدّم لأول مرة من الفئة A أو الفئة B في ماساتشوستس إكماله قبل أن يحدد RMV موعد اختبار مهارات CDL؟","options":["تدريب السائقين المبتدئين (ELDT) من مزوّد مسجّل لدى FMCSA","دورة قيادة دفاعية مدتها 40 ساعة من MassDOT","تدريب مهني تديره الولاية في مركز خدمة RMV","توجيه سلامة طرق صادر عن صاحب العمل فقط"],"explanation":"منذ 7 فبراير 2022، يجب على المتقدّمين لأول مرة من الفئة A/B (وكذلك تصديقات S أو P أو H لأول مرة) إكمال تدريب السائقين المبتدئين (ELDT) من مزوّد مدرَج في سجل مزوّدي التدريب لدى FMCSA قبل أن يحدد RMV موعد اختبار المهارات. المصدر: دليل Mass.gov لـ ELDT؛ 49 CFR Part 380 Subpart F."},"91":{"q":"يتكوّن تدريب السائقين المبتدئين (ELDT) المطلوب قبل اختبار مهارات CDL في ماساتشوستس من أي مكوّنين؟","options":["التعليم النظري والتدريب خلف عجلة القيادة","امتحان تحريري وفحص نظر","تعليم داخل الفصل الدراسي فقط وفحص خلفية فيدرالي","فحص طبي وفحص للمخدرات"],"explanation":"يتطلب ELDT الإكمال الناجح لبرنامج محدد من التعليم النظري والتدريب خلف عجلة القيادة قبل إجراء اختبار مهارات CDL. المصدر: دليل Mass.gov لـ ELDT؛ FMCSA 49 CFR Part 380 Subpart F."},"92":{"q":"إلى جانب المتقدّمين لأول مرة من الفئة A/B، يجب أيضًا إكمال ELDT قبل التقديم على أي تصديق لأول مرة؟","options":["المواد الخطرة (H)، أو الركاب (P)، أو الحافلة المدرسية (S)","مركبة الخزان (N) فقط","المقطورات المزدوجة/الثلاثية (T) فقط","فرامل الهواء (دون قيد)"],"explanation":"ينطبق ELDT على رخص CDL من الفئة A/B لأول مرة، وترقيات الفئة B إلى A، وتصديقات المواد الخطرة (H) والركاب (P) والحافلة المدرسية (S) لأول مرة. المصدر: دليل Mass.gov لـ ELDT؛ 49 CFR Part 380."},"93":{"q":"كم مدة صلاحية رخصة CDL في ماساتشوستس قبل وجوب تجديدها؟","options":["5 years","2 years","8 years","10 years"],"explanation":"رخصة CDL في ماساتشوستس صالحة لمدة 5 years وتنتهي صلاحيتها عمومًا في يوم ميلاد حاملها. المصدر: صفحات Mass.gov RMV لتجديد الرخصة."},"94":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL داخل الولاية فقط (ماساتشوستس فقط)، والحد الأدنى للعمر للتشغيل بين الولايات؟","options":["18 لداخل الولاية و21 لبين الولايات","16 لداخل الولاية و18 لبين الولايات","18 لكل من داخل الولاية وبين الولايات","21 لكل من داخل الولاية وبين الولايات"],"explanation":"يجب أن يكون عمر المتقدّم 18 على الأقل للحصول على رخصة CDL/CLP داخل الولاية (داخل ماساتشوستس) و21 على الأقل للتشغيل في التجارة بين الولايات. المصدر: صفحات Mass.gov RMV لـ CDL؛ 49 CFR 383.3/391.11."},"95":{"q":"عند التقديم للحصول على CLP/CDL في ماساتشوستس، أي مجموعة من المستندات يجب على المتقدّم تقديمها عمومًا؟","options":["إثبات الهوية/الوجود القانوني، ورقم الضمان الاجتماعي، والإقامة في ماساتشوستس","جواز سفر ساري المفعول وتسجيل مركبة فقط","خطاب من صاحب العمل وسند ملكية مركبة فقط","شهادة ميلاد وتقرير ائتماني"],"explanation":"يجب على المتقدّمين لـ CDL في ماساتشوستس إثبات الهوية/الوجود القانوني، وتقديم رقم الضمان الاجتماعي، وإثبات الإقامة في ماساتشوستس، وهي المعايير ذاتها للهوية المستخدمة لسائر وثائق RMV. المصدر: متطلبات Mass.gov RMV لـ CDL والهوية."},"96":{"q":"في اختبار المعرفة العامة التحريري لـ CDL في ماساتشوستس، ما هي درجة النجاح المطلوبة؟","options":["80% على الأقل من الإجابات الصحيحة","60% على الأقل من الإجابات الصحيحة","70% على الأقل من الإجابات الصحيحة","100% كاملة من الإجابات الصحيحة"],"explanation":"تتطلب اختبارات معرفة CDL في ماساتشوستس، بما في ذلك اختبار المعرفة العامة، درجة نجاح لا تقل عن 80% من الإجابات الصحيحة. المصدر: دليل CDL في ماساتشوستس؛ صفحات Mass.gov RMV لاختبارات CDL."}}};
